uiStyle& UI::GetStyle() {
    IM_ASSERT(GImGui != NULL && "Did you call UI::CreateContext() and UI::SetCurrentContext() ?");
    return GImGui->Style;
}
ImU32 UI::GetColorU32(uiCol idx, float alpha_mul) {
    uiStyle& style = GImGui->Style;
    vec4 c = style.Colors[idx];
    c.w *= style.Alpha * alpha_mul;
    return ColorConvertFloat4ToU32(c);
}
ImU32 UI::GetColorU32(const vec4& col) {
    uiStyle& style = GImGui->Style;
    vec4 c = col;
    c.w *= style.Alpha;
    return ColorConvertFloat4ToU32(c);
}
const vec4& UI::GetStyleColorVec4(uiCol idx) { uiStyle& style = GImGui->Style; return style.Colors[idx]; }
ImU32 UI::GetColorU32(ImU32 col, float alpha_mul) {
    uiStyle& style = GImGui->Style;
    alpha_mul *= style.Alpha;
    if (alpha_mul >= 1.0f) return col;
    ImU32 a = (col & IM_COL32_A_MASK) >> IM_COL32_A_SHIFT;
    a = (ImU32)(a * alpha_mul); // We don't need to clamp 0..255 because alpha is in 0..1 range.
    return (col & ~IM_COL32_A_MASK) | (a << IM_COL32_A_SHIFT);
}
// FIXME: This may incur a round-trip (if the end user got their data from a float4) but eventually we aim to store the in-flight colors as ImU32
void UI::PushStyleColor(uiCol idx, ImU32 col) {
    uiContext& g = *GImGui;
    uiColorMod backup;
    backup.Col = idx;
    backup.BackupValue = g.Style.Colors[idx];
    g.ColorStack.push_back(backup);
    if (g.DebugFlashStyleColorIdx != idx) g.Style.Colors[idx] = ColorConvertU32ToFloat4(col);
}
void UI::PushStyleColor(uiCol idx, const vec4& col) {
    uiContext& g = *GImGui;
    uiColorMod backup;
    backup.Col = idx;
    backup.BackupValue = g.Style.Colors[idx];
    g.ColorStack.push_back(backup);
    if (g.DebugFlashStyleColorIdx != idx) g.Style.Colors[idx] = col;
}
void UI::PopStyleColor(int count) {
    uiContext& g = *GImGui;
    if (g.ColorStack.Size < count) {
        IM_ASSERT_USER_ERROR(0, "Calling PopStyleColor() too many times!");
        count = g.ColorStack.Size;
    }
    while (count > 0) {
        uiColorMod& backup = g.ColorStack.back();
        g.Style.Colors[backup.Col] = backup.BackupValue;
        g.ColorStack.pop_back();
        count--;
    }
}
