const uiStyleVarInfo* UI::GetStyleVarInfo(uiStyleVar idx) {
    IM_ASSERT(idx >= 0 && idx < uiStyleVar_COUNT);
    IM_STATIC_ASSERT(IM_COUNTOF(GStyleVarsInfo) == uiStyleVar_COUNT);
    return &GStyleVarsInfo[idx];
}
void UI::PushStyleVar(uiStyleVar idx, float val) {
    uiContext& g = *GImGui;
    const uiStyleVarInfo* var_info = GetStyleVarInfo(idx);
    IM_ASSERT_USER_ERROR_RET(var_info->DataType == uiDataType_Float && var_info->Count == 1, "PushStyleVar() variant with wrong type!");
    float* pvar = (float*)var_info->GetVarPtr(&g.Style);
    g.StyleVarStack.push_back(uiStyleMod(idx, *pvar));
    *pvar = val;
}
void UI::PushStyleVarX(uiStyleVar idx, float val_x) {
    uiContext& g = *GImGui;
    const uiStyleVarInfo* var_info = GetStyleVarInfo(idx);
    IM_ASSERT_USER_ERROR_RET(var_info->DataType == uiDataType_Float && var_info->Count == 2, "PushStyleVar() variant with wrong type!");
    vec2* pvar = (vec2*)var_info->GetVarPtr(&g.Style);
    g.StyleVarStack.push_back(uiStyleMod(idx, *pvar));
    pvar->x = val_x;
}
void UI::PushStyleVarY(uiStyleVar idx, float val_y) {
    uiContext& g = *GImGui;
    const uiStyleVarInfo* var_info = GetStyleVarInfo(idx);
    IM_ASSERT_USER_ERROR_RET(var_info->DataType == uiDataType_Float && var_info->Count == 2, "PushStyleVar() variant with wrong type!");
    vec2* pvar = (vec2*)var_info->GetVarPtr(&g.Style);
    g.StyleVarStack.push_back(uiStyleMod(idx, *pvar));
    pvar->y = val_y;
}
void UI::PushStyleVar(uiStyleVar idx, const vec2& val) {
    uiContext& g = *GImGui;
    const uiStyleVarInfo* var_info = GetStyleVarInfo(idx);
    IM_ASSERT_USER_ERROR_RET(var_info->DataType == uiDataType_Float && var_info->Count == 2, "PushStyleVar() variant with wrong type!");
    vec2* pvar = (vec2*)var_info->GetVarPtr(&g.Style);
    g.StyleVarStack.push_back(uiStyleMod(idx, *pvar));
    *pvar = val;
}
void UI::PopStyleVar(int count) {
    uiContext& g = *GImGui;
    if (g.StyleVarStack.Size < count) {
        IM_ASSERT_USER_ERROR(0, "PopStyleVar() too many times!");
        count = g.StyleVarStack.Size;
    }
    while (count > 0) {
        // We avoid a generic memcpy(data, &backup.Backup.., GDataTypeSize[info->Type] * info->Count), the overhead in Debug is not worth it.
        uiStyleMod& backup = g.StyleVarStack.back();
        const uiStyleVarInfo* var_info = GetStyleVarInfo(backup.VarIdx);
        void* data = var_info->GetVarPtr(&g.Style);
        if (var_info->DataType == uiDataType_Float && var_info->Count == 1)      { ((float*)data)[0] = backup.BackupFloat[0]; }
        else if (var_info->DataType == uiDataType_Float && var_info->Count == 2) { ((float*)data)[0] = backup.BackupFloat[0]; ((float*)data)[1] = backup.BackupFloat[1]; }
        g.StyleVarStack.pop_back();
        count--;
    }
}
