//-----------------------------------------------------------------------------
// [SECTION] RENDER HELPERS
// Some of those (internal) functions are currently quite a legacy mess - their signature and behavior will change,
// we need a nicer separation between low-level functions and high-level functions relying on the ImGui context.
// Also see imgui_draw.cpp for some more which have been reworked to not rely on UI:: context.
//-----------------------------------------------------------------------------
const char* UI::FindRenderedTextEnd(const char* text, const char* text_end) {
    const char* text_display_end = text;
    if (!text_end) text_end = (const char*)-1;
    while (text_display_end < text_end && *text_display_end != '\0' && (text_display_end[0] != '#' || text_display_end[1] != '#'))
        text_display_end++;
    return text_display_end;
}
// Internal ImGui functions to render text
// RenderText***() functions calls ImDrawList::AddText() calls ImBitmapFont::RenderText()
void UI::RenderText(vec2 pos, const char* text, const char* text_end, bool hide_text_after_hash) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    // Hide anything after a '##' string
    const char* text_display_end;
    if (hide_text_after_hash) { text_display_end = FindRenderedTextEnd(text, text_end); }
    // FIXME-OPT (not reached by our internal calls)
    else { if (!text_end) text_end = text + ImStrlen(text); text_display_end = text_end; }
    if (text != text_display_end) {
        window->DrawList->AddText(g.Font, g.FontSize, pos, GetColorU32(uiCol_Text), text, text_display_end);
        if (g.LogEnabled) LogRenderedText(&pos, text, text_display_end);
    }
}
void UI::RenderTextWrapped(vec2 pos, const char* text, const char* text_end, float wrap_width) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    // FIXME-OPT (not reached by our internal calls)
    if (!text_end) text_end = text + ImStrlen(text);
    if (text != text_end) {
        window->DrawList->AddText(g.Font, g.FontSize, pos, GetColorU32(uiCol_Text), text, text_end, wrap_width);
        if (g.LogEnabled) LogRenderedText(&pos, text, text_end);
    }
}
// Default clip_rect uses (pos_min,pos_max)
// Handle clipping on CPU immediately (vs typically let the GPU clip the triangles that are overlapping the clipping rectangle edges)
// FIXME-OPT: Since we have or calculate text_size we could coarse clip whole block immediately, especially for text above draw_list->DrawList.
// Effectively as this is called from widget doing their own coarse clipping it's not very valuable presently. SameLine time function will take
// better advantage of the render function taking size into account for coarse clipping.
void UI::RenderTextClippedEx(ImDrawList* draw_list, const vec2& pos_min, const vec2& pos_max, const char* text, const char* text_display_end, const vec2* text_size_if_known, const vec2& align, const ImRect* clip_rect) {
    // Perform CPU side clipping for single clipped element to avoid using scissor state
    vec2 pos = pos_min;
    const vec2 text_size = text_size_if_known ? *text_size_if_known : CalcTextSize(text, text_display_end, false, 0.0f);
    const vec2* clip_min = clip_rect ? &clip_rect->Min : &pos_min;
    const vec2* clip_max = clip_rect ? &clip_rect->Max : &pos_max;
    bool need_clipping = (pos.x + text_size.x >= clip_max->x) || (pos.y + text_size.y >= clip_max->y);
    // If we had no explicit clipping rectangle then pos==clip_min
    if (clip_rect) need_clipping |= (pos.x < clip_min->x) || (pos.y < clip_min->y);
    // Align whole block. We should defer that to the better rendering function when we'll have support for individual line alignment.
    if (align.x > 0.0f) pos.x = ImMax(pos.x, pos.x + (pos_max.x - pos.x - text_size.x) * align.x);
    if (align.y > 0.0f) pos.y = ImMax(pos.y, pos.y + (pos_max.y - pos.y - text_size.y) * align.y);
    // Render
    if (need_clipping) {
        vec4 fine_clip_rect(clip_min->x, clip_min->y, clip_max->x, clip_max->y);
        draw_list->AddText(NULL, 0.0f, pos, GetColorU32(uiCol_Text), text, text_display_end, 0.0f, &fine_clip_rect);
    } else {
        draw_list->AddText(NULL, 0.0f, pos, GetColorU32(uiCol_Text), text, text_display_end, 0.0f, NULL);
    }
}
void UI::RenderTextClipped(const vec2& pos_min, const vec2& pos_max, const char* text, const char* text_end, const vec2* text_size_if_known, const vec2& align, const ImRect* clip_rect) {
    // Hide anything after a '##' string
    const char* text_display_end = FindRenderedTextEnd(text, text_end);
    const int text_len = (int)(text_display_end - text);
    if (text_len == 0) return;
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    RenderTextClippedEx(window->DrawList, pos_min, pos_max, text, text_display_end, text_size_if_known, align, clip_rect);
    if (g.LogEnabled) LogRenderedText(&pos_min, text, text_display_end);
}
// Another overly complex function until we reorganize everything into a nice all-in-one helper.
// This is made more complex because we have dissociated the layout rectangle (pos_min..pos_max) from 'ellipsis_max_x' which may be beyond it.
// This is because in the context of tabs we selectively hide part of the text when the Close Button appears, but we don't want the ellipsis to move.
// (BREAKING) On 2025/04/16 we removed the 'float clip_max_x' parameters which was preceding 'float ellipsis_max' and was the same value for 99% of users.
void UI::RenderTextEllipsis(ImDrawList* draw_list, const vec2& pos_min, const vec2& pos_max, float ellipsis_max_x, const char* text, const char* text_end_full, const vec2* text_size_if_known) {
    uiContext& g = *GImGui;
    if (text_end_full == NULL) text_end_full = FindRenderedTextEnd(text);
    const vec2 text_size = text_size_if_known ? *text_size_if_known : CalcTextSize(text, text_end_full, false, 0.0f);
    //draw_list->AddLineV(pos_max.x, pos_min.y - 4, pos_max.y + 6, IM_COL32(0, 0, 255, 255));
    //draw_list->AddLineV(ellipsis_max_x, pos_min.y - 2, pos_max.y + 3, IM_COL32(0, 255, 0, 255));
    // FIXME: We could technically remove (last_glyph->AdvanceX - last_glyph->X1) from text_size.x here and save a few pixels.
    if (text_size.x > pos_max.x - pos_min.x) {
        // Hello wo...
        // |       |   |
        // min   max   ellipsis_max
        //          <-> this is generally some padding value
        ImFont* font = draw_list->_Data->Font;
        const float font_size = draw_list->_Data->FontSize;
        const float font_scale = draw_list->_Data->FontScale;
        const char* text_end_ellipsis = NULL;
        ImFontBaked* baked = font->GetFontBaked(font_size);
        const float ellipsis_width = baked->GetCharAdvance(font->EllipsisChar) * font_scale;
        // We can now claim the space between pos_max.x and ellipsis_max.x
        const float text_avail_width = ImMax((ImMax(pos_max.x, ellipsis_max_x) - ellipsis_width) - pos_min.x, 1.0f);
        const float text_size_clipped_x = font->CalcTextSizeA(font_size, text_avail_width, 0.0f, text, text_end_full, &text_end_ellipsis).x;
        // Render text, render ellipsis
        RenderTextClippedEx(draw_list, pos_min, pos_max, text, text_end_ellipsis, &text_size, vec2(0.0f, 0.0f));
        vec4 cpu_fine_clip_rect(pos_min.x, pos_min.y, pos_max.x, pos_max.y);
        vec2 ellipsis_pos = ImTrunc(vec2(pos_min.x + text_size_clipped_x, pos_min.y));
        font->RenderChar(draw_list, font_size, ellipsis_pos, GetColorU32(uiCol_Text), font->EllipsisChar, &cpu_fine_clip_rect);
    } else {
        RenderTextClippedEx(draw_list, pos_min, pos_max, text, text_end_full, &text_size, vec2(0.0f, 0.0f));
    }
    if (g.LogEnabled) LogRenderedText(&pos_min, text, text_end_full);
}
// Render a rectangle shaped with optional rounding and borders
void UI::RenderFrame(vec2 p_min, vec2 p_max, ImU32 fill_col, bool borders, float rounding) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    window->DrawList->AddRectFilled(p_min, p_max, fill_col, rounding);
    const float border_size = g.Style.FrameBorderSize;
    if (borders && border_size > 0.0f) {
        window->DrawList->AddRect(p_min + vec2(1, 1), p_max + vec2(1, 1), GetColorU32(uiCol_BorderShadow), rounding, border_size);
        window->DrawList->AddRect(p_min, p_max, GetColorU32(uiCol_Border), rounding, border_size);
    }
}
void UI::RenderFrameBorder(vec2 p_min, vec2 p_max, float rounding) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    const float border_size = g.Style.FrameBorderSize;
    if (border_size > 0.0f) {
        window->DrawList->AddRect(p_min + vec2(1, 1), p_max + vec2(1, 1), GetColorU32(uiCol_BorderShadow), rounding, border_size);
        window->DrawList->AddRect(p_min, p_max, GetColorU32(uiCol_Border), rounding, border_size);
    }
}
void UI::RenderColorComponentMarker(const ImRect& bb, ImU32 col, float rounding) {
    if (bb.Min.x + 1 >= bb.Max.x) return;
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    RenderRectFilledInRangeH(window->DrawList, bb, col, bb.Min.x, ImMin(bb.Min.x + AUR::Engine::colorMarkerSize, bb.Max.x), rounding);
}
void UI::RenderNavCursor(const ImRect& bb, uiID id, uiNavRenderCursorFlags flags) {
    uiContext& g = *GImGui;
    if (id != g.NavId) return;
    if (!g.NavCursorVisible && !(flags & uiNavRenderCursorFlags_AlwaysDraw)) return;
    if (id == g.LastItemData.ID && (g.LastItemData.ItemFlags & uiItemFlags_NoNav)) return;
    // We don't early out on 'window->Flags & uiWindowFlags_NoNavInputs' because it would be inconsistent with
    // other code directly checking NavCursorVisible. Instead we aim for NavCursorVisible to always be false.
    uiWindow* window = g.CurrentWindow;
    if (window->DC.NavHideHighlightOneFrame) return;
    float rounding = (flags & uiNavRenderCursorFlags_NoRounding) ? 0.0f : g.Style.FrameRounding;
    ImRect display_rect = bb;
    display_rect.ClipWith(window->ClipRect);
    const float thickness = 2.0f;
    if (flags & uiNavRenderCursorFlags_Compact) {
        window->DrawList->AddRect(display_rect.Min, display_rect.Max, GetColorU32(uiCol_NavCursor), rounding, thickness);
    } else {
        const float distance = 3.0f + thickness * 0.5f;
        display_rect.Expand(vec2(distance, distance));
        bool fully_visible = window->ClipRect.Contains(display_rect);
        if (!fully_visible) window->DrawList->PushClipRect(display_rect.Min, display_rect.Max);
        window->DrawList->AddRect(display_rect.Min, display_rect.Max, GetColorU32(uiCol_NavCursor), rounding, thickness);
        if (!fully_visible) window->DrawList->PopClipRect();
    }
}
void UI::RenderMouseCursor(vec2 base_pos, float base_scale, uiMouseCursor mouse_cursor, ImU32 col_fill, ImU32 col_border, ImU32 col_shadow) {
    uiContext& g = *GImGui;
    if (mouse_cursor <= uiMouseCursor_None || mouse_cursor >= uiMouseCursor_COUNT) // We intentionally accept out of bound values.
        mouse_cursor = uiMouseCursor_Arrow;
    ImFontAtlas* font_atlas = g.DrawListSharedData.FontAtlas;
    for (uiViewportP* viewport : g.Viewports) {
        // We scale cursor with current viewport/monitor, however Windows 10 for its own hardware cursor seems to be using a different scale factor.
        vec2 offset, size, uv[4];
        if (!ImFontAtlasGetMouseCursorTexData(font_atlas, mouse_cursor, &offset, &size, &uv[0], &uv[2]))
            continue;
        const vec2 pos = base_pos - offset;
        const float scale = base_scale * viewport->DpiScale;
        if (!viewport->GetMainRect().Overlaps(ImRect(pos, pos + vec2(size.x + 2, size.y + 2) * scale)))
            continue;
        ImDrawList* draw_list = GetForegroundDrawList(viewport);
        ImTextureRef tex_ref = font_atlas->TexRef;
        draw_list->PushTexture(tex_ref);
        draw_list->AddImage(tex_ref, pos + vec2(1, 0) * scale, pos + (vec2(1, 0) + size) * scale, uv[2], uv[3], col_shadow);
        draw_list->AddImage(tex_ref, pos + vec2(2, 0) * scale, pos + (vec2(2, 0) + size) * scale, uv[2], uv[3], col_shadow);
        draw_list->AddImage(tex_ref, pos, pos + size * scale, uv[2], uv[3], col_border);
        draw_list->AddImage(tex_ref, pos, pos + size * scale, uv[0], uv[1], col_fill);
        if (mouse_cursor == uiMouseCursor_Wait || mouse_cursor == uiMouseCursor_Progress) {
            float a_min = ImFmod((float)g.Time * 5.0f, 2.0f * IM_PI);
            float a_max = a_min + IM_PI * 1.65f;
            draw_list->PathArcTo(pos + vec2(14, -1) * scale, 6.0f * scale, a_min, a_max);
            draw_list->PathStroke(col_fill, 3.0f * scale);
        }
        draw_list->PopTexture();
    }
}
//-----------------------------------------------------------------------------
// [SECTION] INITIALIZATION, SHUTDOWN
//-----------------------------------------------------------------------------
// Internal state access - if you want to share Dear ImGui state between modules (e.g. DLL) or allocate it yourself
// Note that we still point to some static data and members (such as GFontAtlas), so the state instance you end up using will point to the static data within its module
uiContext* UI::GetCurrentContext() { return GImGui; }
void UI::SetCurrentContext(uiContext* ctx) {
#ifdef IMGUI_SET_CURRENT_CONTEXT_FUNC
    IMGUI_SET_CURRENT_CONTEXT_FUNC(ctx); // For custom thread-based hackery you may want to have control over this.
#else
    GImGui = ctx;
#endif
}
void UI::SetAllocatorFunctions(uiMemAllocFunc alloc_func, uiMemFreeFunc free_func, void* user_data) {
    GImAllocatorAllocFunc = alloc_func;
    GImAllocatorFreeFunc = free_func;
    GImAllocatorUserData = user_data;
}
// This is provided to facilitate copying allocators from one static/DLL boundary to another (e.g. retrieve default allocator of your executable address space)
void UI::GetAllocatorFunctions(uiMemAllocFunc* p_alloc_func, uiMemFreeFunc* p_free_func, void** p_user_data) {
    *p_alloc_func = GImAllocatorAllocFunc;
    *p_free_func = GImAllocatorFreeFunc;
    *p_user_data = GImAllocatorUserData;
}
uiContext* UI::CreateContext(ImFontAtlas* shared_font_atlas) {
    uiContext* prev_ctx = GetCurrentContext();
    uiContext* ctx = IM_NEW(uiContext)(shared_font_atlas);
    SetCurrentContext(ctx);
    Initialize();
    // Restore previous context if any, else keep new one.
    if (prev_ctx != NULL) SetCurrentContext(prev_ctx);
    return ctx;
}
void UI::DestroyContext(uiContext* ctx) {
    uiContext* prev_ctx = GetCurrentContext();
    //-V1051
    if (ctx == NULL) ctx = prev_ctx;
    SetCurrentContext(ctx);
    Shutdown();
    SetCurrentContext((prev_ctx != ctx) ? prev_ctx : NULL);
    IM_DELETE(ctx);
}
