void UI::MarkItemEdited(uiID id) {
    // This marking is to be able to provide info for IsItemDeactivatedAfterEdit().
    // ActiveId might have been released by the time we call this (as in the typical press/release button behavior) but still need to fill the data.
    uiContext& g = *GImGui;
    g.LastItemData.StatusFlags |= uiItemStatusFlags_EditedInternal;
    if (g.LastItemData.ItemFlags & uiItemFlags_NoMarkEdited) return;
    g.LastItemData.StatusFlags |= uiItemStatusFlags_Edited;
    if (g.ActiveId == id || g.ActiveId == 0) {
        // FIXME: Can't we fully rely on LastItemData yet?
        g.ActiveIdHasBeenEditedThisFrame = true;
        g.ActiveIdHasBeenEditedBefore = true;
        if (g.DeactivatedItemData.ID == id) g.DeactivatedItemData.HasBeenEditedBefore = true;
    }
    // We accept a MarkItemEdited() on drag and drop targets (see https://github.com/ocornut/imgui/issues/1875#issuecomment-978243343)
    // We accept 'ActiveIdPreviousFrame == id' for InputText() returning an edit after it has been taken ActiveId away (#4714)
    // FIXME: This assert is getting a bit meaningless over time. It helped detect some unusual use cases but eventually it is becoming an unnecessary restriction.
    IM_ASSERT(g.DragDropActive || g.ActiveId == id || g.ActiveId == 0 || g.ActiveIdPreviousFrame == id || g.NavJustMovedToId || (g.CurrentMultiSelect != NULL && g.BoxSelectState.IsActive));
}
bool UI::IsWindowContentHoverable(uiWindow* window, uiHoverFlags flags) {
    // An active popup disable hovering on other windows (apart from its own children)
    // FIXME-OPT: This could be cached/stored within the window.
    uiContext& g = *GImGui;
    if (g.NavWindow)
        if (uiWindow* focused_root_window = g.NavWindow->RootWindowDockTree)
            if (focused_root_window->WasActive && focused_root_window != window->RootWindowDockTree) {
                // For the purpose of those flags we differentiate "standard popup" from "modal popup"
                // NB: The 'else' is important because Modal windows are also Popups.
                bool want_inhibit = false;
                if (focused_root_window->Flags & uiWindowFlags_Modal)
                    want_inhibit = true;
                else if ((focused_root_window->Flags & uiWindowFlags_Popup) && !(flags & uiHoverFlags_AllowWhenBlockedByPopup))
                    want_inhibit = true;
                // Inhibit hover unless the window is within the stack of our modal/popup
                if (want_inhibit)
                    if (!IsWindowWithinBeginStackOf(window->RootWindow, focused_root_window))
                        return false;
            }
    // Filter by viewport
    if (window->Viewport != g.MouseViewport)
        if (g.MovingWindow == NULL || window->RootWindowDockTree != g.MovingWindow->RootWindowDockTree)
            return false;
    return true;
}
// TODO remove ?
static inline float CalcDelayFromHoveredFlags(uiHoverFlags flags) {
    uiContext& g = *GImGui;
    if (flags & uiHoverFlags_Delay) return AUR::Engine::hoverDelay;
    return 0.0f;
}
// TODO remove ?
static uiHoverFlags ApplyHoverFlagsForTooltip(uiHoverFlags user_flags, uiHoverFlags shared_flags) {
    // Allow instance flags to override shared flags
    if (user_flags & (uiHoverFlags_Delay))
        shared_flags &= ~(uiHoverFlags_Delay);
    return user_flags | shared_flags;
}
// This is roughly matching the behavior of internal-facing ItemHoverable()
// - we allow hovering to be true when ActiveId==window->MoveID, so that clicking on non-interactive items such as a Text() item still returns true with IsItemHovered()
// - this should work even for non-interactive items that have no ID, so we cannot use LastItemId
bool UI::IsItemHovered(uiHoverFlags flags) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    IM_ASSERT_USER_ERROR((flags & ~uiHoverFlags_AllowedMaskForIsItemHovered) == 0, "Invalid flags for IsItemHovered()!");
    if (g.NavHighlightItemUnderNav && g.NavCursorVisible && !(flags & uiHoverFlags_NoNavOverride)) {
        if (!IsItemFocused())
            return false;
        if ((g.LastItemData.ItemFlags & uiItemFlags_Disabled) && !(flags & uiHoverFlags_AllowWhenDisabled))
            return false;
        if (flags & uiHoverFlags_ForTooltip)
            flags = ApplyHoverFlagsForTooltip(flags, g.Style.HoverFlagsForTooltipNav);
    } else {
        // Test for bounding box overlap, as updated as ItemAdd()
        uiItemStatusFlags status_flags = g.LastItemData.StatusFlags;
        if (!(status_flags & uiItemStatusFlags_HoveredRect)) return false;
        if (flags & uiHoverFlags_ForTooltip)
            flags = ApplyHoverFlagsForTooltip(flags, g.Style.HoverFlagsForTooltipMouse);
        // Done with rectangle culling so we can perform heavier checks now
        // Test if we are hovering the right window (our window could be behind another window)
        // [2021/03/02] Reworked / reverted the revert, finally. Note we want e.g. BeginGroup/ItemAdd/EndGroup to work as well. (#3851)
        // [2017/10/16] Reverted commit 344d48be3 and testing RootWindow instead. I believe it is correct to NOT test for RootWindow but this leaves us unable
        // to use IsItemHovered() after EndChild() itself. Until a solution is found I believe reverting to the test from 2017/09/27 is safe since this was
        // the test that has been running for a long while.
        if (g.HoveredWindow != window && (status_flags & uiItemStatusFlags_HoveredWindow) == 0)
            if ((flags & uiHoverFlags_AllowWhenOverlappedByWindow) == 0)
                return false;
        // Test if another item is active (e.g. being dragged)
        const uiID id = g.LastItemData.ID;
        if ((flags & uiHoverFlags_AllowWhenBlockedByActiveItem) == 0)
            if (g.ActiveId != 0 && g.ActiveId != id && !g.ActiveIdAllowOverlap && !g.ActiveIdFromShortcut) {
                // When ActiveId == MoveId it means that either:
                // - (1) user clicked on void _or_ an item with no id, which triggers moving window (ActiveId is set even when window has _NoMove flag)
                //   - the (id == 0) test handles it, however, IsItemHovered() will leak between id==0 items (mostly visible when using _NoMove). // FIXME: May be fixed.
                // - (2) user clicked a disabled item. UpdateMouseMovingWindowEndFrame() uses ActiveId == MoveId to avoid interference with item logic + sets ActiveIdDisabledId.
                bool cancel_is_hovered = true;
                if (g.ActiveId == window->MoveId && (id == 0 || g.ActiveIdDisabledId == id))
                    cancel_is_hovered = false;
                // When ActiveId == TabId it means user clicked docking tab for the window.
                if (g.ActiveId == window->TabId) cancel_is_hovered = false;
                if (cancel_is_hovered) return false;
            }
        // Test if interactions on this window are blocked by an active popup or modal.
        // The uiHoverFlags_AllowWhenBlockedByPopup flag will be tested here.
        if (!IsWindowContentHoverable(window, flags) && !(g.LastItemData.ItemFlags & uiItemFlags_NoWindowHoverableCheck))
            return false;
        // Test if the item is disabled
        if ((g.LastItemData.ItemFlags & uiItemFlags_Disabled) && !(flags & uiHoverFlags_AllowWhenDisabled))
            return false;
        // Special handling for calling after Begin() which represent the title bar or tab.
        // When the window is skipped/collapsed (SkipItems==true) that last item (always ->MoveId submitted by Begin)
        // will never be overwritten so we need to detect the case.
        if (id == window->MoveId && window->WriteAccessed) return false;
        // Test if using AllowOverlap and overlapped
        if ((g.LastItemData.ItemFlags & uiItemFlags_AllowOverlap) && id != 0)
            if ((flags & uiHoverFlags_AllowWhenOverlappedByItem) == 0)
                if (g.HoveredIdPreviousFrame != g.LastItemData.ID)
                    return false;
    }
    // Handle hover delay
    // (some ideas: https://www.nngroup.com/articles/timing-exposing-content)
    const float delay = CalcDelayFromHoveredFlags(flags);
    if (delay > 0.0f || (flags & uiHoverFlags_Stationary)) {
        uiID hover_delay_id = (g.LastItemData.ID != 0) ? g.LastItemData.ID : window->GetIDFromPos(g.LastItemData.Rect.Min);
        if ((flags & uiHoverFlags_NoSharedDelay) && (g.HoverItemDelayIdPreviousFrame != hover_delay_id))
            g.HoverItemDelayTimer = 0.0f;
        g.HoverItemDelayId = hover_delay_id;
        // When changing hovered item we requires a bit of stationary delay before activating hover timer,
        // but once unlocked on a given item we also moving.
        //if (g.HoverDelayTimer >= delay && (g.HoverDelayTimer - g.IO.DeltaTime < delay || g.MouseStationaryTimer - g.IO.DeltaTime < g.Style.HoverStationaryDelay)) { IMGUI_DEBUG_LOG("HoverDelayTimer = %f/%f, MouseStationaryTimer = %f\n", g.HoverDelayTimer, delay, g.MouseStationaryTimer); }
        if ((flags & uiHoverFlags_Stationary) != 0 && g.HoverItemUnlockedStationaryId != hover_delay_id)
            return false;
        if (g.HoverItemDelayTimer < delay) return false;
    }
    return true;
}
// Internal facing ItemHoverable() used when submitting widgets. THIS IS A SUBMISSION NOT A HOVER CHECK.
// Returns whether the item was hovered, logic differs slightly from IsItemHovered().
// (this does not rely on LastItemData it can be called from a ButtonBehavior() call not following an ItemAdd() call)
// FIXME-LEGACY: the 'uiItemFlags item_flags' parameter was added on 2023-06-28.
// If you used this in your legacy/custom widgets code:
// - Commonly: if your ItemHoverable() call comes after an ItemAdd() call: pass 'item_flags = g.LastItemData.ItemFlags'.
// - Rare: otherwise you may pass 'item_flags = 0' (uiItemFlags_None) unless you want to benefit from special behavior handled by ItemHoverable.
bool UI::ItemHoverable(const ImRect& bb, uiID id, uiItemFlags item_flags) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    // Detect ID conflicts
    // (this is specifically done here by comparing on hover because it allows us a detection of duplicates that is algorithmically extra cheap, 1 u32 compare per item. No O(log N) lookup whatsoever)
#ifndef IMGUI_DISABLE_DEBUG_TOOLS
    if (id != 0 && g.HoveredIdPreviousFrame == id && (item_flags & uiItemFlags_AllowDuplicateId) == 0) {
        g.HoveredIdPreviousFrameItemCount++;
        if (g.DebugDrawIdConflictsId == id)
            window->DrawList->AddRect(bb.Min - vec2(1,1), bb.Max + vec2(1,1), IM_COL32(255, 0, 0, 255), 0.0f, 2.0f);
    }
#endif
    if (g.HoveredWindow != window) return false;
    if (!IsMouseHoveringRect(bb.Min, bb.Max)) return false;
    if (g.HoveredId != 0 && g.HoveredId != id && !g.HoveredIdAllowOverlap) return false;
    if (g.ActiveId != 0 && g.ActiveId != id && !g.ActiveIdAllowOverlap)
        if (!g.ActiveIdFromShortcut)
            return false;
    // We are done with rectangle culling so we can perform heavier checks now.
    if (!(item_flags & uiItemFlags_NoWindowHoverableCheck) && !IsWindowContentHoverable(window, uiHoverFlags_None)) {
        g.HoveredIdIsDisabled = true;
        return false;
    }
    // We exceptionally allow this function to be called with id==0 to allow using it for easy high-level
    // hover test in widgets code. We could also decide to split this function is two.
    if (id != 0) {
        // Drag source doesn't report as hovered
        if (g.DragDropActive && g.DragDropPayload.SourceId == id && !(g.DragDropSourceFlags & uiDragDropFlags_SourceNoDisableHover))
            return false;
        SetHoveredID(id);
        // AllowOverlap mode (rarely used) requires previous frame HoveredId to be null or to match.
        // This allows using patterns where a later submitted widget overlaps a previous one. Generally perceived as a front-to-back hit-test.
        if (item_flags & uiItemFlags_AllowOverlap) {
            g.HoveredIdAllowOverlap = true;
            if (g.HoveredIdPreviousFrame != id) return false;
        }
        // Display shortcut (only works with mouse)
        // (uiItemStatusFlags_HasShortcut in LastItemData denotes we want a tooltip)
        if (id == g.LastItemData.ID && (g.LastItemData.StatusFlags & uiItemStatusFlags_HasShortcut) && g.ActiveId != id)
            if (IsItemHovered(uiHoverFlags_Delay))
                SetTooltip("%s", GetKeyChordName(g.LastItemData.Shortcut));
    }
    // When disabled we'll return false but still set HoveredId
    if (item_flags & uiItemFlags_Disabled) {
        // Release active id if turning disabled
        if (g.ActiveId == id && id != 0) ClearActiveID();
        g.HoveredIdIsDisabled = true;
        return false;
    }
#ifndef IMGUI_DISABLE_DEBUG_TOOLS
    if (id != 0) {
        // [DEBUG] Item Picker tool!
        // We perform the check here because reaching is path is rare (1~ time a frame),
        // making the cost of this tool near-zero! We could get better call-stack and support picking non-hovered
        // items if we performed the test in ItemAdd(), but that would incur a bigger runtime cost.
        if (g.DebugItemPickerActive && g.HoveredIdPreviousFrame == id)
            GetForegroundDrawList()->AddRect(bb.Min, bb.Max, IM_COL32(255, 255, 0, 255));
        if (g.DebugItemPickerBreakId == id) IM_DEBUG_BREAK();
    }
#endif
    if (g.NavHighlightItemUnderNav && (item_flags & uiItemFlags_NoNavDisableMouseHover) == 0)
        return false;
    return true;
}
// FIXME: This is inlined/duplicated in ItemAdd()
// FIXME: The id != 0 path is not used by our codebase, may get rid of it?
bool UI::IsClippedEx(const ImRect& bb, uiID id) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    if (!bb.Overlaps(window->ClipRect))
        if (id == 0 || (id != g.ActiveId && id != g.ActiveIdPreviousFrame && id != g.NavId && id != g.NavActivateId))
            if (!g.ItemUnclipByLog) return true;
    return false;
}
