float UI::CalcWrapWidthForPos(const vec2& pos, float wrap_pos_x) {
    if (wrap_pos_x < 0.0f) return 0.0f;
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    if (wrap_pos_x == 0.0f) {
        // We could decide to setup a default wrapping max point for auto-resizing windows,
        // or have auto-wrap (with unspecified wrapping pos) behave as a ContentSize extending function?
        //if (window->Hidden && (window->Flags & uiWindowFlags_AutoResize))
        //    wrap_pos_x = ImMax(window->WorkRect.Min.x + g.FontSize * 10.0f, window->WorkRect.Max.x);
        //else
        wrap_pos_x = window->WorkRect.Max.x;
    // wrap_pos_x is provided is window local space
    } else if (wrap_pos_x > 0.0f) { wrap_pos_x += window->Pos.x - window->Scroll.x; }
    return ImMax(wrap_pos_x - pos.x, 1.0f);
}
// IM_ALLOC() == UI::MemAlloc()
void* UI::MemAlloc(size_t size) {
    void* ptr = (*GImAllocatorAllocFunc)(size, GImAllocatorUserData);
#ifndef IMGUI_DISABLE_DEBUG_TOOLS
    if (uiContext* ctx = GImGui) DebugAllocHook(&ctx->DebugAllocInfo, ctx->FrameCount, ptr, size);
#endif
    return ptr;
}
// IM_FREE() == UI::MemFree()
void UI::MemFree(void* ptr) {
#ifndef IMGUI_DISABLE_DEBUG_TOOLS
    if (ptr != NULL)
        if (uiContext* ctx = GImGui) DebugAllocHook(&ctx->DebugAllocInfo, ctx->FrameCount, ptr, (size_t)-1);
#endif
    return (*GImAllocatorFreeFunc)(ptr, GImAllocatorUserData);
}
