static ImDrawList* GetViewportBgFgDrawList(uiViewportP* viewport, size_t drawlist_no, const char* drawlist_name) {
    // Create the draw list on demand, because they are not frequently used for all viewports
    uiContext& g = *GImGui;
    IM_ASSERT(drawlist_no < IM_COUNTOF(viewport->BgFgDrawLists));
    ImDrawList* draw_list = viewport->BgFgDrawLists[drawlist_no];
    if (draw_list == NULL) {
        draw_list = IM_NEW(ImDrawList)(&g.DrawListSharedData);
        draw_list->_OwnerName = drawlist_name;
        viewport->BgFgDrawLists[drawlist_no] = draw_list;
    }
    // Our ImDrawList system requires that there is always a command
    if (viewport->BgFgDrawListsLastTimeActive[drawlist_no] != (float)g.Time) {
        draw_list->_ResetForNewFrame();
        draw_list->PushTexture(g.IO.Fonts->TexRef);
        draw_list->PushClipRect(viewport->Pos, viewport->Pos + viewport->Size, false);
        viewport->BgFgDrawListsLastTimeActive[drawlist_no] = (float)g.Time;
    }
    return draw_list;
}
ImDrawList* UI::GetBackgroundDrawList(uiViewport* viewport) {
    if (viewport == NULL) viewport = GImGui->CurrentWindow->Viewport;
    return GetViewportBgFgDrawList((uiViewportP*)viewport, 0, "##Background");
}
ImDrawList* UI::GetForegroundDrawList(uiViewport* viewport) {
    if (viewport == NULL) viewport = GImGui->CurrentWindow->Viewport;
    return GetViewportBgFgDrawList((uiViewportP*)viewport, 1, "##Foreground");
}
