void UI::SetWindowPos(uiWindow* window, const vec2& pos, uiCond cond) {
    // Test condition (NB: bit 0 is always true) and clear flags for next time
    if (cond && (window->SetWindowPosAllowFlags & cond) == 0) return;
    IM_ASSERT(cond == 0 || ImIsPowerOfTwo(cond)); // Make sure the user doesn't attempt to combine multiple condition flags.
    window->SetWindowPosAllowFlags &= ~(uiCond_Once | uiCond_FirstUseEver | uiCond_Appearing);
    window->SetWindowPosVal = vec2(FLT_MAX, FLT_MAX);
    // Set
    const vec2 old_pos = window->Pos;
    window->Pos = ImTrunc(pos);
    vec2 offset = window->Pos - old_pos;
    if (offset.x == 0.0f && offset.y == 0.0f) return;
    MarkIniSettingsDirty(window);
    // FIXME: share code with TranslateWindow(), need to confirm whether the 3 rect modified by TranslateWindow() are desirable here.
    window->DC.CursorPos += offset;    // As we happen to move the window while it is being appended to (which is a bad idea - will smear) let's at least offset the cursor
    window->DC.CursorMaxPos += offset; // And more importantly we need to offset CursorMaxPos/CursorStartPos this so ContentSize calculation doesn't get affected.
    window->DC.IdealMaxPos += offset;
    window->DC.CursorStartPos += offset;
}
void UI::SetWindowPos(const vec2& pos, uiCond cond) { uiWindow* window = GetCurrentWindowRead(); SetWindowPos(window, pos, cond); }
