vec2 UI::GetWindowSize() { uiWindow* window = GetCurrentWindowRead(); return window->Size; }
void UI::SetWindowSize(uiWindow* window, const vec2& size, uiCond cond) {
    // Test condition (NB: bit 0 is always true) and clear flags for next time
    if (cond && (window->SetWindowSizeAllowFlags & cond) == 0) return;
    IM_ASSERT(cond == 0 || ImIsPowerOfTwo(cond)); // Make sure the user doesn't attempt to combine multiple condition flags.
    window->SetWindowSizeAllowFlags &= ~(uiCond_Once | uiCond_FirstUseEver | uiCond_Appearing);
    // Enable auto-fit (not done in BeginChild() path unless appearing or combined with uiChildFlags_AutoResize)
    if ((window->Flags & uiWindowFlags_ChildWindow) == 0 || window->Appearing || (window->ChildFlags & uiChildFlags_AutoResize) != 0)
        window->AutoFitFramesX = (size.x <= 0.0f) ? 2 : 0;
    if ((window->Flags & uiWindowFlags_ChildWindow) == 0 || window->Appearing || (window->ChildFlags & uiChildFlags_AutoResize) != 0)
        window->AutoFitFramesY = (size.y <= 0.0f) ? 2 : 0;
    // Set
    vec2 old_size = window->SizeFull;
    if (size.x <= 0.0f) window->AutoFitOnlyGrows = false;
    else window->SizeFull.x = IM_TRUNC(size.x);
    if (size.y <= 0.0f) window->AutoFitOnlyGrows = false;
    else window->SizeFull.y = IM_TRUNC(size.y);
    if (old_size.x != window->SizeFull.x || old_size.y != window->SizeFull.y) MarkIniSettingsDirty(window);
}
