void UI::SetWindowCollapsed(uiWindow* window, bool collapsed, uiCond cond) {
    // Test condition (NB: bit 0 is always true) and clear flags for next time
    if (cond && (window->SetWindowCollapsedAllowFlags & cond) == 0) return;
    window->SetWindowCollapsedAllowFlags &= ~(uiCond_Once | uiCond_FirstUseEver | uiCond_Appearing);
    // Queue applying in Begin()
    if (window->WantCollapseToggle) window->Collapsed ^= 1;
    window->WantCollapseToggle = (window->Collapsed != collapsed);
}
