bool UI::IsInNavFocusRoute(uiID focus_scope_id) {
    uiContext& g = *GImGui;
    if (g.NavFocusScopeId == focus_scope_id) return true;
    for (const uiFocusScopeData& focus_scope : g.NavFocusRoute) if (focus_scope.ID == focus_scope_id) return true;
    return false;
}
void UI::SetNavFocusScope(uiID focus_scope_id) {
    uiContext& g = *GImGui;
    g.NavFocusScopeId = focus_scope_id;
    g.NavFocusRoute.resize(0); // Invalidate
    if (focus_scope_id == 0) return;
    IM_ASSERT(g.NavWindow != NULL);
    // Store current path (in reverse order)
    if (focus_scope_id == g.CurrentFocusScopeId) {
        // Top of focus stack contains local focus scopes inside current window
        for (int n = g.FocusScopeStack.Size - 1; n >= 0 && g.FocusScopeStack.Data[n].WindowID == g.CurrentWindow->ID; n--)
            g.NavFocusRoute.push_back(g.FocusScopeStack.Data[n]);
    }
    else if (focus_scope_id == g.NavWindow->NavRootFocusScopeId)
        g.NavFocusRoute.push_back({ focus_scope_id, g.NavWindow->ID });
    else return;
    // Then follow on manually set ParentWindowForFocusRoute field (#6798)
    for (uiWindow* window = g.NavWindow->ParentWindowForFocusRoute; window != NULL; window = window->ParentWindowForFocusRoute)
        g.NavFocusRoute.push_back({ window->NavRootFocusScopeId, window->ID });
    IM_ASSERT(g.NavFocusRoute.Size < 100); // Maximum depth is technically 251 as per CalcRoutingScore(): 254 - 3
}
// Focus = move navigation cursor, set scrolling, set focus window.
void UI::FocusItem() {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    IMGUI_DEBUG_LOG_FOCUS("FocusItem(0x%08x) in window \"%s\"\n", g.LastItemData.ID, window->Name);
    if (g.DragDropActive || g.MovingWindow != NULL) { // FIXME: Opt-in flags for this?
        IMGUI_DEBUG_LOG_FOCUS("FocusItem() ignored while DragDropActive!\n");
        return;
    }
    uiNavMoveFlags move_flags = uiNavMoveFlags_IsTabbing | uiNavMoveFlags_FocusApi | uiNavMoveFlags_NoSetNavCursorVisible | uiNavMoveFlags_NoSelect;
    uiScrollFlags scroll_flags = window->Appearing ? uiScrollFlags_KeepVisibleEdgeX | uiScrollFlags_AlwaysCenterY : uiScrollFlags_KeepVisibleEdgeX | uiScrollFlags_KeepVisibleEdgeY;
    SetNavWindow(window);
    NavMoveRequestSubmit(Var::Dir::None, Var::Dir::Up, move_flags, scroll_flags);
    NavMoveRequestResolveWithLastItem(&g.NavMoveResultLocal);
}
