// Note: this will likely be called ActivateItem() once we rework our Focus/Activation system!
// But ActivateItem() should function without altering scroll/focus?
void UI::SetKeyboardFocusHere(int offset) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    IM_ASSERT(offset >= -1);    // -1 is allowed but not below
    IMGUI_DEBUG_LOG_FOCUS("SetKeyboardFocusHere(%d) in window \"%s\"\n", offset, window->Name);
    // It makes sense in the vast majority of cases to never interrupt a drag and drop.
    // When we refactor this function into ActivateItem() we may want to make this an option.
    // MovingWindow is protected from most user inputs using SetActiveIdUsingNavAndKeys(), but
    // is also automatically dropped in the event g.ActiveId is stolen.
    if (g.DragDropActive || g.MovingWindow != NULL) {
        IMGUI_DEBUG_LOG_FOCUS("SetKeyboardFocusHere() ignored while DragDropActive!\n");
        return;
    }
    SetNavWindow(window);
    uiNavMoveFlags move_flags = uiNavMoveFlags_IsTabbing | uiNavMoveFlags_Activate | uiNavMoveFlags_FocusApi | uiNavMoveFlags_NoSetNavCursorVisible;
    uiScrollFlags scroll_flags = window->Appearing ? uiScrollFlags_KeepVisibleEdgeX | uiScrollFlags_AlwaysCenterY : uiScrollFlags_KeepVisibleEdgeX | uiScrollFlags_KeepVisibleEdgeY;
    NavMoveRequestSubmit(Var::Dir::None, offset < 0 ? Var::Dir::Up : Var::Dir::Down, move_flags, scroll_flags); // FIXME-NAV: Once we refactor tabbing, add LegacyApi flag to not activate non-inputable.
    if (offset == -1) { NavMoveRequestResolveWithLastItem(&g.NavMoveResultLocal); }
    else { g.NavTabbingDir = 1; g.NavTabbingCounter = offset + 1; }
}
// TODO
void UI::SetItemDefaultFocus() {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    if (!window->Appearing) return;
    if (g.NavWindow != window->RootWindowForNav || (!g.NavInitRequest && g.NavInitResult.ID == 0) || g.NavLayer != window->DC.NavLayerCurrent)
        return;
    g.NavInitRequest = false;
    NavApplyItemToResult(&g.NavInitResult);
    NavUpdateAnyRequestFlag();
    // Scroll could be done in NavInitRequestApplyResult() via an opt-in flag (we however don't want regular init requests to scroll)
    if (!window->ClipRect.Contains(g.LastItemData.Rect))
        ScrollToRectEx(window, g.LastItemData.Rect, uiScrollFlags_None);
}
