// Push a given id value ignoring the ID stack as a seed.
void UI::PushOverrideID(uiID id) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
#ifndef IMGUI_DISABLE_DEBUG_TOOLS
    if (g.DebugHookIdInfoId == id) DebugHookIdInfo(id, uiDataType_ID, NULL, NULL);
#endif
    window->IDStack.push_back(id);
}
// Helper to avoid a common series of PushOverrideID -> GetID() -> PopID() call
// (note that when using this pattern, ID Stack Tool will tend to not display the intermediate stack level.
//  for that to work we would need to do PushOverrideID() -> ItemAdd() -> PopID() which would alter widget code a little more)
uiID UI::GetIDWithSeed(const char* str, const char* str_end, uiID seed) {
    uiID id = ImHashStr(str, str_end ? (str_end - str) : 0, seed);
#ifndef IMGUI_DISABLE_DEBUG_TOOLS
    uiContext& g = *GImGui;
    if (g.DebugHookIdInfoId == id) DebugHookIdInfo(id, uiDataType_String, str, str_end);
#endif
    return id;
}
uiID UI::GetIDWithSeed(int n, uiID seed) {
    uiID id = ImHashData(&n, sizeof(n), seed);
#ifndef IMGUI_DISABLE_DEBUG_TOOLS
    uiContext& g = *GImGui;
    if (g.DebugHookIdInfoId == id) DebugHookIdInfo(id, uiDataType_S32, (void*)(intptr_t)n, NULL);
#endif
    return id;
}
void UI::PopID() {
    uiWindow* window = GImGui->CurrentWindow;
    IM_ASSERT_USER_ERROR_RET(window->IDStack.Size > 1, "Calling PopID() too many times!");
    window->IDStack.pop_back();
}
uiID UI::GetID(const char* str_id) { uiWindow* window = GImGui->CurrentWindow; return window->GetID(str_id); }
uiID UI::GetID(const char* str_id_begin, const char* str_id_end) { uiWindow* window = GImGui->CurrentWindow; return window->GetID(str_id_begin, str_id_end); }
uiID UI::GetID(const void* ptr_id) { uiWindow* window = GImGui->CurrentWindow; return window->GetID(ptr_id); }
uiID UI::GetID(int int_id) { uiWindow* window = GImGui->CurrentWindow; return window->GetID(int_id); }
