static uiKeyChord GetModForLRModKey(uiKey key) {
    if (key == uiKey_LeftCtrl  || key == uiKey_RightCtrl)  return uiMod_Ctrl;
    if (key == uiKey_LeftShift || key == uiKey_RightShift) return uiMod_Shift;
    if (key == uiKey_LeftAlt   || key == uiKey_RightAlt)   return uiMod_Alt;
    if (key == uiKey_LeftSuper || key == uiKey_RightSuper) return uiMod_Super;
    return uiMod_None;
}
uiKeyChord UI::FixupKeyChord(uiKeyChord key_chord) {
    // Add uiMod_XXXX when a corresponding uiKey_LeftXXX/uiKey_RightXXX is specified.
    uiKey key = (uiKey)(key_chord & ~uiMod_Mask_);
    if (IsLRModKey(key)) key_chord |= GetModForLRModKey(key);
    return key_chord;
}
uiKeyData* UI::GetKeyData(uiContext* ctx, uiKey key) {
    uiContext& g = *ctx;
    // Special storage location for mods
    if (key & uiMod_Mask_) key = ConvertSingleModFlagToKey(key);
    IM_ASSERT(IsNamedKey(key) && "Support for user key indices was dropped in favor of uiKey. Please update backend & user code.");
    return &g.IO.KeysData[key - uiKey_NamedKey_BEGIN];
}
