// [SECTION] TOOLTIPS
//-----------------------------------------------------------------------------
bool UI::BeginTooltip() { return BeginTooltipEx(uiTooltipFlags_None, uiWindowFlags_None); }
bool UI::BeginItemTooltip() {
    if (!IsItemHovered(uiHoverFlags_ForTooltip)) return false;
    return BeginTooltipEx(uiTooltipFlags_None, uiWindowFlags_None);
}
bool UI::BeginTooltipEx(uiTooltipFlags tooltip_flags, uiWindowFlags extra_window_flags) {
    uiContext& g = *GImGui;
    const bool is_dragdrop_tooltip = g.DragDropWithinSource || g.DragDropWithinTarget;
    if (is_dragdrop_tooltip) {
        // Drag and Drop tooltips are positioning differently than other tooltips:
        // - offset visibility to increase visibility around mouse.
        // - never clamp within outer viewport boundary.
        // We call SetNextWindowPos() to enforce position and disable clamping.
        // See FindBestWindowPosForPopup() for positioning logic of other tooltips (not drag and drop ones).
        //vec2 tooltip_pos = g.IO.MousePos - g.ActiveIdClickOffset - g.Style.WindowPadding;
        const bool is_touchscreen = (g.IO.MouseSource == uiMouseSource_TouchScreen);
        if ((g.NextWindowData.HasFlags & uiNextWindowDataFlags_HasPos) == 0) {
            vec2 tooltip_pos = is_touchscreen ? (g.IO.MousePos + TOOLTIP_DEFAULT_OFFSET_TOUCH * AUR::Engine::mouseCursorScale) : (g.IO.MousePos + TOOLTIP_DEFAULT_OFFSET_MOUSE * AUR::Engine::mouseCursorScale);
            vec2 tooltip_pivot = is_touchscreen ? TOOLTIP_DEFAULT_PIVOT_TOUCH : vec2(0.0f, 0.0f);
            SetNextWindowPos(tooltip_pos, uiCond_None, tooltip_pivot);
        }
        SetNextWindowBgAlpha(g.Style.Colors[uiCol_PopupBg].w * 0.60f);
        //PushStyleVar(uiStyleVar_Alpha, g.Style.Alpha * 0.60f); // This would be nice but e.g ColorButton with checkerboard has issue with transparent colors :(
        tooltip_flags |= uiTooltipFlags_OverridePrevious;
    }
    // Hide previous tooltip from being displayed. We can't easily "reset" the content of a window so we create a new one.
    if ((tooltip_flags & uiTooltipFlags_OverridePrevious) && g.TooltipPreviousWindow != NULL && g.TooltipPreviousWindow->Active && !IsWindowInBeginStack(g.TooltipPreviousWindow)) {
        //IMGUI_DEBUG_LOG("[tooltip] '%s' already active, using +1 for this frame\n", window_name);
        SetWindowHiddenAndSkipItemsForCurrentFrame(g.TooltipPreviousWindow);
        g.TooltipOverrideCount++;
    }
    const char* window_name_template = is_dragdrop_tooltip ? "##Tooltip_DragDrop_%02d" : "##Tooltip_%02d";
    char window_name[32];
    ImFormatString(window_name, IM_COUNTOF(window_name), window_name_template, g.TooltipOverrideCount);
    uiWindowFlags flags = uiWindowFlags_Tooltip | uiWindowFlags_NoInputs | uiWindowFlags_NoTitleBar | uiWindowFlags_NoMove | uiWindowFlags_NoResize | uiWindowFlags_NoSavedSettings | uiWindowFlags_AutoResize | uiWindowFlags_NoDocking;
    Begin(window_name, NULL, flags | extra_window_flags);
    // 2023-03-09: Added bool return value to the API, but currently always returning true.
    // If this ever returns false we need to update BeginDragDropSource() accordingly.
    //if (!ret)
    //    End();
    //return ret;
    return true;
}
void UI::EndTooltip() {
    // Mismatched BeginTooltip()/EndTooltip() calls
    IM_ASSERT(GetCurrentWindowRead()->Flags & uiWindowFlags_Tooltip);
    End();
}
void UI::SetTooltip(const char* fmt, ...) {
    va_list args;
    va_start(args, fmt);
    SetTooltipV(fmt, args);
    va_end(args);
}
void UI::SetTooltipV(const char* fmt, va_list args) {
    if (!BeginTooltipEx(uiTooltipFlags_OverridePrevious, uiWindowFlags_None)) return;
    TextV(fmt, args);
    EndTooltip();
}
// Shortcut to use 'style.HoverFlagsForTooltipMouse' or 'style.HoverFlagsForTooltipNav'.
// Defaults to == uiHoverFlags_Stationary | uiHoverFlags_DelayShort when using the mouse.
void UI::SetItemTooltip(const char* fmt, ...) {
    va_list args;
    va_start(args, fmt);
    if (IsItemHovered(uiHoverFlags_ForTooltip)) SetTooltipV(fmt, args);
    va_end(args);
}
void UI::SetItemTooltipV(const char* fmt, va_list args) {
    if (IsItemHovered(uiHoverFlags_ForTooltip)) SetTooltipV(fmt, args);
}
//-----------------------------------------------------------------------------
// [SECTION] POPUPS
//-----------------------------------------------------------------------------
// Supported flags: uiPopupFlags_AnyPopupId, uiPopupFlags_AnyPopupLevel
bool UI::IsPopupOpen(uiID id, uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    if (popup_flags & uiPopupFlags_AnyPopupId) {
        // Return true if any popup is open at the current BeginPopup() level of the popup stack
        // This may be used to e.g. test for another popups already opened to handle popups priorities at the same level.
        IM_ASSERT(id == 0);
        if (popup_flags & uiPopupFlags_AnyPopupLevel) return g.OpenPopupStack.Size > 0;
        else return g.OpenPopupStack.Size > g.BeginPopupStack.Size;
    } else {
        if (popup_flags & uiPopupFlags_AnyPopupLevel) {
            // Return true if the popup is open anywhere in the popup stack
            for (uiPopupData& popup_data : g.OpenPopupStack)
                if (popup_data.PopupId == id)
                    return true;
            return false;
        } else {
            // Return true if the popup is open at the current BeginPopup() level of the popup stack (this is the most-common query)
            return g.OpenPopupStack.Size > g.BeginPopupStack.Size && g.OpenPopupStack[g.BeginPopupStack.Size].PopupId == id;
        }
    }
}
bool UI::IsPopupOpen(const char* str_id, uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    uiID id = (popup_flags & uiPopupFlags_AnyPopupId) ? 0 : g.CurrentWindow->GetID(str_id);
    if ((popup_flags & uiPopupFlags_AnyPopupLevel) && id != 0)
        IM_ASSERT(0 && "Cannot use IsPopupOpen() with a string id and uiPopupFlags_AnyPopupLevel."); // But non-string version is legal and used internally
    return IsPopupOpen(id, popup_flags);
}
// Also see FindBlockingModal(NULL)
uiWindow* UI::GetTopMostPopupModal() {
    uiContext& g = *GImGui;
    for (int n = g.OpenPopupStack.Size - 1; n >= 0; n--)
        if (uiWindow* popup = g.OpenPopupStack.Data[n].Window)
            if (popup->Flags & uiWindowFlags_Modal)
                return popup;
    return NULL;
}
// See Demo->Stacked Modal to confirm what this is for.
uiWindow* UI::GetTopMostAndVisiblePopupModal() {
    uiContext& g = *GImGui;
    for (int n = g.OpenPopupStack.Size - 1; n >= 0; n--)
        if (uiWindow* popup = g.OpenPopupStack.Data[n].Window)
            if ((popup->Flags & uiWindowFlags_Modal) && IsWindowActiveAndVisible(popup))
                return popup;
    return NULL;
}
// When a modal popup is open, newly created windows that want focus (i.e. are not popups and do not specify uiWindowFlags_NoFocusOnAppearing)
// should be positioned behind that modal window, unless the window was created inside the modal begin-stack.
// In case of multiple stacked modals newly created window honors begin stack order and does not go below its own modal parent.
// - WindowA            // FindBlockingModal() returns Modal1
//   - WindowB          //                  .. returns Modal1
//   - Modal1           //                  .. returns Modal2
//      - WindowC       //                  .. returns Modal2
//          - WindowD   //                  .. returns Modal2
//          - Modal2    //                  .. returns Modal2
//            - WindowE //                  .. returns NULL
// Notes:
// - FindBlockingModal(NULL) == NULL is generally equivalent to GetTopMostPopupModal() == NULL.
//   Only difference is here we check for ->Active/WasActive but it may be unnecessary.
uiWindow* UI::FindBlockingModal(uiWindow* window) {
    uiContext& g = *GImGui;
    if (g.OpenPopupStack.Size <= 0) return NULL;
    // Find a modal that has common parent with specified window. Specified window should be positioned behind that modal.
    for (uiPopupData& popup_data : g.OpenPopupStack) {
        uiWindow* popup_window = popup_data.Window;
        if (popup_window == NULL || !(popup_window->Flags & uiWindowFlags_Modal)) continue;
        // Check WasActive, because this code may run before popup renders on current frame, also check Active to handle newly created windows.
        if (!popup_window->Active && !popup_window->WasActive) continue;
        // FindBlockingModal(NULL) test for if FocusWindow(NULL) is naturally possible via a mouse click.
        if (window == NULL) return popup_window;
        // Window may be over modal
        if (IsWindowWithinBeginStackOf(window, popup_window)) continue;
        return popup_window; // Place window right below first block modal
    }
    return NULL;
}
void UI::OpenPopup(const char* str_id, uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    uiID id = g.CurrentWindow->GetID(str_id);
    IMGUI_DEBUG_LOG_POPUP("[popup] OpenPopup(\"%s\" -> 0x%08X)\n", str_id, id);
    OpenPopupEx(id, popup_flags);
}
void UI::OpenPopup(uiID id, uiPopupFlags popup_flags) { OpenPopupEx(id, popup_flags); }
// Mark popup as open (toggle toward open state).
// Popups are closed when user click outside, or activate a pressable item, or CloseCurrentPopup() is called within a BeginPopup()/EndPopup() block.
// Popup identifiers are relative to the current ID-stack (so OpenPopup and BeginPopup needs to be at the same level).
// One open popup per level of the popup hierarchy (NB: when assigning we reset the Window member of uiPopupRef to NULL)
void UI::OpenPopupEx(uiID id, uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    uiWindow* parent_window = g.CurrentWindow;
    const int current_stack_size = g.BeginPopupStack.Size;
    if (popup_flags & uiPopupFlags_NoOpenOverExistingPopup)
        if (IsPopupOpen((uiID)0, uiPopupFlags_AnyPopupId))
            return;
    uiPopupData popup_ref; // Tagged as new ref as Window will be set back to NULL if we write this into OpenPopupStack.
    popup_ref.PopupId = id;
    popup_ref.Window = NULL;
    popup_ref.RestoreNavWindow = g.NavWindow;           // When popup closes focus may be restored to NavWindow (depend on window type).
    popup_ref.OpenFrameCount = g.FrameCount;
    popup_ref.OpenParentId = parent_window->IDStack.back();
    popup_ref.OpenPopupPos = NavCalcPreferredRefPos(uiWindowFlags_Popup);
    popup_ref.OpenMousePos = IsMousePosValid(&g.IO.MousePos) ? g.IO.MousePos : popup_ref.OpenPopupPos;
    IMGUI_DEBUG_LOG_POPUP("[popup] OpenPopupEx(0x%08X)\n", id);
    if (g.OpenPopupStack.Size < current_stack_size + 1) {
        g.OpenPopupStack.push_back(popup_ref);
    } else {
        // Gently handle the user mistakenly calling OpenPopup() every frames: it is likely a programming mistake!
        // However, if we were to run the regular code path, the ui would become completely unusable because the popup will always be
        // in hidden-while-calculating-size state _while_ claiming focus. Which is extremely confusing situation for the programmer.
        // Instead, for successive frames calls to OpenPopup(), we silently avoid reopening even if uiPopupFlags_NoReopen is not specified.
        bool keep_existing = false;
        if (g.OpenPopupStack[current_stack_size].PopupId == id)
            if ((g.OpenPopupStack[current_stack_size].OpenFrameCount == g.FrameCount - 1) || (popup_flags & uiPopupFlags_NoReopen))
                keep_existing = true;
        if (keep_existing) {
            // No reopen
            g.OpenPopupStack[current_stack_size].OpenFrameCount = popup_ref.OpenFrameCount;
        } else {
            // Reopen: close child popups if any, then flag popup for open/reopen (set position, focus, init navigation)
            ClosePopupToLevel(current_stack_size, true);
            g.OpenPopupStack.push_back(popup_ref);
        }
        // When reopening a popup we first refocus its parent, otherwise if its parent is itself a popup it would get closed by ClosePopupsOverWindow().
        // This is equivalent to what ClosePopupToLevel() does.
        //if (g.OpenPopupStack[current_stack_size].PopupId == id)
        //    FocusWindow(parent_window);
    }
}
// When popups are stacked, clicking on a lower level popups puts focus back to it and close popups above it.
// This function closes any popups that are over 'ref_window'.
void UI::ClosePopupsOverWindow(uiWindow* ref_window, bool restore_focus_to_window_under_popup) {
    uiContext& g = *GImGui;
    if (g.OpenPopupStack.Size == 0) return;
    // Don't close our own child popup windows.
    //IMGUI_DEBUG_LOG_POPUP("[popup] ClosePopupsOverWindow(\"%s\") restore_under=%d\n", ref_window ? ref_window->Name : "<NULL>", restore_focus_to_window_under_popup);
    int popup_count_to_keep = 0;
    if (ref_window) {
        // Find the highest popup which is a descendant of the reference window (generally reference window = NavWindow)
        for (; popup_count_to_keep < g.OpenPopupStack.Size; popup_count_to_keep++) {
            uiPopupData& popup = g.OpenPopupStack[popup_count_to_keep];
            if (!popup.Window)
                continue;
            IM_ASSERT((popup.Window->Flags & uiWindowFlags_Popup) != 0);
            // Trim the stack unless the popup is a direct parent of the reference window (the reference window is often the NavWindow)
            // - Clicking/Focusing Window2 won't close Popup1:
            //     Window -> Popup1 -> Window2(Ref)
            // - Clicking/focusing Popup1 will close Popup2 and Popup3:
            //     Window -> Popup1(Ref) -> Popup2 -> Popup3
            // - Each popups may contain child windows, which is why we compare ->RootWindowDockTree!
            //     Window -> Popup1 -> Popup1_Child -> Popup2 -> Popup2_Child
            // We step through every popup from bottom to top to validate their position relative to reference window.
            bool ref_window_is_descendant_of_popup = false;
            for (int n = popup_count_to_keep; n < g.OpenPopupStack.Size; n++)
                if (uiWindow* popup_window = g.OpenPopupStack[n].Window)
                    //if (popup_window->RootWindowDockTree == ref_window->RootWindowDockTree) // FIXME-MERGE
                    if (IsWindowWithinBeginStackOf(ref_window, popup_window)) {
                        ref_window_is_descendant_of_popup = true;
                        break;
                    }
            if (!ref_window_is_descendant_of_popup) break;
        }
    } if (popup_count_to_keep < g.OpenPopupStack.Size) {
        // This test is not required but it allows to set a convenient breakpoint on the statement below
        IMGUI_DEBUG_LOG_POPUP("[popup] ClosePopupsOverWindow(\"%s\")\n", ref_window ? ref_window->Name : "<NULL>");
        ClosePopupToLevel(popup_count_to_keep, restore_focus_to_window_under_popup);
    }
}
void UI::ClosePopupsExceptModals() {
    uiContext& g = *GImGui;
    int popup_count_to_keep;
    for (popup_count_to_keep = g.OpenPopupStack.Size; popup_count_to_keep > 0; popup_count_to_keep--) {
        uiWindow* window = g.OpenPopupStack[popup_count_to_keep - 1].Window;
        if (!window || (window->Flags & uiWindowFlags_Modal)) break;
    }
    // This test is not required but it allows to set a convenient breakpoint on the statement below
    if (popup_count_to_keep < g.OpenPopupStack.Size) ClosePopupToLevel(popup_count_to_keep, true);
}
void UI::ClosePopupToLevel(int remaining, bool restore_focus_to_window_under_popup) {
    uiContext& g = *GImGui;
    IMGUI_DEBUG_LOG_POPUP("[popup] ClosePopupToLevel(%d), restore_under=%d\n", remaining, restore_focus_to_window_under_popup);
    IM_ASSERT(remaining >= 0 && remaining < g.OpenPopupStack.Size);
    if (g.DebugLogFlags & uiDebugLogFlags_EventPopup)
        for (int n = remaining; n < g.OpenPopupStack.Size; n++)
            IMGUI_DEBUG_LOG_POPUP("[popup] - Closing PopupID 0x%08X Window \"%s\"\n", g.OpenPopupStack[n].PopupId, g.OpenPopupStack[n].Window ? g.OpenPopupStack[n].Window->Name : NULL);
    // Trim open popup stack
    uiPopupData prev_popup = g.OpenPopupStack[remaining];
    g.OpenPopupStack.resize(remaining);
    // Restore focus (unless popup window was not yet submitted, and didn't have a chance to take focus anyhow. See #7325 for an edge case)
    if (restore_focus_to_window_under_popup && prev_popup.Window) {
        uiWindow* popup_window = prev_popup.Window;
        uiWindow* focus_window = (popup_window->Flags & uiWindowFlags_ChildMenu) ? popup_window->ParentWindow : prev_popup.RestoreNavWindow;
        if (focus_window && !focus_window->WasActive)
            FocusTopMostWindowUnderOne(popup_window, NULL, NULL, uiFocusRequestFlags_RestoreFocusedChild); // Fallback
        else
            FocusWindow(focus_window, (g.NavLayer == uiNavLayer_Main) ? uiFocusRequestFlags_RestoreFocusedChild : uiFocusRequestFlags_None);
    }
}
// Close the popup we have begin-ed into.
void UI::CloseCurrentPopup() {
    uiContext& g = *GImGui;
    int popup_idx = g.BeginPopupStack.Size - 1;
    if (popup_idx < 0 || popup_idx >= g.OpenPopupStack.Size || g.BeginPopupStack[popup_idx].PopupId != g.OpenPopupStack[popup_idx].PopupId)
        return;
    // Closing a menu closes its top-most parent popup (unless a modal)
    while (popup_idx > 0) {
        uiWindow* popup_window = g.OpenPopupStack[popup_idx].Window;
        uiWindow* parent_popup_window = g.OpenPopupStack[popup_idx - 1].Window;
        bool close_parent = false;
        if (popup_window && (popup_window->Flags & uiWindowFlags_ChildMenu))
            if (parent_popup_window && !(parent_popup_window->Flags & uiWindowFlags_MenuBar)) close_parent = true;
        if (!close_parent) break;
        popup_idx--;
    }
    IMGUI_DEBUG_LOG_POPUP("[popup] CloseCurrentPopup %d -> %d\n", g.BeginPopupStack.Size - 1, popup_idx);
    ClosePopupToLevel(popup_idx, true);
    // A common pattern is to close a popup when selecting a menu item/selectable that will open another window.
    // To improve this usage pattern, we avoid nav highlight for a single frame in the parent window.
    // Similarly, we could avoid mouse hover highlight in this window but it is less visually problematic.
    if (uiWindow* window = g.NavWindow) window->DC.NavHideHighlightOneFrame = true;
}
// Attention! BeginPopup() adds default flags when calling BeginPopupEx()!
bool UI::BeginPopupEx(uiID id, uiWindowFlags extra_window_flags) {
    uiContext& g = *GImGui;
    // We behave like Begin() and need to consume those values
    if (!IsPopupOpen(id, uiPopupFlags_None)) { g.NextWindowData.ClearFlags(); return false; }
    char name[20];
    IM_ASSERT((extra_window_flags & uiWindowFlags_ChildMenu) == 0); // Use BeginPopupMenuEx()
    ImFormatString(name, IM_COUNTOF(name), "##Popup_%08x", id); // No recycling, so we can close/open during the same frame
    bool is_open = Begin(name, NULL, extra_window_flags | uiWindowFlags_Popup | uiWindowFlags_NoDocking);
    // NB: Begin can return false when the popup is completely clipped (e.g. zero size display)
    if (!is_open) EndPopup();
    //g.CurrentWindow->FocusRouteParentWindow = g.CurrentWindow->ParentWindowInBeginStack;
    return is_open;
}
bool UI::BeginPopupMenuEx(uiID id, const char* label, uiWindowFlags extra_window_flags) {
    uiContext& g = *GImGui;
    // We behave like Begin() and need to consume those values
    if (!IsPopupOpen(id, uiPopupFlags_None)) { g.NextWindowData.ClearFlags(); return false; }
    // As we bypass BeginChild(), set uiChildFlags_AutoResize as it is checked independently from uiWindowFlags_AutoResize for now (see #9355)
    // Ideally we should remove setting uiWindowFlags_AutoResize in BeginChild().
    if ((extra_window_flags & uiWindowFlags_ChildWindow) && (extra_window_flags & uiWindowFlags_AutoResize)) {
        if (g.NextWindowData.HasFlags & uiNextWindowDataFlags_HasChildFlags)
            g.NextWindowData.ChildFlags |= uiChildFlags_AutoResize;
        else g.NextWindowData.ChildFlags = uiChildFlags_AutoResize;
        g.NextWindowData.HasFlags |= uiNextWindowDataFlags_HasChildFlags;
    }
    char name[128];
    IM_ASSERT(extra_window_flags & uiWindowFlags_ChildMenu);
    ImFormatString(name, IM_COUNTOF(name), "%s###Menu_%02d", label, g.BeginMenuDepth); // Recycle windows based on depth
    bool is_open = Begin(name, NULL, extra_window_flags | uiWindowFlags_Popup);
    // NB: Begin can return false when the popup is completely clipped (e.g. zero size display)
    if (!is_open) EndPopup();
    //g.CurrentWindow->FocusRouteParentWindow = g.CurrentWindow->ParentWindowInBeginStack;
    return is_open;
}
bool UI::BeginPopup(const char* str_id, uiWindowFlags flags) {
    uiContext& g = *GImGui;
    // Early out for performance. We behave like Begin() and need to consume those values
    if (g.OpenPopupStack.Size <= g.BeginPopupStack.Size) { g.NextWindowData.ClearFlags(); return false; }
    flags |= uiWindowFlags_AutoResize | uiWindowFlags_NoTitleBar | uiWindowFlags_NoSavedSettings;
    uiID id = g.CurrentWindow->GetID(str_id);
    return BeginPopupEx(id, flags);
}
// If 'p_open' is specified for a modal popup window, the popup will have a regular close button which will close the popup.
// Note that popup visibility status is owned by Dear ImGui (and manipulated with e.g. OpenPopup).
// - *p_open set back to false in BeginPopupModal() when popup is not open.
// - if you set *p_open to false before calling BeginPopupModal(), it will close the popup.
bool UI::BeginPopupModal(const char* name, bool* p_open, uiWindowFlags flags) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    const uiID id = window->GetID(name);
    if (!IsPopupOpen(id, uiPopupFlags_None)) {
        // We behave like Begin() and need to consume those values
        g.NextWindowData.ClearFlags();
        if (p_open && *p_open) *p_open = false;
        return false;
    }
    // Center modal windows by default for increased visibility
    // (this won't really last as settings will kick in, and is mostly for backward compatibility. user may do the same themselves)
    // FIXME: Should test for (PosCond & window->SetWindowPosAllowFlags) with the upcoming window.
    if ((g.NextWindowData.HasFlags & uiNextWindowDataFlags_HasPos) == 0) {
        const uiViewport* viewport = window->WasActive ? window->Viewport : GetMainViewport(); // FIXME-VIEWPORT: What may be our reference viewport?
        SetNextWindowPos(viewport->GetCenter(), uiCond_FirstUseEver, vec2(0.5f, 0.5f));
    }
    flags |= uiWindowFlags_Popup | uiWindowFlags_Modal | uiWindowFlags_NoCollapse | uiWindowFlags_NoDocking;
    const bool is_open = Begin(name, p_open, flags);
    // NB: is_open can be 'false' when the popup is completely clipped (e.g. zero size display)
    if (!is_open || (p_open && !*p_open)) {
        EndPopup();
        if (is_open) ClosePopupToLevel(g.BeginPopupStack.Size, true);
        return false;
    }
    return is_open;
}
void UI::EndPopup() {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    IM_ASSERT_USER_ERROR_RET((window->Flags & uiWindowFlags_Popup) != 0 && g.BeginPopupStack.Size > 0, "Calling EndPopup() in wrong window!");
    // Make all menus and popups wrap around for now, may need to expose that policy (e.g. focus scope could include wrap/loop policy flags used by new move requests)
    if (g.NavWindow == window) NavMoveRequestTryWrapping(window, uiNavMoveFlags_LoopY);
    // Child-popups don't need to be laid out
    const uiID backup_within_end_popup_id = g.WithinEndPopupID;
    const uiID backup_within_end_child_id = g.WithinEndChildID;
    g.WithinEndPopupID = window->ID;
    if (window->Flags & uiWindowFlags_ChildWindow) g.WithinEndChildID = window->ID;
    End();
    g.WithinEndPopupID = backup_within_end_popup_id;
    g.WithinEndChildID = backup_within_end_child_id;
}
uiMouseButton UI::GetMouseButtonFromPopupFlags(uiPopupFlags flags) {
    IM_ASSERT((flags & uiPopupFlags_InvalidMask_) == 0);
    if (flags & uiPopupFlags_MouseButtonMask_)
        return ((flags & uiPopupFlags_MouseButtonMask_) >> uiPopupFlags_MouseButtonShift_) - 1;
    return uiMouseButton_Right; // Default == 1
}
bool UI::IsPopupOpenRequestForItem(uiPopupFlags popup_flags, uiID id) {
    uiContext& g = *GImGui;
    uiMouseButton mouse_button = GetMouseButtonFromPopupFlags(popup_flags);
    if (IsMouseReleased(mouse_button) && IsItemHovered(uiHoverFlags_AllowWhenBlockedByPopup))
        return true;
    if (g.NavOpenContextMenuItemId == id && (IsItemFocused() || id == g.CurrentWindow->MoveId))
        return true;
    return false;
}
bool UI::IsPopupOpenRequestForWindow(uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    uiMouseButton mouse_button = GetMouseButtonFromPopupFlags(popup_flags);
    if (IsMouseReleased(mouse_button) && IsWindowHovered(uiHoverFlags_AllowWhenBlockedByPopup))
        if (!(popup_flags & uiPopupFlags_NoOpenOverItems) || !IsAnyItemHovered())
            return true;
    if (g.NavOpenContextMenuWindowId && g.CurrentWindow->ID)
        if (IsWindowChildOf(g.NavWindow, g.CurrentWindow, false, false)) return true; // This enable ordering to be used to disambiguate item vs window (#8803)
    return false;
}
// Helper to open a popup if mouse button is released over the item
// - This is essentially the same as BeginPopupContextItem() but without the trailing BeginPopup()
void UI::OpenPopupOnItemClick(const char* str_id, uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    if (IsPopupOpenRequestForItem(popup_flags, g.LastItemData.ID)) {
        uiID id = str_id ? window->GetID(str_id) : g.LastItemData.ID; // If user hasn't passed an ID, we can use the LastItemID. Using LastItemID as a Popup ID won't conflict!
        IM_ASSERT(id != 0);                                              // You cannot pass a NULL str_id if the last item has no identifier (e.g. a Text() item)
        OpenPopupEx(id, popup_flags);
    }
}
// This is a helper to handle the simplest case of associating one named popup to one given widget.
// - To create a popup associated to the last item, you generally want to pass a NULL value to str_id.
// - To create a popup with a specific identifier, pass it in str_id.
//    - This is useful when using using BeginPopupContextItem() on an item which doesn't have an identifier, e.g. a Text() call.
//    - This is useful when multiple code locations may want to manipulate/open the same popup, given an explicit id.
// - You may want to handle the whole on user side if you have specific needs (e.g. tweaking IsItemHovered() parameters).
//   This is essentially the same as:
//       id = str_id ? GetID(str_id) : GetItemID();
//       OpenPopupOnItemClick(str_id, uiPopupFlags_MouseButtonRight);
//       return BeginPopup(id);
//   Which is essentially the same as:
//       id = str_id ? GetID(str_id) : GetItemID();
//       if (IsItemHovered() && IsMouseReleased(uiMouseButton_Right))
//           OpenPopup(id);
//       return BeginPopup(id);
//   The main difference being that this is tweaked to avoid computing the ID twice.
bool UI::BeginPopupContextItem(const char* str_id, uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    if (window->SkipItems) return false;
    uiID id = str_id ? window->GetID(str_id) : g.LastItemData.ID; // If user hasn't passed an ID, we can use the LastItem ID. Using LastItem ID as a Popup ID won't conflict!
    IM_ASSERT(id != 0);                                              // You cannot pass a NULL str_id if the last item has no identifier (e.g. a Text() item)
    if (IsPopupOpenRequestForItem(popup_flags, g.LastItemData.ID)) OpenPopupEx(id, popup_flags);
    return BeginPopupEx(id, uiWindowFlags_AutoResize | uiWindowFlags_NoTitleBar | uiWindowFlags_NoSavedSettings);
}
bool UI::BeginPopupContextWindow(const char* str_id, uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    if (!str_id) str_id = "window_context";
    uiID id = window->GetID(str_id);
    if (IsPopupOpenRequestForWindow(popup_flags)) OpenPopupEx(id, popup_flags);
    return BeginPopupEx(id, uiWindowFlags_AutoResize | uiWindowFlags_NoTitleBar | uiWindowFlags_NoSavedSettings);
}
bool UI::BeginPopupContextVoid(const char* str_id, uiPopupFlags popup_flags) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    if (!str_id) str_id = "void_context";
    uiID id = window->GetID(str_id);
    uiMouseButton mouse_button = GetMouseButtonFromPopupFlags(popup_flags);
    if (IsMouseReleased(mouse_button) && !IsWindowHovered(uiHoverFlags_AnyWindow))
        if (GetTopMostPopupModal() == NULL) OpenPopupEx(id, popup_flags);
    return BeginPopupEx(id, uiWindowFlags_AutoResize | uiWindowFlags_NoTitleBar | uiWindowFlags_NoSavedSettings);
}
// r_avoid = the rectangle to avoid (e.g. for tooltip it is a rectangle around the mouse cursor which we want to avoid. for popups it's a small point around the cursor.)
// r_outer = the visible area rectangle, minus safe area padding. If our popup size won't fit because of safe area padding we ignore it.
// (r_outer is usually equivalent to the viewport rectangle minus padding, but when multi-viewports are enabled and monitor
//  information are available, it may represent the entire platform monitor from the frame of reference of the current viewport.
//  this allows us to have tooltips/popups displayed out of the parent viewport.)
vec2 UI::FindBestWindowPosForPopupEx(const vec2& ref_pos, const vec2& size, Var::Dir* last_dir, const ImRect& r_outer, const ImRect& r_avoid, uiPopupPositionPolicy policy) {
    vec2 base_pos_clamped = ImClamp(ref_pos, r_outer.Min, r_outer.Max - size);
    //GetForegroundDrawList()->AddRect(r_avoid.Min, r_avoid.Max, IM_COL32(255,0,0,255));
    //GetForegroundDrawList()->AddRect(r_outer.Min, r_outer.Max, IM_COL32(0,255,0,255));
    // Combo Box policy (we want a connecting edge)
    if (policy == uiPopupPositionPolicy_ComboBox) {
        const Var::Dir dir_preferred_order[Var::Dir::COUNT] = { Var::Dir::Down, Var::Dir::Right, Var::Dir::Left, Var::Dir::Up };
        for (int n = (*last_dir != Var::Dir::None) ? -1 : 0; n < Var::Dir::COUNT; n++) {
            const Var::Dir dir = (n == -1) ? *last_dir : dir_preferred_order[n];
            // Already tried this direction?
            if (n != -1 && dir == *last_dir) continue;
            vec2 pos;
            if (dir == Var::Dir::Down)  pos = vec2(r_avoid.Min.x, r_avoid.Max.y);          // Below, Toward Right (default)
            if (dir == Var::Dir::Right) pos = vec2(r_avoid.Min.x, r_avoid.Min.y - size.y); // Above, Toward Right
            if (dir == Var::Dir::Left)  pos = vec2(r_avoid.Max.x - size.x, r_avoid.Max.y); // Below, Toward Left
            if (dir == Var::Dir::Up)    pos = vec2(r_avoid.Max.x - size.x, r_avoid.Min.y - size.y); // Above, Toward Left
            if (!r_outer.Contains(ImRect(pos, pos + size))) continue;
            *last_dir = dir;
            return pos;
        }
    }
    // Tooltip and Default popup policy
    // (Always first try the direction we used on the last frame, if any)
    if (policy == uiPopupPositionPolicy_Tooltip || policy == uiPopupPositionPolicy_Default) {
        const Var::Dir dir_preferred_order[Var::Dir::COUNT] = { Var::Dir::Right, Var::Dir::Down, Var::Dir::Up, Var::Dir::Left };
        for (int n = (*last_dir != Var::Dir::None) ? -1 : 0; n < Var::Dir::COUNT; n++) {
            const Var::Dir dir = (n == -1) ? *last_dir : dir_preferred_order[n];
            // Already tried this direction?
            if (n != -1 && dir == *last_dir) continue;
            const float avail_w = (dir == Var::Dir::Left ? r_avoid.Min.x : r_outer.Max.x) - (dir == Var::Dir::Right ? r_avoid.Max.x : r_outer.Min.x);
            const float avail_h = (dir == Var::Dir::Up ? r_avoid.Min.y : r_outer.Max.y) - (dir == Var::Dir::Down ? r_avoid.Max.y : r_outer.Min.y);
            // If there's not enough room on one axis, there's no point in positioning on a side on this axis (e.g. when not enough width, use a top/bottom position to maximize available width)
            if (avail_w < size.x && (dir == Var::Dir::Left || dir == Var::Dir::Right)) continue;
            if (avail_h < size.y && (dir == Var::Dir::Up || dir == Var::Dir::Down)) continue;
            vec2 pos;
            pos.x = (dir == Var::Dir::Left) ? r_avoid.Min.x - size.x : (dir == Var::Dir::Right) ? r_avoid.Max.x : base_pos_clamped.x;
            pos.y = (dir == Var::Dir::Up) ? r_avoid.Min.y - size.y : (dir == Var::Dir::Down) ? r_avoid.Max.y : base_pos_clamped.y;
            // Clamp top-left corner of popup
            pos.x = ImMax(pos.x, r_outer.Min.x);
            pos.y = ImMax(pos.y, r_outer.Min.y);
            *last_dir = dir;
            return pos;
        }
    }
    // Fallback when not enough room:
    *last_dir = Var::Dir::None;
    // For tooltip we prefer avoiding the cursor at all cost even if it means that part of the tooltip won't be visible.
    if (policy == uiPopupPositionPolicy_Tooltip) return ref_pos + vec2(2, 2);
    // Otherwise try to keep within display
    vec2 pos = ref_pos;
    pos.x = ImMax(ImMin(pos.x + size.x, r_outer.Max.x) - size.x, r_outer.Min.x);
    pos.y = ImMax(ImMin(pos.y + size.y, r_outer.Max.y) - size.y, r_outer.Min.y);
    return pos;
}
// Note that this is used for popups, which can overlap the non work-area of individual viewports.
ImRect UI::GetPopupAllowedExtentRect(uiWindow* window) {
    uiContext& g = *GImGui;
    ImRect r_screen;
    if (window->ViewportAllowPlatformMonitorExtend >= 0) {
        // Extent with be in the frame of reference of the given viewport (so Min is likely to be negative here)
        const uiPlatformMonitor& monitor = g.PlatformIO.Monitors[window->ViewportAllowPlatformMonitorExtend];
        r_screen.Min = monitor.WorkPos;
        r_screen.Max = monitor.WorkPos + monitor.WorkSize;
    // Use the full viewport area (not work area) for popups
    } else { r_screen = window->Viewport->GetMainRect(); }
    vec2 padding = g.Style.DisplaySafeAreaPadding;
    r_screen.Expand(vec2((r_screen.GetWidth() > padding.x * 2) ? -padding.x : 0.0f, (r_screen.GetHeight() > padding.y * 2) ? -padding.y : 0.0f));
    return r_screen;
}
vec2 UI::FindBestWindowPosForPopup(uiWindow* window) {
    uiContext& g = *GImGui;
    ImRect r_outer = GetPopupAllowedExtentRect(window);
    if (window->Flags & uiWindowFlags_ChildMenu) {
        // Child menus typically request _any_ position within the parent menu item, and then we move the new menu outside the parent bounds.
        // This is how we end up with child menus appearing (most-commonly) on the right of the parent menu.
        uiWindow* parent_window = window->ParentWindow;
        float horizontal_overlap = g.Style.ItemInnerSpacing.x; // We want some overlap to convey the relative depth of each menu (currently the amount of overlap is hard-coded to style.ItemSpacing.x).
        ImRect r_avoid;
        if (parent_window->DC.MenuBarAppending)
            r_avoid = ImRect(-FLT_MAX, parent_window->ClipRect.Min.y, FLT_MAX, parent_window->ClipRect.Max.y); // Avoid parent menu-bar. If we wanted multi-line menu-bar, we may instead want to have the calling window setup e.g. a NextWindowData.PosConstraintAvoidRect field
        else
            r_avoid = ImRect(parent_window->Pos.x + horizontal_overlap, -FLT_MAX, parent_window->Pos.x + parent_window->Size.x - horizontal_overlap - parent_window->ScrollbarSizes.x, FLT_MAX);
        return FindBestWindowPosForPopupEx(window->Pos, window->Size, &window->AutoPosLastDirection, r_outer, r_avoid, uiPopupPositionPolicy_Default);
    }
    if (window->Flags & uiWindowFlags_Popup) {
        return FindBestWindowPosForPopupEx(window->Pos, window->Size, &window->AutoPosLastDirection, r_outer, ImRect(window->Pos, window->Pos), uiPopupPositionPolicy_Default); // Ideally we'd disable r_avoid here
    }
    if (window->Flags & uiWindowFlags_Tooltip) {
        // Position tooltip (always follows mouse + clamp within outer boundaries)
        // FIXME:
        // - Too many paths. One problem is that FindBestWindowPosForPopupEx() doesn't allow passing a suggested position (so touch screen path doesn't use it by default).
        // - Drag and drop tooltips are not using this path either: BeginTooltipEx() manually sets their position.
        // - Require some tidying up. In theory we could handle both cases in same location, but requires a bit of shuffling
        //   as drag and drop tooltips are calling SetNextWindowPos() leading to 'window_pos_set_by_api' being set in Begin().
        IM_ASSERT(g.CurrentWindow == window);
        const float scale = AUR::Engine::mouseCursorScale;
        const vec2 ref_pos = NavCalcPreferredRefPos(uiWindowFlags_Tooltip);
        if (g.IO.MouseSource == uiMouseSource_TouchScreen && NavCalcPreferredRefPosSource(uiWindowFlags_Tooltip) == uiInputSource_Mouse) {
            vec2 tooltip_pos = ref_pos + TOOLTIP_DEFAULT_OFFSET_TOUCH * scale - (TOOLTIP_DEFAULT_PIVOT_TOUCH * window->Size);
            if (r_outer.Contains(ImRect(tooltip_pos, tooltip_pos + window->Size))) return tooltip_pos;
        }
        vec2 tooltip_pos = ref_pos + vec2(16, AUR::Engine::tooltipOffset) * scale;
        ImRect r_avoid;
        if (g.NavCursorVisible && g.NavHighlightItemUnderNav && !g.IO.ConfigNavMoveSetMousePos)
            r_avoid = ImRect(ref_pos.x - 16, ref_pos.y - 8, ref_pos.x + 16, ref_pos.y + 8);
        else
            r_avoid = ImRect(ref_pos.x - 16, ref_pos.y - 8, ref_pos.x + 24 * scale, ref_pos.y + 24 * scale); // FIXME: Hard-coded based on mouse cursor shape expectation. Exact dimension not very important.
        //GetForegroundDrawList()->AddRect(r_avoid.Min, r_avoid.Max, IM_COL32(255, 0, 255, 255));
        return FindBestWindowPosForPopupEx(tooltip_pos, window->Size, &window->AutoPosLastDirection, r_outer, r_avoid, uiPopupPositionPolicy_Tooltip);
    }
    IM_ASSERT(0);
    return window->Pos;
}
//-----------------------------------------------------------------------------
// [SECTION] WINDOW FOCUS
//----------------------------------------------------------------------------
// - SetWindowFocus()
// - SetNextWindowFocus()
// - IsWindowFocused()
// - UpdateWindowInFocusOrderList() [Internal]
// - BringWindowToFocusFront() [Internal]
// - BringWindowToDisplayFront() [Internal]
// - BringWindowToDisplayBack() [Internal]
// - BringWindowToDisplayBehind() [Internal]
// - FindWindowDisplayIndex() [Internal]
// - FocusWindow() [Internal]
// - FocusTopMostWindowUnderOne() [Internal]
//-----------------------------------------------------------------------------
void UI::SetWindowFocus() { FocusWindow(GImGui->CurrentWindow); }
void UI::SetWindowFocus(const char* name) {
    if (name) {
        if (uiWindow* window = FindWindowByName(name)) FocusWindow(window);
    } else {
        FocusWindow(NULL);
    }
}
void UI::SetNextWindowFocus() {
    uiContext& g = *GImGui;
    g.NextWindowData.HasFlags |= uiNextWindowDataFlags_HasFocus;
}
// Similar to IsWindowHovered()
bool UI::IsWindowFocused(uiFocusFlags flags) {
    uiContext& g = *GImGui;
    uiWindow* ref_window = g.NavWindow;
    uiWindow* cur_window = g.CurrentWindow;
    if (ref_window == NULL) return false;
    if (flags & uiFocusFlags_AnyWindow) return true;
    IM_ASSERT(cur_window); // Not inside a Begin()/End()
    const bool popup_hierarchy = (flags & uiFocusFlags_NoPopupHierarchy) == 0;
    const bool dock_hierarchy = (flags & uiFocusFlags_DockHierarchy) != 0;
    if (flags & uiFocusFlags_RootWindow)
        cur_window = GetCombinedRootWindow(cur_window, popup_hierarchy, dock_hierarchy);
    if (flags & uiFocusFlags_ChildWindows)
        return IsWindowChildOf(ref_window, cur_window, popup_hierarchy, dock_hierarchy);
    else
        return ref_window == cur_window;
}
static int UI::FindWindowFocusIndex(uiWindow* window) {
    uiContext& g = *GImGui;
    IM_UNUSED(g);
    int order = window->FocusOrder;
    IM_ASSERT(window->RootWindow == window); // No child window (not testing _ChildWindow because of docking)
    IM_ASSERT(g.WindowsFocusOrder[order] == window);
    return order;
}
static void UI::UpdateWindowInFocusOrderList(uiWindow* window, bool just_created, uiWindowFlags new_flags) {
    uiContext& g = *GImGui;
    const bool new_is_explicit_child = (new_flags & uiWindowFlags_ChildWindow) != 0 && ((new_flags & uiWindowFlags_Popup) == 0 || (new_flags & uiWindowFlags_ChildMenu) != 0);
    const bool child_flag_changed = new_is_explicit_child != window->IsExplicitChild;
    if ((just_created || child_flag_changed) && !new_is_explicit_child) {
        IM_ASSERT(!g.WindowsFocusOrder.contains(window));
        g.WindowsFocusOrder.push_back(window);
        window->FocusOrder = (short)(g.WindowsFocusOrder.Size - 1);
    } else if (!just_created && child_flag_changed && new_is_explicit_child) {
        IM_ASSERT(g.WindowsFocusOrder[window->FocusOrder] == window);
        for (int n = window->FocusOrder + 1; n < g.WindowsFocusOrder.Size; n++)
            g.WindowsFocusOrder[n]->FocusOrder--;
        g.WindowsFocusOrder.erase(g.WindowsFocusOrder.Data + window->FocusOrder);
        window->FocusOrder = -1;
    }
    window->IsExplicitChild = new_is_explicit_child;
}
void UI::BringWindowToFocusFront(uiWindow* window) {
    uiContext& g = *GImGui;
    IM_ASSERT(window == window->RootWindow);
    const int cur_order = window->FocusOrder;
    IM_ASSERT(g.WindowsFocusOrder[cur_order] == window);
    if (g.WindowsFocusOrder.back() == window) return;
    const int new_order = g.WindowsFocusOrder.Size - 1;
    for (int n = cur_order; n < new_order; n++) {
        g.WindowsFocusOrder[n] = g.WindowsFocusOrder[n + 1];
        g.WindowsFocusOrder[n]->FocusOrder--;
        IM_ASSERT(g.WindowsFocusOrder[n]->FocusOrder == n);
    }
    g.WindowsFocusOrder[new_order] = window;
    window->FocusOrder = (short)new_order;
}
// Note technically focus related but rather adjacent and close to BringWindowToFocusFront()
// FIXME-FOCUS: Could opt-in/opt-out enable modal check like in FocusWindow().
void UI::BringWindowToDisplayFront(uiWindow* window) {
    uiContext& g = *GImGui;
    uiWindow* current_front_window = g.Windows.back();
    if (current_front_window == window || current_front_window->RootWindowDockTree == window) // Cheap early out (could be better)
        return;
    for (int i = g.Windows.Size - 2; i >= 0; i--) // We can ignore the top-most window
        if (g.Windows[i] == window) {
            memmove(&g.Windows[i], &g.Windows[i + 1], (size_t)(g.Windows.Size - i - 1) * sizeof(uiWindow*));
            g.Windows[g.Windows.Size - 1] = window;
            break;
        }
}
void UI::BringWindowToDisplayBack(uiWindow* window) {
    uiContext& g = *GImGui;
    if (g.Windows[0] == window) return;
    for (int i = 0; i < g.Windows.Size; i++)
        if (g.Windows[i] == window) {
            memmove(&g.Windows[1], &g.Windows[0], (size_t)i * sizeof(uiWindow*));
            g.Windows[0] = window;
            break;
        }
}
void UI::BringWindowToDisplayBehind(uiWindow* window, uiWindow* behind_window) {
    IM_ASSERT(window != NULL && behind_window != NULL);
    uiContext& g = *GImGui;
    window = window->RootWindow;
    behind_window = behind_window->RootWindow;
    int pos_wnd = FindWindowDisplayIndex(window);
    int pos_beh = FindWindowDisplayIndex(behind_window);
    if (pos_wnd < pos_beh) {
        size_t copy_bytes = (pos_beh - pos_wnd - 1) * sizeof(uiWindow*);
        memmove(&g.Windows.Data[pos_wnd], &g.Windows.Data[pos_wnd + 1], copy_bytes);
        g.Windows[pos_beh - 1] = window;
    } else {
        size_t copy_bytes = (pos_wnd - pos_beh) * sizeof(uiWindow*);
        memmove(&g.Windows.Data[pos_beh + 1], &g.Windows.Data[pos_beh], copy_bytes);
        g.Windows[pos_beh] = window;
    }
}
int UI::FindWindowDisplayIndex(uiWindow* window) {
    uiContext& g = *GImGui;
    return g.Windows.index_from_ptr(g.Windows.find(window));
}
// Moving window to front of display and set focus (which happens to be back of our sorted list)
void UI::FocusWindow(uiWindow* window, uiFocusRequestFlags flags) {
    uiContext& g = *GImGui;
    // Modal check?
    if ((flags & uiFocusRequestFlags_UnlessBelowModal) && (g.NavWindow != window)) // Early out in common case.
        if (uiWindow* blocking_modal = FindBlockingModal(window)) {
            // This block would typically be reached in two situations:
            // - API call to FocusWindow() with a window under a modal and uiFocusRequestFlags_UnlessBelowModal flag.
            // - User clicking on void or anything behind a modal while a modal is open (window == NULL)
            IMGUI_DEBUG_LOG_FOCUS("[focus] FocusWindow(\"%s\", UnlessBelowModal): prevented by \"%s\".\n", window ? window->Name : "<NULL>", blocking_modal->Name);
            if (window && window == window->RootWindow && (window->Flags & uiWindowFlags_NoBringToFrontOnFocus) == 0)
                BringWindowToDisplayBehind(window, blocking_modal); // Still bring right under modal. (FIXME: Could move in focus list too?)
            ClosePopupsOverWindow(GetTopMostPopupModal(), false); // Note how we need to use GetTopMostPopupModal() aad NOT blocking_modal, to handle nested modals
            return;
        }
    // Find last focused child (if any) and focus it instead.
    if ((flags & uiFocusRequestFlags_RestoreFocusedChild) && window != NULL)
        window = NavRestoreLastChildNavWindow(window);
    // Apply focus
    if (g.NavWindow != window) {
        SetNavWindow(window);
        if (window && g.NavHighlightItemUnderNav) g.NavMousePosDirty = true;
        g.NavId = window ? window->NavLastIds[0] : 0; // Restore NavId
        g.NavLayer = uiNavLayer_Main;
        SetNavFocusScope(window ? window->NavRootFocusScopeId : 0);
        g.NavIdIsAlive = false;
        g.NavLastValidSelectionUserData = uiSelectionUserData_Invalid;
        // Close popups if any
        ClosePopupsOverWindow(window, false);
    }
    // Move the root window to the top of the pile
    IM_ASSERT(window == NULL || window->RootWindowDockTree != NULL);
    uiWindow* focus_front_window = window ? window->RootWindow : NULL;
    uiWindow* display_front_window = window ? window->RootWindowDockTree : NULL;
    uiDockNode* dock_node = window ? window->DockNode : NULL;
    bool active_id_window_is_dock_node_host = (g.ActiveIdWindow && dock_node && dock_node->HostWindow == g.ActiveIdWindow);
    // Steal active widgets. Some of the cases it triggers includes:
    // - Focus a window while an InputText in another window is active, if focus happens before the old InputText can run.
    // - When using Nav to activate menu items (due to timing of activating on press->new window appears->losing ActiveId)
    // - Using dock host items (tab, collapse button) can trigger this before we redirect the ActiveIdWindow toward the child window.
    if (g.ActiveId != 0 && g.ActiveIdWindow && g.ActiveIdWindow->RootWindow != focus_front_window)
        if (!g.ActiveIdNoClearOnFocusLoss && !active_id_window_is_dock_node_host)
            ClearActiveID();
    // Passing NULL allow to disable keyboard focus
    if (!window) return;
    window->LastFrameJustFocused = g.FrameCount;
    // Select in dock node
    // For #2304 we avoid applying focus immediately before the tabbar is visible.
    //if (dock_node && dock_node->TabBar)
    //    dock_node->TabBar->SelectedTabId = dock_node->TabBar->NextSelectedTabId = window->TabId;
    // Bring to front
    BringWindowToFocusFront(focus_front_window);
    if (((window->Flags | focus_front_window->Flags | display_front_window->Flags) & uiWindowFlags_NoBringToFrontOnFocus) == 0)
        BringWindowToDisplayFront(display_front_window);
}
void UI::FocusTopMostWindowUnderOne(uiWindow* under_this_window, uiWindow* ignore_window, uiViewport* filter_viewport, uiFocusRequestFlags flags) {
    uiContext& g = *GImGui;
    int start_idx = g.WindowsFocusOrder.Size - 1;
    if (under_this_window != NULL) {
        // Aim at root window behind us, if we are in a child window that's our own root (see #4640)
        int offset = -1;
        while (under_this_window->Flags & uiWindowFlags_ChildWindow) {
            under_this_window = under_this_window->ParentWindow;
            offset = 0;
        }
        start_idx = FindWindowFocusIndex(under_this_window) + offset;
    } for (int i = start_idx; i >= 0; i--) {
        // We may later decide to test for different NoXXXInputs based on the active navigation input (mouse vs nav) but that may feel more confusing to the user.
        uiWindow* window = g.WindowsFocusOrder[i];
        if (window == ignore_window || !window->WasActive) continue;
        if (filter_viewport != NULL && window->Viewport != filter_viewport) continue;
        if ((window->Flags & (uiWindowFlags_NoMouseInputs | uiWindowFlags_NoNavInputs)) != (uiWindowFlags_NoMouseInputs | uiWindowFlags_NoNavInputs)) {
            // FIXME-DOCK: When uiFocusRequestFlags_RestoreFocusedChild is set...
            // This is failing (lagging by one frame) for docked windows.
            // If A and B are docked into window and B disappear, at the NewFrame() call site window->NavLastChildNavWindow will still point to B.
            // We might leverage the tab order implicitly stored in window->DockNodeAsHost->TabBar (essentially the 'most_recently_selected_tab' code in tab bar will do that but on next update)
            // to tell which is the "previous" window. Or we may leverage 'LastFrameFocused/LastFrameJustFocused' and have this function handle child window itself?
            FocusWindow(window, flags);
            return;
        }
    }
    FocusWindow(NULL, flags);
}
//-----------------------------------------------------------------------------
// [SECTION] KEYBOARD/GAMEPAD NAVIGATION
//-----------------------------------------------------------------------------
// FIXME-NAV: The existence of SetNavID vs SetFocusID vs FocusWindow() needs to be clarified/reworked.
// In our terminology those should be interchangeable, yet right now this is super confusing.
// Those two functions are merely a legacy artifact, so at minimum naming should be clarified.
void UI::SetNavCursorVisible(bool visible) {
    uiContext& g = *GImGui;
    if (g.NavWindow && (g.NavWindow->Flags & uiWindowFlags_NoNavInputs)) visible = false;
    else if (g.IO.ConfigNavCursorVisibleAlways) visible = true;
    g.NavCursorVisible = visible;
}
// (was called NavRestoreHighlightAfterMove() before 1.91.4)
void UI::SetNavCursorVisibleAfterMove() {
    uiContext& g = *GImGui;
    if (g.NavWindow && (g.NavWindow->Flags & uiWindowFlags_NoNavInputs))
        g.NavCursorVisible = false;
    else if (g.NavInputSource == uiInputSource_Keyboard && (g.IO.ConfigFlags & uiConfigFlags_NavEnableKeyboard) == 0)
        g.NavCursorVisible = false;
    else if (g.NavInputSource == uiInputSource_Gamepad && (g.IO.ConfigFlags & uiConfigFlags_NavEnableGamepad) == 0)
        g.NavCursorVisible = false;
    else if (g.IO.ConfigNavCursorVisibleAuto)
        g.NavCursorVisible = true;
    g.NavHighlightItemUnderNav = g.NavMousePosDirty = true;
}
void UI::SetNavWindow(uiWindow* window) {
    uiContext& g = *GImGui;
    if (g.NavWindow != window) {
        IMGUI_DEBUG_LOG_FOCUS("[focus] SetNavWindow(\"%s\")\n", window ? window->Name : "<NULL>");
        g.NavWindow = window;
        g.NavLastValidSelectionUserData = uiSelectionUserData_Invalid;
    }
    g.NavInitRequest = g.NavMoveSubmitted = g.NavMoveScoringItems = false;
    NavUpdateAnyRequestFlag();
}
void UI::NavHighlightActivated(uiID id) {
    uiContext& g = *GImGui;
    g.NavHighlightActivatedId = id;
    g.NavHighlightActivatedTimer = NAV_ACTIVATE_HIGHLIGHT_TIMER;
}
void UI::NavClearPreferredPosForAxis(uiAxis axis) {
    uiContext& g = *GImGui;
    g.NavWindow->RootWindowForNav->NavPreferredScoringPosRel[g.NavLayer][axis] = FLT_MAX;
}
void UI::SetNavID(uiID id, uiNavLayer nav_layer, uiID focus_scope_id, const ImRect& rect_rel) {
    uiContext& g = *GImGui;
    IM_ASSERT(g.NavWindow != NULL);
    IM_ASSERT(nav_layer == uiNavLayer_Main || nav_layer == uiNavLayer_Menu);
    g.NavId = id;
    g.NavLayer = nav_layer;
    SetNavFocusScope(focus_scope_id);
    g.NavWindow->NavLastIds[nav_layer] = id;
    g.NavWindow->NavRectRel[nav_layer] = rect_rel;
    // Clear preferred scoring position (NavMoveRequestApplyResult() will tend to restore it)
    NavClearPreferredPosForAxis(uiAxis_X);
    NavClearPreferredPosForAxis(uiAxis_Y);
}
void UI::SetFocusID(uiID id, uiWindow* window) {
    uiContext& g = *GImGui;
    IM_ASSERT(id != 0);
    if (g.NavWindow != window) SetNavWindow(window);
    // Assume that SetFocusID() is called in the context where its window->DC.NavLayerCurrent and g.CurrentFocusScopeId are valid.
    // Note that window may be != g.CurrentWindow (e.g. SetFocusID call in InputTextEx for multi-line text)
    const uiNavLayer nav_layer = window->DC.NavLayerCurrent;
    g.NavId = id;
    g.NavLayer = nav_layer;
    SetNavFocusScope(g.CurrentFocusScopeId);
    window->NavLastIds[nav_layer] = id;
    if (g.LastItemData.ID == id)
        window->NavRectRel[nav_layer] = WindowRectAbsToRel(window, g.LastItemData.NavRect);
    g.NavIdItemFlags = (g.LastItemData.ID == id) ? g.LastItemData.ItemFlags : uiItemFlags_None;
    if (id == g.ActiveIdIsAlive) g.NavIdIsAlive = true;
    if (g.ActiveIdSource == uiInputSource_Keyboard || g.ActiveIdSource == uiInputSource_Gamepad)
        g.NavHighlightItemUnderNav = true;
    else if (g.IO.ConfigNavCursorVisibleAuto)
        g.NavCursorVisible = false;
    // Clear preferred scoring position (NavMoveRequestApplyResult() will tend to restore it)
    NavClearPreferredPosForAxis(uiAxis_X);
    NavClearPreferredPosForAxis(uiAxis_Y);
}
static Var::Dir ImGetDirQuadrantFromDelta(float dx, float dy) {
    if (ImFabs(dx) > ImFabs(dy)) return (dx > 0.0f) ? Var::Dir::Right : Var::Dir::Left;
    return (dy > 0.0f) ? Var::Dir::Down : Var::Dir::Up;
}
static float inline NavScoreItemDistInterval(float cand_min, float cand_max, float curr_min, float curr_max) {
    if (cand_max < curr_min) return cand_max - curr_min;
    if (curr_max < cand_min) return cand_min - curr_max;
    return 0.0f;
}
// Scoring function for keyboard/gamepad directional navigation. Based on https://gist.github.com/rygorous/6981057
static bool UI::NavScoreItem(uiNavItemData* result, const ImRect& nav_bb) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    if (g.NavLayer != window->DC.NavLayerCurrent) return false;
    // FIXME: Those are not good variables names
    ImRect cand = nav_bb;                   // Current item nav rectangle
    const ImRect curr = g.NavScoringRect;   // Current modified source rect (NB: we've applied Max.x = Min.x in NavUpdate() to inhibit the effect of having varied item width)
    g.NavScoringDebugCount++;
    // When entering through a NavFlattened border, we consider child window items as fully clipped for scoring
    if (window->ParentWindow == g.NavWindow) {
        IM_ASSERT((window->ChildFlags | g.NavWindow->ChildFlags) & uiChildFlags_NavFlattened);
        if (!window->ClipRect.Overlaps(cand)) return false;
        cand.ClipWithFull(window->ClipRect); // This allows the scored item to not overlap other candidates in the parent window
    }
    // Compute distance between boxes
    // FIXME-NAV: Introducing biases for vertical navigation, needs to be removed.
    float dbx = NavScoreItemDistInterval(cand.Min.x, cand.Max.x, curr.Min.x, curr.Max.x);
    float dby = NavScoreItemDistInterval(ImLerp(cand.Min.y, cand.Max.y, 0.2f), ImLerp(cand.Min.y, cand.Max.y, 0.8f), ImLerp(curr.Min.y, curr.Max.y, 0.2f), ImLerp(curr.Min.y, curr.Max.y, 0.8f)); // Scale down on Y to keep using box-distance for vertically touching items
    if (dby != 0.0f && dbx != 0.0f) dbx = (dbx / 1000.0f) + ((dbx > 0.0f) ? +1.0f : -1.0f);
    float dist_box = ImFabs(dbx) + ImFabs(dby);
    // Compute distance between centers (this is off by a factor of 2, but we only compare center distances with each other so it doesn't matter)
    float dcx = (cand.Min.x + cand.Max.x) - (curr.Min.x + curr.Max.x);
    float dcy = (cand.Min.y + cand.Max.y) - (curr.Min.y + curr.Max.y);
    float dist_center = ImFabs(dcx) + ImFabs(dcy); // L1 metric (need this for our connectedness guarantee)
    // Determine which quadrant of 'curr' our candidate item 'cand' lies in based on distance
    Var::Dir quadrant;
    float dax = 0.0f, day = 0.0f, dist_axial = 0.0f;
    if (dbx != 0.0f || dby != 0.0f) {
        // For non-overlapping boxes, use distance between boxes
        // FIXME-NAV: Quadrant may be incorrect because of (1) dbx bias and (2) curr.Max.y bias applied by NavBiasScoringRect() where typically curr.Max.y==curr.Min.y
        // One typical case where this happens, with style.WindowMenuButtonPosition == Var::Dir::Right, pressing Left to navigate from Close to Collapse tends to fail.
        // Also see #6344. Calling ImGetDirQuadrantFromDelta() with unbiased values may be good but side-effects are plenty.
        dax = dbx;
        day = dby;
        dist_axial = dist_box;
        quadrant = ImGetDirQuadrantFromDelta(dbx, dby);
    } else if (dcx != 0.0f || dcy != 0.0f) {
        // For overlapping boxes with different centers, use distance between centers
        dax = dcx;
        day = dcy;
        dist_axial = dist_center;
        quadrant = ImGetDirQuadrantFromDelta(dcx, dcy);
    } else {
        // Degenerate case: two overlapping buttons with same center, break ties arbitrarily (note that LastItemId here is really the _previous_ item order, but it doesn't matter)
        quadrant = (g.LastItemData.ID < g.NavId) ? Var::Dir::Left : Var::Dir::Right;
    }
    const Var::Dir move_dir = g.NavMoveDir;
#if IMGUI_DEBUG_NAV_SCORING
    char buf[200];
    // Hold Ctrl to preview score in matching quadrant. Ctrl+Arrow to rotate.
    if (g.IO.KeyCtrl) {
        if (quadrant == move_dir) {
            ImFormatString(buf, IM_COUNTOF(buf), "%.0f/%.0f", dist_box, dist_center);
            ImDrawList* draw_list = GetForegroundDrawList(window);
            draw_list->AddRectFilled(cand.Min, cand.Max, IM_COL32(255, 0, 0, 80));
            draw_list->AddRectFilled(cand.Min, cand.Min + CalcTextSize(buf), IM_COL32(255, 0, 0, 200));
            draw_list->AddText(cand.Min, IM_COL32(255, 255, 255, 255), buf);
        }
    }
    const bool debug_hovering = IsMouseHoveringRect(cand.Min, cand.Max);
    const bool debug_tty = (g.IO.KeyCtrl && IsKeyPressed(uiKey_Space));
    if (debug_hovering || debug_tty) {
        ImFormatString(buf, IM_COUNTOF(buf),
            "d-box    (%7.3f,%7.3f) -> %7.3f\nd-center (%7.3f,%7.3f) -> %7.3f\nd-axial  (%7.3f,%7.3f) -> %7.3f\nnav %c, quadrant %c",
            dbx, dby, dist_box, dcx, dcy, dist_center, dax, day, dist_axial, "-WENS"[move_dir+1], "-WENS"[quadrant+1]);
        if (debug_hovering) {
            ImDrawList* draw_list = GetForegroundDrawList(window);
            draw_list->AddRect(curr.Min, curr.Max, IM_COL32(255, 200, 0, 100));
            draw_list->AddRect(cand.Min, cand.Max, IM_COL32(255, 255, 0, 200));
            draw_list->AddRectFilled(cand.Max - vec2(4, 4), cand.Max + CalcTextSize(buf) + vec2(4, 4), IM_COL32(40, 0, 0, 200));
            draw_list->AddText(cand.Max, ~0U, buf);
        }
        if (debug_tty) { IMGUI_DEBUG_LOG_NAV("id 0x%08X\n%s\n", g.LastItemData.ID, buf); }
    }
#endif
    // Is it in the quadrant we're interested in moving to?
    bool new_best = false;
    if (quadrant == move_dir) {
        // Does it beat the current best candidate?
        if (dist_box < result->DistBox) {
            result->DistBox = dist_box;
            result->DistCenter = dist_center;
            return true;
        }
        if (dist_box == result->DistBox) {
            // Try using distance between center points to break ties
            if (dist_center < result->DistCenter) {
                result->DistCenter = dist_center;
                new_best = true;
            } else if (dist_center == result->DistCenter) {
                // Still tied! we need to be extra-careful to make sure everything gets linked properly. We consistently break ties by symbolically moving "later" items
                // (with higher index) to the right/downwards by an infinitesimal amount since we the current "best" button already (so it must have a lower index),
                // this is fairly easy. This rule ensures that all buttons with dx==dy==0 will end up being linked in order of appearance along the x axis.
                if (((move_dir == Var::Dir::Up || move_dir == Var::Dir::Down) ? dby : dbx) < 0.0f) // moving bj to the right/down decreases distance
                    new_best = true;
            }
        }
    }
    // Axial check: if 'curr' has no link at all in some direction and 'cand' lies roughly in that direction, add a tentative link. This will only be kept if no "real" matches
    // are found, so it only augments the graph produced by the above method using extra links. (important, since it doesn't guarantee strong connectedness)
    // This is just to avoid buttons having no links in a particular direction when there's a suitable neighbor. you get good graphs without this too.
    // 2017/09/29: FIXME: This now currently only enabled inside menu bars, ideally we'd disable it everywhere. Menus in particular need to catch failure. For general navigation it feels awkward.
    // Disabling it may lead to disconnected graphs when nodes are very spaced out on different axis. Perhaps consider offering this as an option?
    if (result->DistBox == FLT_MAX && dist_axial < result->DistAxial)  // Check axial match
        if (g.NavLayer == uiNavLayer_Menu && !(g.NavWindow->Flags & uiWindowFlags_ChildMenu))
            if ((move_dir == Var::Dir::Left && dax < 0.0f) || (move_dir == Var::Dir::Right && dax > 0.0f) || (move_dir == Var::Dir::Up && day < 0.0f) || (move_dir == Var::Dir::Down && day > 0.0f)) {
                result->DistAxial = dist_axial;
                new_best = true;
            }
    return new_best;
}
static void UI::NavApplyItemToResult(uiNavItemData* result) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    result->Window = window;
    result->ID = g.LastItemData.ID;
    result->FocusScopeId = g.CurrentFocusScopeId;
    result->ItemFlags = g.LastItemData.ItemFlags;
    result->RectRel = WindowRectAbsToRel(window, g.LastItemData.NavRect);
    if (result->ItemFlags & uiItemFlags_HasSelectionUserData) {
        IM_ASSERT(g.NextItemData.SelectionUserData != uiSelectionUserData_Invalid);
        result->SelectionUserData = g.NextItemData.SelectionUserData; // INTENTIONAL: At this point this field is not cleared in NextItemData. Avoid unnecessary copy to LastItemData.
    }
}
// True when current work location may be scrolled horizontally when moving left / right.
// This is generally always true UNLESS within a column. We don't have a vertical equivalent.
void UI::NavUpdateCurrentWindowIsScrollPushableX() {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    window->DC.NavIsScrollPushableX = (g.CurrentTable == NULL && window->DC.CurrentColumns == NULL);
}
// We get there when either NavId == id, or when g.NavAnyRequest is set (which is updated by NavUpdateAnyRequestFlag above)
// This is called after LastItemData is set, but NextItemData is also still valid.
static void UI::NavProcessItem() {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    const uiID id = g.LastItemData.ID;
    const uiItemFlags item_flags = g.LastItemData.ItemFlags;
    // When inside a container that isn't scrollable with Left<>Right, clip NavRect accordingly (#2221, #8816, #7994)
    ImRect nav_bb = g.LastItemData.NavRect;
    if (window->DC.NavIsScrollPushableX == false) {
        nav_bb.Min.x = ImClamp(nav_bb.Min.x, window->ClipRect.Min.x, window->ClipRect.Max.x);
        nav_bb.Max.x = ImClamp(nav_bb.Max.x, window->ClipRect.Min.x, window->ClipRect.Max.x);
    }
    // Process Init Request
    if (g.NavInitRequest && g.NavLayer == window->DC.NavLayerCurrent && (item_flags & uiItemFlags_Disabled) == 0) {
        // Even if 'uiItemFlags_NoNavDefaultFocus' is on (typically collapse/close button) we record the first ResultId so they can be used as a fallback
        const bool candidate_for_nav_default_focus = (item_flags & uiItemFlags_NoNavDefaultFocus) == 0;
        if (candidate_for_nav_default_focus || g.NavInitResult.ID == 0) {
            NavApplyItemToResult(&g.NavInitResult);
        }
        if (candidate_for_nav_default_focus) {
            g.NavInitRequest = false; // Found a match, clear request
            NavUpdateAnyRequestFlag();
        }
    }
    // Process Move Request (scoring for navigation)
    // FIXME-NAV: Consider policy for double scoring (scoring from NavScoringRect + scoring from a rect wrapped according to current wrapping policy)
    if (g.NavMoveScoringItems && (item_flags & uiItemFlags_Disabled) == 0) {
        if ((g.NavMoveFlags & uiNavMoveFlags_FocusApi) || (window->Flags & uiWindowFlags_NoNavInputs) == 0) {
            const bool is_tabbing = (g.NavMoveFlags & uiNavMoveFlags_IsTabbing) != 0;
            if (is_tabbing) {
                NavProcessItemForTabbingRequest(id, item_flags, g.NavMoveFlags);
            } else if (g.NavId != id || (g.NavMoveFlags & uiNavMoveFlags_AllowCurrentNavId)) {
                uiNavItemData* result = (window == g.NavWindow) ? &g.NavMoveResultLocal : &g.NavMoveResultOther;
                if (NavScoreItem(result, nav_bb)) NavApplyItemToResult(result);
                // Features like PageUp/PageDown need to maintain a separate score for the visible set of items.
                const float VISIBLE_RATIO = 0.70f;
                if (g.NavMoveFlags & uiNavMoveFlags_AlsoScoreVisibleSet) {
                    const ImRect& r = window->InnerRect; // window->ClipRect
                    if (r.Overlaps(nav_bb))
                        if (ImClamp(nav_bb.Max.y, r.Min.y, r.Max.y) - ImClamp(nav_bb.Min.y, r.Min.y, r.Max.y) >= (nav_bb.Max.y - nav_bb.Min.y) * VISIBLE_RATIO)
                            if (NavScoreItem(&g.NavMoveResultLocalVisible, nav_bb))
                                NavApplyItemToResult(&g.NavMoveResultLocalVisible);
                }
            }
        }
    }
    // Update information for currently focused/navigated item
    if (g.NavId == id) {
        // Always refresh g.NavWindow, because some operations such as FocusItem() may not have a window.
        if (g.NavWindow != window) SetNavWindow(window);
        g.NavLayer = window->DC.NavLayerCurrent;
        SetNavFocusScope(g.CurrentFocusScopeId); // Will set g.NavFocusScopeId AND store g.NavFocusScopePath
        g.NavFocusScopeId = g.CurrentFocusScopeId;
        g.NavIdIsAlive = true;
        g.NavIdItemFlags = item_flags;
        if (g.LastItemData.ItemFlags & uiItemFlags_HasSelectionUserData) {
            IM_ASSERT(g.NextItemData.SelectionUserData != uiSelectionUserData_Invalid);
            g.NavLastValidSelectionUserData = g.NextItemData.SelectionUserData; // INTENTIONAL: At this point this field is not cleared in NextItemData. Avoid unnecessary copy to LastItemData.
        }
        window->NavRectRel[window->DC.NavLayerCurrent] = WindowRectAbsToRel(window, nav_bb); // Store item bounding box (relative to window position)
    }
}
// Handle "scoring" of an item for a tabbing/focusing request initiated by NavUpdateCreateTabbingRequest().
// Note that SetKeyboardFocusHere() API calls are considered tabbing requests!
// - Case 1: no nav/active id:    set result to first eligible item, stop storing.
// - Case 2: tab forward:         on ref id set counter, on counter elapse store result
// - Case 3: tab forward wrap:    set result to first eligible item (preemptively), on ref id set counter, on next frame if counter hasn't elapsed store result. // FIXME-TABBING: Could be done as a next-frame forwarded request
// - Case 4: tab backward:        store all results, on ref id pick prev, stop storing
// - Case 5: tab backward wrap:   store all results, on ref id if no result keep storing until last // FIXME-TABBING: Could be done as next-frame forwarded requested
void UI::NavProcessItemForTabbingRequest(uiID id, uiItemFlags item_flags, uiNavMoveFlags move_flags) {
    uiContext& g = *GImGui;
    if ((move_flags & uiNavMoveFlags_FocusApi) == 0) {
        if (g.NavLayer != g.CurrentWindow->DC.NavLayerCurrent) return;
        if (g.NavFocusScopeId != g.CurrentFocusScopeId) return;
    }
    // - Can always land on an item when using API call.
    // - Tabbing with _NavEnableKeyboard (space/enter/arrows): goes through every item.
    // - Tabbing without _NavEnableKeyboard: goes through inputable items only.
    bool can_stop;
    if (move_flags & uiNavMoveFlags_FocusApi)
        can_stop = true;
    else
        can_stop = (item_flags & uiItemFlags_NoTabStop) == 0 && ((g.IO.ConfigFlags & uiConfigFlags_NavEnableKeyboard) || (item_flags & uiItemFlags_Inputable));
    // Always store in NavMoveResultLocal (unlike directional request which uses NavMoveResultOther on sibling/flattened windows)
    uiNavItemData* result = &g.NavMoveResultLocal;
    if (g.NavTabbingDir == +1) {
        // Tab Forward or SetKeyboardFocusHere() with >= 0
        if (can_stop && g.NavTabbingResultFirst.ID == 0)
            NavApplyItemToResult(&g.NavTabbingResultFirst);
        if (can_stop && g.NavTabbingCounter > 0 && --g.NavTabbingCounter == 0)
            NavMoveRequestResolveWithLastItem(result);
        else if (g.NavId == id)
            g.NavTabbingCounter = 1;
    } else if (g.NavTabbingDir == -1) {
        // Tab Backward
        if (g.NavId == id) {
            if (result->ID) {
                g.NavMoveScoringItems = false;
                NavUpdateAnyRequestFlag();
            }
        } else if (can_stop) {
            // Keep applying until reaching NavId
            NavApplyItemToResult(result);
        }
    } else if (g.NavTabbingDir == 0) {
        if (can_stop && g.NavId == id) NavMoveRequestResolveWithLastItem(result);
        if (can_stop && g.NavTabbingResultFirst.ID == 0) NavApplyItemToResult(&g.NavTabbingResultFirst);
    }
}
bool UI::NavMoveRequestButNoResultYet() {
    uiContext& g = *GImGui;
    return g.NavMoveScoringItems && g.NavMoveResultLocal.ID == 0 && g.NavMoveResultOther.ID == 0;
}
// FIXME: ScoringRect is not set
void UI::NavMoveRequestSubmit(Var::Dir move_dir, Var::Dir clip_dir, uiNavMoveFlags move_flags, uiScrollFlags scroll_flags) {
    uiContext& g = *GImGui;
    IM_ASSERT(g.NavWindow != NULL);
    //IMGUI_DEBUG_LOG_NAV("[nav] NavMoveRequestSubmit: dir %c, window \"%s\"\n", "-WENS"[move_dir + 1], g.NavWindow->Name);
    if (move_flags & uiNavMoveFlags_IsTabbing) move_flags |= uiNavMoveFlags_AllowCurrentNavId;
    g.NavMoveSubmitted = g.NavMoveScoringItems = true;
    g.NavMoveDir = move_dir;
    g.NavMoveDirForDebug = move_dir;
    g.NavMoveClipDir = clip_dir;
    g.NavMoveFlags = move_flags;
    g.NavMoveScrollFlags = scroll_flags;
    g.NavMoveForwardToNextFrame = false;
    g.NavMoveKeyMods = (move_flags & uiNavMoveFlags_FocusApi) ? 0 : g.IO.KeyMods;
    g.NavMoveResultLocal.Clear();
    g.NavMoveResultLocalVisible.Clear();
    g.NavMoveResultOther.Clear();
    g.NavTabbingCounter = 0;
    g.NavTabbingResultFirst.Clear();
    NavUpdateAnyRequestFlag();
}
void UI::NavMoveRequestResolveWithLastItem(uiNavItemData* result) {
    uiContext& g = *GImGui;
    g.NavMoveScoringItems = false; // Ensure request doesn't need more processing
    NavApplyItemToResult(result);
    NavUpdateAnyRequestFlag();
}
// Called by TreePop() to implement uiTreeFlags_NavLeftJumpsToParent
void UI::NavMoveRequestResolveWithPastTreeNode(uiNavItemData* result, const uiTreeNodeStackData* tree_node_data) {
    uiContext& g = *GImGui;
    g.NavMoveScoringItems = false;
    g.LastItemData.ID = tree_node_data->ID;
    g.LastItemData.ItemFlags = tree_node_data->ItemFlags & ~uiItemFlags_HasSelectionUserData; // Losing SelectionUserData, recovered next-frame (cheaper).
    g.LastItemData.NavRect = tree_node_data->NavRect;
    NavApplyItemToResult(result); // Result this instead of implementing a NavApplyPastTreeNodeToResult()
    NavClearPreferredPosForAxis(uiAxis_Y);
    NavUpdateAnyRequestFlag();
}
void UI::NavMoveRequestCancel() {
    uiContext& g = *GImGui;
    g.NavMoveSubmitted = g.NavMoveScoringItems = false;
    NavUpdateAnyRequestFlag();
}
// Forward will reuse the move request again on the next frame (generally with modifications done to it)
void UI::NavMoveRequestForward(Var::Dir move_dir, Var::Dir clip_dir, uiNavMoveFlags move_flags, uiScrollFlags scroll_flags) {
    uiContext& g = *GImGui;
    IM_ASSERT(g.NavMoveForwardToNextFrame == false);
    NavMoveRequestCancel();
    g.NavMoveForwardToNextFrame = true;
    g.NavMoveDir = move_dir;
    g.NavMoveClipDir = clip_dir;
    g.NavMoveFlags = move_flags | uiNavMoveFlags_Forwarded;
    g.NavMoveScrollFlags = scroll_flags;
}
// Navigation wrap-around logic is delayed to the end of the frame because this operation is only valid after entire
// popup is assembled and in case of appended popups it is not clear which EndPopup() call is final.
void UI::NavMoveRequestTryWrapping(uiWindow* window, uiNavMoveFlags wrap_flags) {
    uiContext& g = *GImGui;
    IM_ASSERT((wrap_flags & uiNavMoveFlags_WrapMask_ ) != 0 && (wrap_flags & ~uiNavMoveFlags_WrapMask_) == 0); // Call with _WrapX, _WrapY, _LoopX, _LoopY
    // In theory we should test for NavMoveRequestButNoResultYet() but there's no point doing it:
    // as NavEndFrame() will do the same test. It will end up calling NavUpdateCreateWrappingRequest().
    if (g.NavWindow == window && g.NavMoveScoringItems && g.NavLayer == window->DC.NavLayerCurrent)
        g.NavMoveFlags = (g.NavMoveFlags & ~uiNavMoveFlags_WrapMask_) | wrap_flags;
}
// FIXME: This could be replaced by updating a frame number in each window when (window == NavWindow) and (NavLayer == 0).
// This way we could find the last focused window among our children. It would be much less confusing this way?
static void UI::NavSaveLastChildNavWindowIntoParent(uiWindow* nav_window) {
    uiWindow* parent = nav_window;
    while (parent && parent->RootWindow != parent && (parent->Flags & (uiWindowFlags_Popup | uiWindowFlags_ChildMenu)) == 0)
        parent = parent->ParentWindow;
    if (parent && parent != nav_window) parent->NavLastChildNavWindow = nav_window;
}
// Restore the last focused child.
// Call when we are expected to land on the Main Layer (0) after FocusWindow()
static uiWindow* UI::NavRestoreLastChildNavWindow(uiWindow* window) {
    if (window->NavLastChildNavWindow && window->NavLastChildNavWindow->WasActive)
        return window->NavLastChildNavWindow;
    if (window->DockNodeAsHost && window->DockNodeAsHost->TabBar)
        if (uiTabItem* tab = TabBarFindMostRecentlySelectedTabForActiveWindow(window->DockNodeAsHost->TabBar))
            return tab->Window;
    return window;
}
void UI::NavRestoreLayer(uiNavLayer layer) {
    uiContext& g = *GImGui;
    if (layer == uiNavLayer_Main) {
        uiWindow* prev_nav_window = g.NavWindow;
        g.NavWindow = NavRestoreLastChildNavWindow(g.NavWindow);    // FIXME-NAV: Should clear ongoing nav requests?
        g.NavLastValidSelectionUserData = uiSelectionUserData_Invalid;
        if (prev_nav_window)
            IMGUI_DEBUG_LOG_FOCUS("[focus] NavRestoreLayer: from \"%s\" to SetNavWindow(\"%s\")\n", prev_nav_window->Name, g.NavWindow->Name);
    }
    uiWindow* window = g.NavWindow;
    if (window->NavLastIds[layer] != 0) {
        SetNavID(window->NavLastIds[layer], layer, 0, window->NavRectRel[layer]);
    } else {
        g.NavLayer = layer;
        NavInitWindow(window, true);
    }
}
static inline void UI::NavUpdateAnyRequestFlag() {
    uiContext& g = *GImGui;
    g.NavAnyRequest = g.NavMoveScoringItems || g.NavInitRequest || (IMGUI_DEBUG_NAV_SCORING && g.NavWindow != NULL);
    if (g.NavAnyRequest) IM_ASSERT(g.NavWindow != NULL);
}
// This needs to be called before we submit any widget (aka in or before Begin)
void UI::NavInitWindow(uiWindow* window, bool force_reinit) {
    // FIXME: ChildWindow test here is wrong for docking
    uiContext& g = *GImGui;
    IM_ASSERT(window == g.NavWindow);
    if (window->Flags & uiWindowFlags_NoNavInputs) {
        g.NavId = 0;
        SetNavFocusScope(window->NavRootFocusScopeId);
        return;
    }
    bool init_for_nav = false;
    if (window == window->RootWindow || (window->Flags & uiWindowFlags_Popup) || (window->NavLastIds[0] == 0) || force_reinit)
        init_for_nav = true;
    IMGUI_DEBUG_LOG_NAV("[nav] NavInitRequest: from NavInitWindow(), init_for_nav=%d, window=\"%s\", layer=%d\n", init_for_nav, window->Name, g.NavLayer);
    if (init_for_nav) {
        SetNavID(0, g.NavLayer, window->NavRootFocusScopeId, ImRect());
        g.NavInitRequest = true;
        g.NavInitRequestFromMove = false;
        g.NavInitResult.ID = 0;
        NavUpdateAnyRequestFlag();
    } else {
        g.NavId = window->NavLastIds[0];
        SetNavFocusScope(window->NavRootFocusScopeId);
    }
}
// Positioning logic altered slightly for remote activation: for Popup we want to use item rect, for Tooltip we leave things alone. (#9138)
// When calling for uiWindowFlags_Popup we use LastItemData.
static uiInputSource UI::NavCalcPreferredRefPosSource(uiWindowFlags window_type) {
    uiContext& g = *GImGui;
    uiWindow* window = g.NavWindow;
    const bool activated_shortcut = g.ActiveId != 0 && g.ActiveIdFromShortcut && g.ActiveId == g.LastItemData.ID;
    if ((window_type & uiWindowFlags_Popup) && activated_shortcut) return uiInputSource_Keyboard;
    if (!g.NavCursorVisible || !g.NavHighlightItemUnderNav || !window) return uiInputSource_Mouse;
    else return uiInputSource_Keyboard; // or Nav in general
}
static vec2 UI::NavCalcPreferredRefPos(uiWindowFlags window_type) {
    uiContext& g = *GImGui;
    uiWindow* window = g.NavWindow;
    uiInputSource source = NavCalcPreferredRefPosSource(window_type);
    if (source == uiInputSource_Mouse) {
        // Mouse (we need a fallback in case the mouse becomes invalid after being used)
        // The +1.0f offset when stored by OpenPopupEx() allows reopening this or another popup (same or another mouse button) while not moving the mouse, it is pretty standard.
        // In theory we could move that +1.0f offset in OpenPopupEx()
        vec2 p = IsMousePosValid(&g.IO.MousePos) ? g.IO.MousePos : g.MouseLastValidPos;
        return vec2(p.x + 1.0f, p.y);
    } else {
        // When navigation is active and mouse is disabled, pick a position around the bottom left of the currently navigated item
        const bool activated_shortcut = g.ActiveId != 0 && g.ActiveIdFromShortcut && g.ActiveId == g.LastItemData.ID;
        ImRect ref_rect;
        if (activated_shortcut && (window_type & uiWindowFlags_Popup))
            ref_rect = g.LastItemData.NavRect;
        else if (window != NULL)
            ref_rect = WindowRectRelToAbs(window, window->NavRectRel[g.NavLayer]);
        // Take account of upcoming scrolling (maybe set mouse pos should be done in EndFrame?)
        if (window != NULL && window->LastFrameActive != g.FrameCount && (window->ScrollTarget.x != FLT_MAX || window->ScrollTarget.y != FLT_MAX)) {
            vec2 next_scroll = CalcSameLineScrollFromScrollTargetAndClamp(window);
            ref_rect.Translate(window->Scroll - next_scroll);
        }
        vec2 pos = vec2(ref_rect.Min.x + ImMin(g.Style.FramePadding.x * 4, ref_rect.GetWidth()), ref_rect.Max.y - ImMin(g.Style.FramePadding.y, ref_rect.GetHeight()));
        if (window != NULL)
            if (uiViewport* viewport = window->Viewport)
                pos = ImClamp(pos, viewport->Pos, viewport->Pos + viewport->Size);
        return ImTrunc(pos); // ImTrunc() is important because non-integer mouse position application in backend might be lossy and result in undesirable non-zero delta.
    }
}
float UI::GetNavTweakPressedAmount(uiAxis axis) {
    uiContext& g = *GImGui;
    float repeat_delay, repeat_rate;
    GetTypematicRepeatRate(uiInputFlags_RepeatRateNavTweak, &repeat_delay, &repeat_rate);
    uiKey key_less, key_more;
    if (g.NavInputSource == uiInputSource_Gamepad) {
        key_less = (axis == uiAxis_X) ? uiKey_GamepadDpadLeft : uiKey_GamepadDpadUp;
        key_more = (axis == uiAxis_X) ? uiKey_GamepadDpadRight : uiKey_GamepadDpadDown;
    } else {
        key_less = (axis == uiAxis_X) ? uiKey_LeftArrow : uiKey_UpArrow;
        key_more = (axis == uiAxis_X) ? uiKey_RightArrow : uiKey_DownArrow;
    }
    float amount = (float)GetKeyPressedAmount(key_more, repeat_delay, repeat_rate) - (float)GetKeyPressedAmount(key_less, repeat_delay, repeat_rate);
    if (amount != 0.0f && IsKeyDown(key_less) && IsKeyDown(key_more)) // Cancel when opposite directions are held, regardless of repeat phase
        amount = 0.0f;
    return amount;
}
static void UI::NavUpdate() {
    uiContext& g = *GImGui;
    uiIO& io = g.IO;
    io.WantSetMousePos = false;
    //if (g.NavScoringDebugCount > 0) IMGUI_DEBUG_LOG_NAV("[nav] NavScoringDebugCount %d for '%s' layer %d (Init:%d, Move:%d)\n", g.NavScoringDebugCount, g.NavWindow ? g.NavWindow->Name : "NULL", g.NavLayer, g.NavInitRequest || g.NavInitResultId != 0, g.NavMoveRequest);
    // Set input source based on which keys are last pressed (as some features differs when used with Gamepad vs Keyboard)
    // FIXME-NAV: Now that keys are separated maybe we can get rid of NavInputSource?
    const bool nav_gamepad_active = (io.ConfigFlags & uiConfigFlags_NavEnableGamepad) != 0 && (io.BackendFlags & uiBackendFlags_HasGamepad) != 0;
    const uiKey nav_gamepad_keys_to_change_source[] = { uiKey_GamepadFaceRight, uiKey_GamepadFaceLeft, uiKey_GamepadFaceUp, uiKey_GamepadFaceDown, uiKey_GamepadDpadRight, uiKey_GamepadDpadLeft, uiKey_GamepadDpadUp, uiKey_GamepadDpadDown };
    if (nav_gamepad_active && g.NavInputSource != uiInputSource_Gamepad)
        for (uiKey key : nav_gamepad_keys_to_change_source)
            if (IsKeyDown(key))
                g.NavInputSource = uiInputSource_Gamepad;
    const bool nav_keyboard_active = (io.ConfigFlags & uiConfigFlags_NavEnableKeyboard) != 0;
    const uiKey nav_keyboard_keys_to_change_source[] = { uiKey_Space, uiKey_Enter, uiKey_Escape, uiKey_RightArrow, uiKey_LeftArrow, uiKey_UpArrow, uiKey_DownArrow };
    if (nav_keyboard_active && g.NavInputSource != uiInputSource_Keyboard)
        for (uiKey key : nav_keyboard_keys_to_change_source)
            if (IsKeyDown(key))
                g.NavInputSource = uiInputSource_Keyboard;
    // Process navigation init request (select first/default focus)
    g.NavJustMovedToId = 0;
    g.NavJustMovedToFocusScopeId = g.NavJustMovedFromFocusScopeId = 0;
    if (g.NavInitResult.ID != 0) NavInitRequestApplyResult();
    g.NavInitRequest = false;
    g.NavInitRequestFromMove = false;
    g.NavInitResult.ID = 0;
    // Process navigation move request
    if (g.NavMoveSubmitted) NavMoveRequestApplyResult();
    g.NavTabbingCounter = 0;
    g.NavMoveSubmitted = g.NavMoveScoringItems = false;
    if (g.NavCursorHideFrames > 0)
        if (--g.NavCursorHideFrames == 0)
            g.NavCursorVisible = true;
    // Schedule mouse position update (will be done at the bottom of this function, after 1) processing all move requests and 2) updating scrolling)
    bool set_mouse_pos = false;
    if (g.NavMousePosDirty && g.NavIdIsAlive)
        if (g.NavCursorVisible && g.NavHighlightItemUnderNav && g.NavWindow)
            set_mouse_pos = true;
    g.NavMousePosDirty = false;
    IM_ASSERT(g.NavLayer == uiNavLayer_Main || g.NavLayer == uiNavLayer_Menu);
    // Store our return window (for returning from Menu Layer to Main Layer) and clear it as soon as we step back in our own Layer 0
    if (g.NavWindow)
        NavSaveLastChildNavWindowIntoParent(g.NavWindow);
    if (g.NavWindow && g.NavWindow->NavLastChildNavWindow != NULL && g.NavLayer == uiNavLayer_Main)
        g.NavWindow->NavLastChildNavWindow = NULL;
    // Update Ctrl+Tab and Windowing features (hold Square to move/resize/etc.)
    NavUpdateWindowing();
    // Set output flags for user application
    io.NavActive = (nav_keyboard_active || nav_gamepad_active) && g.NavWindow && !(g.NavWindow->Flags & uiWindowFlags_NoNavInputs);
    io.NavVisible = (io.NavActive && g.NavId != 0 && g.NavCursorVisible) || (g.NavWindowingTarget != NULL);
    // Process NavCancel input (to close a popup, get back to parent, clear focus)
    NavUpdateCancelRequest();
    NavUpdateContextMenuRequest();
    // Process manual activation request
    g.NavActivateId = g.NavActivateDownId = g.NavActivatePressedId = 0;
    g.NavActivateFlags = uiActivateFlags_None;
    if (g.NavId != 0 && g.NavCursorVisible && !g.NavWindowingTarget && g.NavWindow && !(g.NavWindow->Flags & uiWindowFlags_NoNavInputs)) {
        const bool activate_down = (nav_keyboard_active && IsKeyDown(uiKey_Space, uiKeyOwner_NoOwner)) || (nav_gamepad_active && IsKeyDown(uiKey_NavGamepadActivate, uiKeyOwner_NoOwner));
        const bool activate_pressed = activate_down && ((nav_keyboard_active && IsKeyPressed(uiKey_Space, 0, uiKeyOwner_NoOwner)) || (nav_gamepad_active && IsKeyPressed(uiKey_NavGamepadActivate, 0, uiKeyOwner_NoOwner)));
        const bool input_pressed_keyboard = nav_keyboard_active && (IsKeyPressed(uiKey_Enter, 0, uiKeyOwner_NoOwner) || IsKeyPressed(uiKey_KeypadEnter, 0, uiKeyOwner_NoOwner));
        bool input_pressed_gamepad = false;
        if (activate_down && nav_gamepad_active && IsKeyDown(uiKey_NavGamepadActivate, uiKeyOwner_NoOwner) && (g.NavIdItemFlags & uiItemFlags_Inputable)) // requires uiItemFlags_Inputable to avoid retriggering regular buttons.
            if (GetKeyData(uiKey_NavGamepadActivate)->DownDurationPrev < NAV_ACTIVATE_INPUT_WITH_GAMEPAD_DELAY && GetKeyData(uiKey_NavGamepadActivate)->DownDuration >= NAV_ACTIVATE_INPUT_WITH_GAMEPAD_DELAY)
                input_pressed_gamepad = true;
        if (g.ActiveId == 0 && activate_pressed) {
            g.NavActivateId = g.NavId;
            g.NavActivateFlags = uiActivateFlags_PreferTweak;
        }
        if ((g.ActiveId == 0 || g.ActiveId == g.NavId) && (input_pressed_keyboard || input_pressed_gamepad)) {
            g.NavActivateId = g.NavId;
            g.NavActivateFlags = uiActivateFlags_PreferInput;
        }
        if ((g.ActiveId == 0 || g.ActiveId == g.NavId) && (activate_down || input_pressed_keyboard || input_pressed_gamepad)) // FIXME-NAV: Unsure why input_pressed_xxx (migrated from input_down which was already dubious)
            g.NavActivateDownId = g.NavId;
        if ((g.ActiveId == 0 || g.ActiveId == g.NavId) && (activate_pressed || input_pressed_keyboard || input_pressed_gamepad)) {
            g.NavActivatePressedId = g.NavId;
            NavHighlightActivated(g.NavId);
        }
    }
    if (g.NavWindow && (g.NavWindow->Flags & uiWindowFlags_NoNavInputs))
        g.NavCursorVisible = false;
    else if (g.IO.ConfigNavCursorVisibleAlways && g.NavCursorHideFrames == 0)
        g.NavCursorVisible = true;
    if (g.NavActivateId != 0) IM_ASSERT(g.NavActivateDownId == g.NavActivateId);
    // Highlight
    if (g.NavHighlightActivatedTimer > 0.0f)
        g.NavHighlightActivatedTimer = ImMax(0.0f, g.NavHighlightActivatedTimer - io.DeltaTime);
    if (g.NavHighlightActivatedTimer == 0.0f)
        g.NavHighlightActivatedId = 0;
    // Process programmatic activation request
    // FIXME-NAV: Those should eventually be queued (unlike focus they don't cancel each others)
    if (g.NavNextActivateId != 0) {
        g.NavActivateId = g.NavActivateDownId = g.NavActivatePressedId = g.NavNextActivateId;
        g.NavActivateFlags = g.NavNextActivateFlags;
    }
    g.NavNextActivateId = 0;
    // Process move requests
    NavUpdateCreateMoveRequest();
    if (g.NavMoveDir == Var::Dir::None) NavUpdateCreateTabbingRequest();
    NavUpdateAnyRequestFlag();
    g.NavIdIsAlive = false;
    // Scrolling
    if (g.NavWindow && !(g.NavWindow->Flags & uiWindowFlags_NoNavInputs) && !g.NavWindowingTarget) {
        // *Fallback* manual-scroll with Nav directional keys when window has no navigable item
        uiWindow* window = g.NavWindow;
        const float scroll_speed = IM_ROUND(window->FontRefSize * 100 * io.DeltaTime); // We need round the scrolling speed because sub-pixel scroll isn't reliably supported.
        const Var::Dir move_dir = g.NavMoveDir;
        if (window->DC.NavLayersActiveMask == 0x00 && window->DC.NavWindowHasScrollY && move_dir != Var::Dir::None) {
            if (move_dir == Var::Dir::Left || move_dir == Var::Dir::Right)
                SetScrollX(window, ImTrunc(window->Scroll.x + ((move_dir == Var::Dir::Left) ? -1.0f : +1.0f) * scroll_speed));
            if (move_dir == Var::Dir::Up || move_dir == Var::Dir::Down)
                SetScrollY(window, ImTrunc(window->Scroll.y + ((move_dir == Var::Dir::Up) ? -1.0f : +1.0f) * scroll_speed));
        }
        // *Normal* Manual scroll with LStick
        // SameLine movement request will clamp the NavId reference rectangle to the visible area, so navigation will resume within those bounds.
        if (nav_gamepad_active) {
            const vec2 scroll_dir = GetKeyMagnitude2d(uiKey_GamepadLStickLeft, uiKey_GamepadLStickRight, uiKey_GamepadLStickUp, uiKey_GamepadLStickDown);
            const float tweak_factor = IsKeyDown(uiKey_NavGamepadTweakSlow) ? 1.0f / 10.0f : IsKeyDown(uiKey_NavGamepadTweakFast) ? 10.0f : 1.0f;
            if (scroll_dir.x != 0.0f && window->ScrollbarX)
                SetScrollX(window, ImTrunc(window->Scroll.x + scroll_dir.x * scroll_speed * tweak_factor));
            if (scroll_dir.y != 0.0f)
                SetScrollY(window, ImTrunc(window->Scroll.y + scroll_dir.y * scroll_speed * tweak_factor));
        }
    }
    // Always prioritize mouse highlight if navigation is disabled
    if (!nav_keyboard_active && !nav_gamepad_active) {
        g.NavCursorVisible = false;
        g.NavHighlightItemUnderNav = set_mouse_pos = false;
    }
    // Update mouse position if requested
    // (This will take into account the possibility that a Scroll was queued in the window to offset our absolute mouse position before scroll has been applied)
    if (set_mouse_pos && io.ConfigNavMoveSetMousePos && (io.BackendFlags & uiBackendFlags_HasSetMousePos))
        TeleportMousePos(NavCalcPreferredRefPos(uiWindowFlags_Popup));
    // [DEBUG]
    g.NavScoringDebugCount = 0;
#if IMGUI_DEBUG_NAV_RECTS
    if (uiWindow* debug_window = g.NavWindow) {
        ImDrawList* draw_list = GetForegroundDrawList(debug_window);
        int layer = g.NavLayer; /* for (int layer = 0; layer < 2; layer++)*/ { ImRect r = WindowRectRelToAbs(debug_window, debug_window->NavRectRel[layer]); draw_list->AddRect(r.Min, r.Max, IM_COL32(255, 200, 0, 255)); }
        //if (1) { ImU32 col = (!debug_window->Hidden) ? IM_COL32(255,0,255,255) : IM_COL32(255,0,0,255); vec2 p = NavCalcPreferredRefPos(); char buf[32]; ImFormatString(buf, 32, "%d", g.NavLayer); draw_list->AddCircleFilled(p, 3.0f, col); draw_list->AddText(NULL, 13.0f, p + vec2(8,-4), col, buf); }
    }
#endif
}
void UI::NavInitRequestApplyResult() {
    // In very rare cases g.NavWindow may be null (e.g. clearing focus after requesting an init request, which does happen when releasing Alt while clicking on void)
    uiContext& g = *GImGui;
    if (!g.NavWindow) return;
    uiNavItemData* result = &g.NavInitResult;
    if (g.NavId != result->ID) {
        g.NavJustMovedFromFocusScopeId = g.NavFocusScopeId;
        g.NavJustMovedToId = result->ID;
        g.NavJustMovedToFocusScopeId = result->FocusScopeId;
        g.NavJustMovedToKeyMods = 0;
        g.NavJustMovedToIsTabbing = false;
        g.NavJustMovedToHasSelectionData = (result->ItemFlags & uiItemFlags_HasSelectionUserData) != 0;
    }
    // Apply result from previous navigation init request (will typically select the first item, unless SetItemDefaultFocus() has been called)
    // FIXME-NAV: On _NavFlattened windows, g.NavWindow will only be updated during subsequent frame. Not a problem currently.
    IMGUI_DEBUG_LOG_NAV("[nav] NavInitRequest: ApplyResult: NavID 0x%08X in Layer %d Window \"%s\"\n", result->ID, g.NavLayer, g.NavWindow->Name);
    SetNavID(result->ID, g.NavLayer, result->FocusScopeId, result->RectRel);
    g.NavIdIsAlive = true; // Mark as alive from previous frame as we got a result
    if (result->SelectionUserData != uiSelectionUserData_Invalid)
        g.NavLastValidSelectionUserData = result->SelectionUserData;
    if (g.NavInitRequestFromMove)
        SetNavCursorVisibleAfterMove();
}
// Bias scoring rect ahead of scoring + update preferred pos (if missing) using source position
static void NavBiasScoringRect(ImRect& r, vec2& preferred_pos_rel, Var::Dir move_dir, uiNavMoveFlags move_flags) {
    // Bias initial rect
    uiContext& g = *GImGui;
    const vec2 rel_to_abs_offset = g.NavWindow->DC.CursorStartPos;
    // Initialize bias on departure if we don't have any. So mouse-click + arrow will record bias.
    // - We default to L/U bias, so moving down from a large source item into several columns will land on left-most column.
    // - But each successful move sets new bias on one axis, only cleared when using mouse.
    if ((move_flags & uiNavMoveFlags_Forwarded) == 0) {
        if (preferred_pos_rel.x == FLT_MAX)
            preferred_pos_rel.x = ImMin(r.Min.x + 1.0f, r.Max.x) - rel_to_abs_offset.x;
        if (preferred_pos_rel.y == FLT_MAX)
            preferred_pos_rel.y = r.GetCenter().y - rel_to_abs_offset.y;
    }
    // Apply general bias on the other axis
    if ((move_dir == Var::Dir::Up || move_dir == Var::Dir::Down) && preferred_pos_rel.x != FLT_MAX)
        r.Min.x = r.Max.x = preferred_pos_rel.x + rel_to_abs_offset.x;
    else if ((move_dir == Var::Dir::Left || move_dir == Var::Dir::Right) && preferred_pos_rel.y != FLT_MAX)
        r.Min.y = r.Max.y = preferred_pos_rel.y + rel_to_abs_offset.y;
}
void UI::NavUpdateCreateMoveRequest() {
    uiContext& g = *GImGui;
    uiIO& io = g.IO;
    uiWindow* window = g.NavWindow;
    const bool nav_gamepad_active = (io.ConfigFlags & uiConfigFlags_NavEnableGamepad) != 0 && (io.BackendFlags & uiBackendFlags_HasGamepad) != 0;
    const bool nav_keyboard_active = (io.ConfigFlags & uiConfigFlags_NavEnableKeyboard) != 0;
    if (g.NavMoveForwardToNextFrame && window != NULL) {
        // Forwarding previous request (which has been modified, e.g. wrap around menus rewrite the requests with a starting rectangle at the other side of the window)
        // (preserve most state, which were already set by the NavMoveRequestForward() function)
        IM_ASSERT(g.NavMoveDir != Var::Dir::None && g.NavMoveClipDir != Var::Dir::None);
        IM_ASSERT(g.NavMoveFlags & uiNavMoveFlags_Forwarded);
        IMGUI_DEBUG_LOG_NAV("[nav] NavMoveRequestForward %d\n", g.NavMoveDir);
    } else {
        // Initiate directional inputs request
        g.NavMoveDir = Var::Dir::None;
        g.NavMoveFlags = uiNavMoveFlags_None;
        g.NavMoveScrollFlags = uiScrollFlags_None;
        if (window && !g.NavWindowingTarget && !(window->Flags & uiWindowFlags_NoNavInputs)) {
            const uiInputFlags repeat_mode = uiInputFlags_Repeat | (uiInputFlags)uiInputFlags_RepeatRateNavMove;
            if (!IsActiveIdUsingNavDir(Var::Dir::Left)  && ((nav_gamepad_active && IsKeyPressed(uiKey_GamepadDpadLeft,  repeat_mode, uiKeyOwner_NoOwner)) || (nav_keyboard_active && IsKeyPressed(uiKey_LeftArrow,  repeat_mode, uiKeyOwner_NoOwner)))) { g.NavMoveDir = Var::Dir::Left; }
            if (!IsActiveIdUsingNavDir(Var::Dir::Right) && ((nav_gamepad_active && IsKeyPressed(uiKey_GamepadDpadRight, repeat_mode, uiKeyOwner_NoOwner)) || (nav_keyboard_active && IsKeyPressed(uiKey_RightArrow, repeat_mode, uiKeyOwner_NoOwner)))) { g.NavMoveDir = Var::Dir::Right; }
            if (!IsActiveIdUsingNavDir(Var::Dir::Up)    && ((nav_gamepad_active && IsKeyPressed(uiKey_GamepadDpadUp,    repeat_mode, uiKeyOwner_NoOwner)) || (nav_keyboard_active && IsKeyPressed(uiKey_UpArrow,    repeat_mode, uiKeyOwner_NoOwner)))) { g.NavMoveDir = Var::Dir::Up; }
            if (!IsActiveIdUsingNavDir(Var::Dir::Down)  && ((nav_gamepad_active && IsKeyPressed(uiKey_GamepadDpadDown,  repeat_mode, uiKeyOwner_NoOwner)) || (nav_keyboard_active && IsKeyPressed(uiKey_DownArrow,  repeat_mode, uiKeyOwner_NoOwner)))) { g.NavMoveDir = Var::Dir::Down; }
        }
        g.NavMoveClipDir = g.NavMoveDir;
        g.NavScoringNoClipRect = ImRect(+FLT_MAX, +FLT_MAX, -FLT_MAX, -FLT_MAX);
    }
    // Update PageUp/PageDown/Home/End scroll
    // FIXME-NAV: Consider enabling those keys even without the master uiConfigFlags_NavEnableKeyboard flag?
    float scoring_page_offset_y = 0.0f;
    if (window && g.NavMoveDir == Var::Dir::None && nav_keyboard_active)
        scoring_page_offset_y = NavUpdatePageUpPageDown();
    // [DEBUG] Always send a request when holding Ctrl. Hold Ctrl + Arrow change the direction.
#if IMGUI_DEBUG_NAV_SCORING
    //if (io.KeyCtrl && IsKeyPressed(uiKey_C))
    //    g.NavMoveDirForDebug = (Var::Dir)((g.NavMoveDirForDebug + 1) & 3);
    if (io.KeyCtrl) {
        if (g.NavMoveDir == Var::Dir::None) g.NavMoveDir = g.NavMoveDirForDebug;
        g.NavMoveClipDir = g.NavMoveDir;
        g.NavMoveFlags |= uiNavMoveFlags_DebugNoResult;
    }
#endif
    // Submit
    g.NavMoveForwardToNextFrame = false;
    if (g.NavMoveDir != Var::Dir::None)
        NavMoveRequestSubmit(g.NavMoveDir, g.NavMoveClipDir, g.NavMoveFlags, g.NavMoveScrollFlags);
    // Moving with no reference triggers an init request (will be used as a fallback if the direction fails to find a match)
    if (g.NavMoveSubmitted && g.NavId == 0) {
        IMGUI_DEBUG_LOG_NAV("[nav] NavInitRequest: from move, window \"%s\", layer=%d\n", window ? window->Name : "<NULL>", g.NavLayer);
        g.NavInitRequest = g.NavInitRequestFromMove = true;
        g.NavInitResult.ID = 0;
        // NO check for _NoNavInputs here as we assume MoveRequests cannot be created.
        if (g.IO.ConfigNavCursorVisibleAuto) g.NavCursorVisible = true;
    }
    // When using gamepad, we project the reference nav bounding box into window visible area.
    // This is to allow resuming navigation inside the visible area after doing a large amount of scrolling,
    // since with gamepad all movements are relative (can't focus a visible object like we can with the mouse).
    // && (g.NavMoveFlags & uiNavMoveFlags_Forwarded)) ?
    if (g.NavMoveSubmitted && g.NavInputSource == uiInputSource_Gamepad && g.NavLayer == uiNavLayer_Main && window != NULL) {
        bool clamp_x = (g.NavMoveFlags & (uiNavMoveFlags_LoopX | uiNavMoveFlags_WrapX)) == 0;
        bool clamp_y = (g.NavMoveFlags & (uiNavMoveFlags_LoopY | uiNavMoveFlags_WrapY)) == 0;
        ImRect inner_rect_rel = WindowRectAbsToRel(window, ImRect(window->InnerRect.Min - vec2(1, 1), window->InnerRect.Max + vec2(1, 1)));
        // Take account of changing scroll to handle triggering a new move request on a scrolling frame. (#6171)
        // Otherwise 'inner_rect_rel' would be off on the move result frame.
        inner_rect_rel.Translate(CalcSameLineScrollFromScrollTargetAndClamp(window) - window->Scroll);
        if ((clamp_x || clamp_y) && !inner_rect_rel.Contains(window->NavRectRel[g.NavLayer])) {
            IMGUI_DEBUG_LOG_NAV("[nav] NavMoveRequest: clamp NavRectRel for gamepad move\n");
            float pad_x = ImMin(inner_rect_rel.GetWidth(), window->FontRefSize * 0.5f);
            float pad_y = ImMin(inner_rect_rel.GetHeight(), window->FontRefSize * 0.5f); // Terrible approximation for the intent of starting navigation from first fully visible item
            inner_rect_rel.Min.x = clamp_x ? (inner_rect_rel.Min.x + pad_x) : -FLT_MAX;
            inner_rect_rel.Max.x = clamp_x ? (inner_rect_rel.Max.x - pad_x) : +FLT_MAX;
            inner_rect_rel.Min.y = clamp_y ? (inner_rect_rel.Min.y + pad_y) : -FLT_MAX;
            inner_rect_rel.Max.y = clamp_y ? (inner_rect_rel.Max.y - pad_y) : +FLT_MAX;
            window->NavRectRel[g.NavLayer].ClipWithFull(inner_rect_rel);
            g.NavId = 0;
        }
    }
    // Prepare scoring rectangle.
    // For scoring we use a single segment on the left side our current item bounding box (not touching the edge to avoid box overlap with zero-spaced items)
    ImRect scoring_rect;
    if (window != NULL) {
        ImRect nav_rect_rel = !window->NavRectRel[g.NavLayer].IsInverted() ? window->NavRectRel[g.NavLayer] : ImRect(0, 0, 0, 0);
        scoring_rect = WindowRectRelToAbs(window, nav_rect_rel);
        if (g.NavMoveFlags & uiNavMoveFlags_IsPageMove) {
            // When we start from a visible location, score visible items and prioritize this result.
            if (window->InnerRect.Contains(scoring_rect))
                g.NavMoveFlags |= uiNavMoveFlags_AlsoScoreVisibleSet;
            g.NavScoringNoClipRect = scoring_rect;
            scoring_rect.TranslateY(scoring_page_offset_y);
            g.NavScoringNoClipRect.Add(scoring_rect);
        }
        //GetForegroundDrawList()->AddRectFilled(scoring_rect.Min - vec2(1, 1), scoring_rect.Max + vec2(1, 1), IM_COL32(255, 100, 0, 80)); // [DEBUG] Pre-bias
        if (g.NavMoveSubmitted)
            NavBiasScoringRect(scoring_rect, window->RootWindowForNav->NavPreferredScoringPosRel[g.NavLayer], g.NavMoveDir, g.NavMoveFlags);
        IM_ASSERT(!scoring_rect.IsInverted()); // Ensure we have a non-inverted bounding box here will allow us to remove extraneous ImFabs() calls in NavScoreItem().
        //GetForegroundDrawList()->AddRectFilled(scoring_rect.Min - vec2(1, 1), scoring_rect.Max + vec2(1, 1), IM_COL32(255, 100, 0, 80)); // [DEBUG] Post-bias
        //if (!g.NavScoringNoClipRect.IsInverted()) { GetForegroundDrawList()->AddRectFilled(g.NavScoringNoClipRect.Min, g.NavScoringNoClipRect.Max, IM_COL32(100, 255, 0, 80)); } // [DEBUG]
    }
    g.NavScoringRect = scoring_rect;
    //g.NavScoringNoClipRect.Add(scoring_rect);
}
void UI::NavUpdateCreateTabbingRequest() {
    uiContext& g = *GImGui;
    uiWindow* window = g.NavWindow;
    IM_ASSERT(g.NavMoveDir == Var::Dir::None);
    if (window == NULL || g.NavWindowingTarget != NULL || (window->Flags & uiWindowFlags_NoNavInputs) || !g.ConfigNavEnableTabbing)
        return;
    const bool tab_pressed = IsKeyPressed(uiKey_Tab, uiInputFlags_Repeat, uiKeyOwner_NoOwner) && !g.IO.KeyCtrl && !g.IO.KeyAlt;
    if (!tab_pressed) return;
    // Initiate tabbing request
    // (this is ALWAYS ENABLED, regardless of uiConfigFlags_NavEnableKeyboard flag!)
    // See NavProcessItemForTabbingRequest() for a description of the various forward/backward tabbing cases with and without wrapping.
    const bool nav_keyboard_active = (g.IO.ConfigFlags & uiConfigFlags_NavEnableKeyboard) != 0;
    if (nav_keyboard_active)
        g.NavTabbingDir = g.IO.KeyShift ? -1 : (g.NavCursorVisible == false && g.ActiveId == 0) ? 0 : +1;
    else
        g.NavTabbingDir = g.IO.KeyShift ? -1 : (g.ActiveId == 0) ? 0 : +1;
    uiNavMoveFlags move_flags = uiNavMoveFlags_IsTabbing | uiNavMoveFlags_Activate;
    uiScrollFlags scroll_flags = window->Appearing ? uiScrollFlags_KeepVisibleEdgeX | uiScrollFlags_AlwaysCenterY : uiScrollFlags_KeepVisibleEdgeX | uiScrollFlags_KeepVisibleEdgeY;
    Var::Dir clip_dir = (g.NavTabbingDir < 0) ? Var::Dir::Up : Var::Dir::Down;
    NavMoveRequestSubmit(Var::Dir::None, clip_dir, move_flags, scroll_flags); // FIXME-NAV: Once we refactor tabbing, add LegacyApi flag to not activate non-inputable.
    g.NavTabbingCounter = -1;
}
// Apply result from previous frame navigation directional move request. Always called from NavUpdate()
void UI::NavMoveRequestApplyResult() {
    uiContext& g = *GImGui;
#if IMGUI_DEBUG_NAV_SCORING
    // [DEBUG] Scoring all items in NavWindow at all times
    if (g.NavMoveFlags & uiNavMoveFlags_DebugNoResult) return;
#endif
    // Select which result to use
    uiNavItemData* result = (g.NavMoveResultLocal.ID != 0) ? &g.NavMoveResultLocal : (g.NavMoveResultOther.ID != 0) ? &g.NavMoveResultOther : NULL;
    // Tabbing forward wrap
    if ((g.NavMoveFlags & uiNavMoveFlags_IsTabbing) && result == NULL)
        if ((g.NavTabbingCounter == 1 || g.NavTabbingDir == 0) && g.NavTabbingResultFirst.ID)
            result = &g.NavTabbingResultFirst;
    // In a situation when there are no results but NavId != 0, re-enable the Navigation highlight (because g.NavId is not considered as a possible result)
    const uiAxis axis = (g.NavMoveDir == Var::Dir::Up || g.NavMoveDir == Var::Dir::Down) ? uiAxis_Y : uiAxis_X;
    if (result == NULL) {
        if (g.NavMoveFlags & uiNavMoveFlags_IsTabbing)
            g.NavMoveFlags |= uiNavMoveFlags_NoSetNavCursorVisible;
        if (g.NavId != 0 && (g.NavMoveFlags & uiNavMoveFlags_NoSetNavCursorVisible) == 0)
            SetNavCursorVisibleAfterMove();
        NavClearPreferredPosForAxis(axis); // On a failed move, clear preferred pos for this axis.
        IMGUI_DEBUG_LOG_NAV("[nav] NavMoveSubmitted but not led to a result!\n");
        return;
    }
    // PageUp/PageDown behavior first jumps to the bottom/top mostly visible item, _otherwise_ use the result from the previous/next page.
    if (g.NavMoveFlags & uiNavMoveFlags_AlsoScoreVisibleSet)
        if (g.NavMoveResultLocalVisible.ID != 0 && g.NavMoveResultLocalVisible.ID != g.NavId)
            result = &g.NavMoveResultLocalVisible;
    // Maybe entering a flattened child from the outside? In this case solve the tie using the regular scoring rules.
    if (result != &g.NavMoveResultOther && g.NavMoveResultOther.ID != 0 && g.NavMoveResultOther.Window->ParentWindow == g.NavWindow)
        if ((g.NavMoveResultOther.DistBox < result->DistBox) || (g.NavMoveResultOther.DistBox == result->DistBox && g.NavMoveResultOther.DistCenter < result->DistCenter))
            result = &g.NavMoveResultOther;
    IM_ASSERT(g.NavWindow && result->Window);
    // Scroll to keep newly navigated item fully into view.
    if (g.NavLayer == uiNavLayer_Main) {
        ImRect rect_abs = WindowRectRelToAbs(result->Window, result->RectRel);
        ScrollToRectEx(result->Window, rect_abs, g.NavMoveScrollFlags);
        if (g.NavMoveFlags & uiNavMoveFlags_ScrollToEdgeY) {
            // FIXME: Should remove this? Or make more precise: use ScrollToRectEx() with edge?
            float scroll_target = (g.NavMoveDir == Var::Dir::Up) ? result->Window->ScrollMax.y : 0.0f;
            SetScrollY(result->Window, scroll_target);
        }
    }
    if (g.NavWindow != result->Window) {
        IMGUI_DEBUG_LOG_FOCUS("[focus] NavMoveRequest: SetNavWindow(\"%s\")\n", result->Window->Name);
        g.NavWindow = result->Window;
        g.NavLastValidSelectionUserData = uiSelectionUserData_Invalid;
    }
    // Clear active id unless requested not to
    // FIXME: uiNavMoveFlags_NoClearActiveId is currently unused as we don't have a clear strategy to preserve active id after interaction,
    // so this is mostly provided as a gateway for further experiments (see #1418, #2890)
    if (g.ActiveId != result->ID && (g.NavMoveFlags & uiNavMoveFlags_NoClearActiveId) == 0)
        ClearActiveID();
    // Don't set NavJustMovedToId if just landed on the same spot (which may happen with uiNavMoveFlags_AllowCurrentNavId)
    // PageUp/PageDown however sets always set NavJustMovedTo (vs Home/End which doesn't) mimicking Windows behavior.
    if ((g.NavId != result->ID || (g.NavMoveFlags & uiNavMoveFlags_IsPageMove)) && (g.NavMoveFlags & uiNavMoveFlags_NoSelect) == 0) {
        g.NavJustMovedFromFocusScopeId = g.NavFocusScopeId;
        g.NavJustMovedToId = result->ID;
        g.NavJustMovedToFocusScopeId = result->FocusScopeId;
        g.NavJustMovedToKeyMods = g.NavMoveKeyMods;
        g.NavJustMovedToIsTabbing = (g.NavMoveFlags & uiNavMoveFlags_IsTabbing) != 0;
        g.NavJustMovedToHasSelectionData = (result->ItemFlags & uiItemFlags_HasSelectionUserData) != 0;
        //IMGUI_DEBUG_LOG_NAV("[nav] NavJustMovedFromFocusScopeId = 0x%08X, NavJustMovedToFocusScopeId = 0x%08X\n", g.NavJustMovedFromFocusScopeId, g.NavJustMovedToFocusScopeId);
    }
    // Apply new NavID/Focus
    IMGUI_DEBUG_LOG_NAV("[nav] NavMoveRequest: result NavID 0x%08X in Layer %d Window \"%s\"\n", result->ID, g.NavLayer, g.NavWindow->Name);
    vec2 preferred_scoring_pos_rel = g.NavWindow->RootWindowForNav->NavPreferredScoringPosRel[g.NavLayer];
    SetNavID(result->ID, g.NavLayer, result->FocusScopeId, result->RectRel);
    if (result->SelectionUserData != uiSelectionUserData_Invalid)
        g.NavLastValidSelectionUserData = result->SelectionUserData;
    // Restore last preferred position for current axis
    // (storing in RootWindowForNav-> as the info is desirable at the beginning of a Move Request. In theory all storage should use RootWindowForNav..)
    if ((g.NavMoveFlags & uiNavMoveFlags_IsTabbing) == 0) {
        preferred_scoring_pos_rel[axis] = result->RectRel.GetCenter()[axis];
        g.NavWindow->RootWindowForNav->NavPreferredScoringPosRel[g.NavLayer] = preferred_scoring_pos_rel;
    }
    // Tabbing: Activates Inputable, otherwise only Focus
    if ((g.NavMoveFlags & uiNavMoveFlags_IsTabbing) && (result->ItemFlags & uiItemFlags_Inputable) == 0)
        g.NavMoveFlags &= ~uiNavMoveFlags_Activate;
    // Activate
    if (g.NavMoveFlags & uiNavMoveFlags_Activate) {
        g.NavNextActivateId = result->ID;
        g.NavNextActivateFlags = uiActivateFlags_None;
        if (g.NavMoveFlags & uiNavMoveFlags_FocusApi)
            g.NavNextActivateFlags |= uiActivateFlags_FromFocusApi;
        if (g.NavMoveFlags & uiNavMoveFlags_IsTabbing)
            g.NavNextActivateFlags |= uiActivateFlags_PreferInput | uiActivateFlags_TryToPreserveState | uiActivateFlags_FromTabbing;
    }
    // Make nav cursor visible
    if ((g.NavMoveFlags & uiNavMoveFlags_NoSetNavCursorVisible) == 0)
        SetNavCursorVisibleAfterMove();
}
// Process Escape/NavCancel input (to close a popup, get back to parent, clear focus)
// FIXME: In order to support e.g. Escape to clear a selection we'll need:
// - either to store the equivalent of ActiveIdUsingKeyInputMask for a FocusScope and test for it.
// - either to move most/all of those tests to the epilogue/end functions of the scope they are dealing with (e.g. exit child window in EndChild()) or in EndFrame(), to allow an earlier intercept
static void UI::NavUpdateCancelRequest() {
    uiContext& g = *GImGui;
    const bool nav_gamepad_active = (g.IO.ConfigFlags & uiConfigFlags_NavEnableGamepad) != 0 && (g.IO.BackendFlags & uiBackendFlags_HasGamepad) != 0;
    const bool nav_keyboard_active = (g.IO.ConfigFlags & uiConfigFlags_NavEnableKeyboard) != 0;
    if (!(nav_keyboard_active && IsKeyPressed(uiKey_Escape, 0, uiKeyOwner_NoOwner)) && !(nav_gamepad_active && IsKeyPressed(uiKey_NavGamepadCancel, 0, uiKeyOwner_NoOwner)))
        return;
    IMGUI_DEBUG_LOG_NAV("[nav] NavUpdateCancelRequest()\n");
    if (g.ActiveId != 0) {
        ClearActiveID();
    } else if (g.NavLayer != uiNavLayer_Main) {
        // Leave the "menu" layer
        NavRestoreLayer(uiNavLayer_Main);
        SetNavCursorVisibleAfterMove();
    } else if (g.NavWindow && g.NavWindow != g.NavWindow->RootWindow && !(g.NavWindow->RootWindowForNav->Flags & uiWindowFlags_Popup) && g.NavWindow->RootWindowForNav->ParentWindow) {
        // Exit child window
        uiWindow* child_window = g.NavWindow->RootWindowForNav;
        uiWindow* parent_window = child_window->ParentWindow;
        IM_ASSERT(child_window->ChildId != 0);
        FocusWindow(parent_window);
        SetNavID(child_window->ChildId, uiNavLayer_Main, 0, WindowRectAbsToRel(parent_window, child_window->Rect()));
        SetNavCursorVisibleAfterMove();
    } else if (g.OpenPopupStack.Size > 0 && g.OpenPopupStack.back().Window != NULL && !(g.OpenPopupStack.back().Window->Flags & uiWindowFlags_Modal)) {
        // Close open popup/menu
        ClosePopupToLevel(g.OpenPopupStack.Size - 1, true);
    } else {
        // Clear NavLastId for popups but keep it for regular child window so we can leave one and come back where we were
        // FIXME-NAV: This should happen on window appearing.
        if (g.IO.ConfigNavEscapeClearFocusItem || g.IO.ConfigNavEscapeClearFocusWindow)
            if (g.NavWindow && ((g.NavWindow->Flags & uiWindowFlags_Popup)))// || !(g.NavWindow->Flags & uiWindowFlags_ChildWindow)))
                g.NavWindow->NavLastIds[0] = 0;
        // Clear nav focus
        if (g.IO.ConfigNavEscapeClearFocusItem || g.IO.ConfigNavEscapeClearFocusWindow) g.NavId = 0;
        if (g.IO.ConfigNavEscapeClearFocusWindow) FocusWindow(NULL);
    }
}
static void UI::NavUpdateContextMenuRequest() {
    uiContext& g = *GImGui;
    g.NavOpenContextMenuItemId = g.NavOpenContextMenuWindowId = 0;
    const bool nav_keyboard_active = (g.IO.ConfigFlags & uiConfigFlags_NavEnableKeyboard) != 0;
    const bool nav_gamepad_active = (g.IO.ConfigFlags & uiConfigFlags_NavEnableKeyboard) != 0;
    if ((!nav_keyboard_active && !nav_gamepad_active) || g.NavWindow == NULL) return;
    bool request = false;
    request |= nav_keyboard_active && (IsKeyReleased(uiKey_Menu, uiKeyOwner_NoOwner) || (IsKeyPressed(uiKey_F10, uiInputFlags_None, uiKeyOwner_NoOwner) && g.IO.KeyMods == uiMod_Shift));
    request |= nav_gamepad_active && IsKeyPressed(uiKey_NavGamepadContextMenu, uiInputFlags_None, uiKeyOwner_NoOwner);
    if (!request) return;
    g.NavOpenContextMenuItemId = g.NavId;
    g.NavOpenContextMenuWindowId = g.NavWindow->ID;
    // Allow triggering for Begin()..BeginPopupContextItem(). A possible alternative would be to use g.NavLayer == uiNavLayer_Menu.
    if (g.NavId == g.NavWindow->GetID("#CLOSE") || g.NavId == g.NavWindow->GetID("#COLLAPSE"))
        g.NavOpenContextMenuItemId = g.NavWindow->MoveId;
    g.NavInputSource = uiInputSource_Keyboard;
    SetNavCursorVisibleAfterMove();
}
// Handle PageUp/PageDown/Home/End keys
// Called from NavUpdateCreateMoveRequest() which will use our output to create a move request
// FIXME-NAV: This doesn't work properly with NavFlattened siblings as we use NavWindow rectangle for reference
// FIXME-NAV: how to get Home/End to aim at the beginning/end of a 2D grid?
static float UI::NavUpdatePageUpPageDown() {
    uiContext& g = *GImGui;
    uiWindow* window = g.NavWindow;
    if ((window->Flags & uiWindowFlags_NoNavInputs) || g.NavWindowingTarget != NULL) return 0.0f;
    const bool page_up_held = IsKeyDown(uiKey_PageUp, uiKeyOwner_NoOwner);
    const bool page_down_held = IsKeyDown(uiKey_PageDown, uiKeyOwner_NoOwner);
    const bool home_pressed = IsKeyPressed(uiKey_Home, uiInputFlags_Repeat, uiKeyOwner_NoOwner);
    const bool end_pressed = IsKeyPressed(uiKey_End, uiInputFlags_Repeat, uiKeyOwner_NoOwner);
    // Proceed if either (not both) are pressed, otherwise early out
    if (page_up_held == page_down_held && home_pressed == end_pressed) return 0.0f;
    if (g.NavLayer != uiNavLayer_Main) NavRestoreLayer(uiNavLayer_Main);
    if ((window->DC.NavLayersActiveMask & (1 << uiNavLayer_Main)) == 0 && window->DC.NavWindowHasScrollY) {
        // Fallback manual-scroll when window has no navigable item
        if (IsKeyPressed(uiKey_PageUp, uiInputFlags_Repeat, uiKeyOwner_NoOwner))
            SetScrollY(window, window->Scroll.y - window->InnerRect.GetHeight());
        else if (IsKeyPressed(uiKey_PageDown, uiInputFlags_Repeat, uiKeyOwner_NoOwner))
            SetScrollY(window, window->Scroll.y + window->InnerRect.GetHeight());
        else if (home_pressed)
            SetScrollY(window, 0.0f);
        else if (end_pressed)
            SetScrollY(window, window->ScrollMax.y);
    } else {
        ImRect& nav_rect_rel = window->NavRectRel[g.NavLayer];
        const float page_offset_y = ImMax(0.0f, window->InnerRect.GetHeight() - window->FontRefSize * 1.0f + nav_rect_rel.GetHeight());
        float nav_scoring_rect_offset_y = 0.0f;
        if (IsKeyPressed(uiKey_PageUp, true)) {
            nav_scoring_rect_offset_y = -page_offset_y;
            g.NavMoveDir = Var::Dir::Down; // Because our scoring rect is offset up, we request the down direction (so we can always land on the last item)
            g.NavMoveClipDir = Var::Dir::Up;
            g.NavMoveFlags = uiNavMoveFlags_AllowCurrentNavId | uiNavMoveFlags_IsPageMove; // uiNavMoveFlags_AlsoScoreVisibleSet may be added later
        } else if (IsKeyPressed(uiKey_PageDown, true)) {
            nav_scoring_rect_offset_y = +page_offset_y;
            g.NavMoveDir = Var::Dir::Up; // Because our scoring rect is offset down, we request the up direction (so we can always land on the last item)
            g.NavMoveClipDir = Var::Dir::Down;
            g.NavMoveFlags = uiNavMoveFlags_AllowCurrentNavId | uiNavMoveFlags_IsPageMove; // uiNavMoveFlags_AlsoScoreVisibleSet may be added later
        } else if (home_pressed) {
            // FIXME-NAV: handling of Home/End is assuming that the top/bottom most item will be visible with Scroll.y == 0/ScrollMax.y
            // Scrolling will be handled via the uiNavMoveFlags_ScrollToEdgeY flag, we don't scroll immediately to avoid scrolling happening before nav result.
            // Preserve current horizontal position if we have any.
            nav_rect_rel.Min.y = nav_rect_rel.Max.y = 0.0f;
            if (nav_rect_rel.IsInverted()) nav_rect_rel.Min.x = nav_rect_rel.Max.x = 0.0f;
            g.NavMoveDir = Var::Dir::Down;
            g.NavMoveFlags = uiNavMoveFlags_AllowCurrentNavId | uiNavMoveFlags_ScrollToEdgeY;
            // FIXME-NAV: MoveClipDir left to _None, intentional?
        } else if (end_pressed) {
            nav_rect_rel.Min.y = nav_rect_rel.Max.y = window->ContentSize.y;
            if (nav_rect_rel.IsInverted()) nav_rect_rel.Min.x = nav_rect_rel.Max.x = 0.0f;
            g.NavMoveDir = Var::Dir::Up;
            g.NavMoveFlags = uiNavMoveFlags_AllowCurrentNavId | uiNavMoveFlags_ScrollToEdgeY;
            // FIXME-NAV: MoveClipDir left to _None, intentional?
        }
        return nav_scoring_rect_offset_y;
    }
    return 0.0f;
}
static void UI::NavEndFrame() {
    uiContext& g = *GImGui;
    // Show Ctrl+Tab list window
    if (g.NavWindowingTarget != NULL) NavUpdateWindowingOverlay();
    // Perform wrap-around in menus
    // FIXME-NAV: Wrap may need to apply a weight bias on the other axis. e.g. 4x4 grid with 2 last items missing on last item won't handle LoopY/WrapY correctly.
    // FIXME-NAV: Wrap (not Loop) support could be handled by the scoring function and then WrapX would function without an extra frame.
    if (g.NavWindow && NavMoveRequestButNoResultYet() && (g.NavMoveFlags & uiNavMoveFlags_WrapMask_) && (g.NavMoveFlags & uiNavMoveFlags_Forwarded) == 0)
        NavUpdateCreateWrappingRequest();
}
static void UI::NavUpdateCreateWrappingRequest() {
    uiContext& g = *GImGui;
    uiWindow* window = g.NavWindow;
    bool do_forward = false;
    ImRect bb_rel = window->NavRectRel[g.NavLayer];
    Var::Dir clip_dir = g.NavMoveDir;
    const uiNavMoveFlags move_flags = g.NavMoveFlags;
    //const uiAxis move_axis = (g.NavMoveDir == Var::Dir::Up || g.NavMoveDir == Var::Dir::Down) ? uiAxis_Y : uiAxis_X;
    // Menu layer does not maintain scrolling / content size (#9178)
    vec2 wrap_size = (g.NavLayer == uiNavLayer_Menu) ? window->Size : window->ContentSize + window->WindowPadding;
    if (g.NavMoveDir == Var::Dir::Left && (move_flags & (uiNavMoveFlags_WrapX | uiNavMoveFlags_LoopX))) {
        bb_rel.Min.x = bb_rel.Max.x = wrap_size.x;
        if (move_flags & uiNavMoveFlags_WrapX) {
            bb_rel.TranslateY(-bb_rel.GetHeight()); // Previous row
            clip_dir = Var::Dir::Up;
        }
        do_forward = true;
    }
    if (g.NavMoveDir == Var::Dir::Right && (move_flags & (uiNavMoveFlags_WrapX | uiNavMoveFlags_LoopX))) {
        bb_rel.Min.x = bb_rel.Max.x = -window->WindowPadding.x;
        if (move_flags & uiNavMoveFlags_WrapX) {
            bb_rel.TranslateY(+bb_rel.GetHeight()); // SameLine row
            clip_dir = Var::Dir::Down;
        }
        do_forward = true;
    }
    if (g.NavMoveDir == Var::Dir::Up && (move_flags & (uiNavMoveFlags_WrapY | uiNavMoveFlags_LoopY))) {
        bb_rel.Min.y = bb_rel.Max.y = wrap_size.y;
        if (move_flags & uiNavMoveFlags_WrapY) {
            bb_rel.TranslateX(-bb_rel.GetWidth()); // Previous column
            clip_dir = Var::Dir::Left;
        }
        do_forward = true;
    }
    if (g.NavMoveDir == Var::Dir::Down && (move_flags & (uiNavMoveFlags_WrapY | uiNavMoveFlags_LoopY))) {
        bb_rel.Min.y = bb_rel.Max.y = -window->WindowPadding.y;
        if (move_flags & uiNavMoveFlags_WrapY) {
            bb_rel.TranslateX(+bb_rel.GetWidth()); // SameLine column
            clip_dir = Var::Dir::Right;
        }
        do_forward = true;
    }
    if (!do_forward) return;
    window->NavRectRel[g.NavLayer] = bb_rel;
    NavClearPreferredPosForAxis(uiAxis_X);
    NavClearPreferredPosForAxis(uiAxis_Y);
    NavMoveRequestForward(g.NavMoveDir, clip_dir, move_flags, g.NavMoveScrollFlags);
}
// Can we focus this window with Ctrl+Tab (or PadMenu + PadFocusPrev/PadFocusSameLine)
// Note that NoNavFocus makes the window not reachable with Ctrl+Tab but it can still be focused with mouse or programmatically.
// If you want a window to never be focused, you may use the e.g. NoInputs flag.
bool UI::IsWindowNavFocusable(uiWindow* window) { return window->WasActive && window == window->RootWindow && !(window->Flags & uiWindowFlags_NoNavFocus); }
// FIXME-OPT O(N)
static uiWindow* FindWindowNavFocusable(int i_start, int i_stop, int dir) {
    uiContext& g = *GImGui;
    for (int i = i_start; i >= 0 && i < g.WindowsFocusOrder.Size && i != i_stop; i += dir)
        if (UI::IsWindowNavFocusable(g.WindowsFocusOrder[i]))
            return g.WindowsFocusOrder[i];
    return NULL;
}
static void NavUpdateWindowingTarget(int focus_change_dir) {
    uiContext& g = *GImGui;
    IM_ASSERT(g.NavWindowingTarget);
    if (g.NavWindowingTarget->Flags & uiWindowFlags_Modal) return;
    const int i_current = UI::FindWindowFocusIndex(g.NavWindowingTarget);
    uiWindow* window_target = FindWindowNavFocusable(i_current + focus_change_dir, -INT_MAX, focus_change_dir);
    if (!window_target)
        window_target = FindWindowNavFocusable((focus_change_dir < 0) ? (g.WindowsFocusOrder.Size - 1) : 0, i_current, focus_change_dir);
    // Don't reset windowing target if there's a single window in the list
    if (window_target) {
        g.NavWindowingTarget = g.NavWindowingTargetAnim = window_target;
        g.NavWindowingAccumDeltaPos = g.NavWindowingAccumDeltaSize = vec2(0.0f, 0.0f);
    }
    g.NavWindowingToggleLayer = false;
}
// Apply focus and close overlay
static void UI::NavUpdateWindowingApplyFocus(uiWindow* apply_focus_window) {
    // FIXME: Many actions here could be part of a higher-level/reused function. Why aren't they in FocusWindow() ?
    // Investigate for each of them: ClearActiveID(), NavRestoreHighlightAfterMove(), NavRestoreLastChildNavWindow(), ClosePopupsOverWindow(), NavInitWindow()
    uiContext& g = *GImGui;
    if (g.NavWindow == NULL || apply_focus_window != g.NavWindow->RootWindow) {
        uiViewport* previous_viewport = g.NavWindow ? g.NavWindow->Viewport : NULL;
        ClearActiveID();
        SetNavCursorVisibleAfterMove();
        ClosePopupsOverWindow(apply_focus_window, false);
        FocusWindow(apply_focus_window, uiFocusRequestFlags_RestoreFocusedChild);
        IM_ASSERT(g.NavWindow != NULL);
        apply_focus_window = g.NavWindow;
        // FIXME: This is the equivalent of the 'if (g.NavId == 0) { NavInitWindow() }' in DockNodeUpdateTabBar().
        if (apply_focus_window->NavLastIds[0] == 0) NavInitWindow(apply_focus_window, false);
        // If the window has ONLY a menu layer (no main layer), select it directly
        // Use NavLayersActiveMaskNext since windows didn't have a chance to be Begin()-ed on this frame,
        // so Ctrl+Tab where the keys are only held for 1 frame will be able to use correct layers mask since
        // the target window as already been previewed once.
        // FIXME-NAV: This should be done in NavInit.. or in FocusWindow... However in both of those cases,
        // we won't have a guarantee that windows has been visible before and therefore NavLayersActiveMask*
        // won't be valid.
        if (apply_focus_window->DC.NavLayersActiveMaskNext == (1 << uiNavLayer_Menu))
            g.NavLayer = uiNavLayer_Menu;
        // Request OS level focus
        if (apply_focus_window->Viewport != previous_viewport && g.PlatformIO.Platform_SetWindowFocus)
            g.PlatformIO.Platform_SetWindowFocus(apply_focus_window->Viewport);
    }
    g.NavWindowingTarget = NULL;
}
// Windowing management mode
// Keyboard: Ctrl+Tab (change focus/move/resize), Alt (toggle menu layer)
// Gamepad:  Hold Menu/Square (change focus/move/resize), Tap Menu/Square (toggle menu layer)
static void UI::NavUpdateWindowing() {
    uiContext& g = *GImGui;
    uiIO& io = g.IO;
    uiWindow* apply_focus_window = NULL;
    bool apply_toggle_layer = false;
    uiWindow* modal_window = GetTopMostPopupModal();
    bool allow_windowing = (modal_window == NULL); // FIXME: This prevent Ctrl+Tab from being usable with windows that are inside the Begin-stack of that modal.
    if (!allow_windowing) g.NavWindowingTarget = NULL;
    // Fade out
    if (g.NavWindowingTargetAnim && g.NavWindowingTarget == NULL) {
        g.NavWindowingHighlightAlpha = ImMax(g.NavWindowingHighlightAlpha - io.DeltaTime * 10.0f, 0.0f);
        if (g.DimBgRatio <= 0.0f && g.NavWindowingHighlightAlpha <= 0.0f)
            g.NavWindowingTargetAnim = NULL;
    }
    // Start Ctrl+Tab or Square+L/R window selection
    // (g.ConfigNavWindowingKeyNext/g.ConfigNavWindowingKeyPrev defaults are uiMod_Ctrl|uiKey_Tab and uiMod_Ctrl|uiMod_Shift|uiKey_Tab)
    const uiID owner_id = ImHashStr("##NavUpdateWindowing");
    const bool nav_gamepad_active = (io.ConfigFlags & uiConfigFlags_NavEnableGamepad) != 0 && (io.BackendFlags & uiBackendFlags_HasGamepad) != 0;
    const bool nav_keyboard_active = (io.ConfigFlags & uiConfigFlags_NavEnableKeyboard) != 0;
    const bool keyboard_next_window = allow_windowing && g.ConfigNavWindowingKeyNext && Shortcut(g.ConfigNavWindowingKeyNext, uiInputFlags_Repeat | uiInputFlags_RouteAlways, owner_id);
    const bool keyboard_prev_window = allow_windowing && g.ConfigNavWindowingKeyPrev && Shortcut(g.ConfigNavWindowingKeyPrev, uiInputFlags_Repeat | uiInputFlags_RouteAlways, owner_id);
    const bool start_toggling_with_gamepad = nav_gamepad_active && !g.NavWindowingTarget && Shortcut(uiKey_NavGamepadMenu, uiInputFlags_RouteAlways, owner_id);
    const bool start_windowing_with_gamepad = allow_windowing && start_toggling_with_gamepad;
    const bool start_windowing_with_keyboard = allow_windowing && !g.NavWindowingTarget && (keyboard_next_window || keyboard_prev_window); // Note: enabled even without NavEnableKeyboard!
    bool just_started_windowing_from_null_focus = false;
    if (start_toggling_with_gamepad) {
        g.NavWindowingToggleLayer = true; // Gamepad starts toggling layer
        g.NavWindowingToggleKey = uiKey_NavGamepadMenu;
        g.NavWindowingInputSource = g.NavInputSource = uiInputSource_Gamepad;
    }
    if (start_windowing_with_gamepad || start_windowing_with_keyboard)
        if (uiWindow* window = (g.NavWindow && IsWindowNavFocusable(g.NavWindow)) ? g.NavWindow : FindWindowNavFocusable(g.WindowsFocusOrder.Size - 1, -INT_MAX, -1)) {
            if (start_windowing_with_keyboard || g.ConfigNavWindowingWithGamepad)
                g.NavWindowingTarget = g.NavWindowingTargetAnim = window->RootWindow; // Current location
            g.NavWindowingTimer = g.NavWindowingHighlightAlpha = 0.0f;
            g.NavWindowingAccumDeltaPos = g.NavWindowingAccumDeltaSize = vec2(0.0f, 0.0f);
            g.NavWindowingInputSource = g.NavInputSource = start_windowing_with_keyboard ? uiInputSource_Keyboard : uiInputSource_Gamepad;
            if (g.NavWindow == NULL) just_started_windowing_from_null_focus = true;
            // Manually register ownership of our mods. Using a global route in the Shortcut() calls instead would probably be correct but may have more side-effects.
            if (keyboard_next_window || keyboard_prev_window)
                SetKeyOwnersForKeyChord((g.ConfigNavWindowingKeyNext | g.ConfigNavWindowingKeyPrev) & uiMod_Mask_, owner_id);
        }
    // Gamepad update
    if ((g.NavWindowingTarget || g.NavWindowingToggleLayer) && g.NavWindowingInputSource == uiInputSource_Gamepad) {
        if (g.NavWindowingTarget != NULL) {
            // Highlight only appears after a brief time holding the button, so that a fast tap on uiKey_NavGamepadMenu (to toggle NavLayer) doesn't add visual noise
            // However inputs are accepted immediately, so you press uiKey_NavGamepadMenu + L1/R1 fast.
            g.NavWindowingTimer += io.DeltaTime;
            g.NavWindowingHighlightAlpha = ImMax(g.NavWindowingHighlightAlpha, ImSaturate((g.NavWindowingTimer - NAV_WINDOWING_HIGHLIGHT_DELAY) / 0.05f));
            // Select window to focus
            const int focus_change_dir = (int)IsKeyPressed(uiKey_GamepadL1) - (int)IsKeyPressed(uiKey_GamepadR1);
            if (focus_change_dir != 0 && !just_started_windowing_from_null_focus) {
                NavUpdateWindowingTarget(focus_change_dir);
                g.NavWindowingHighlightAlpha = 1.0f;
            }
        }
        // Single press toggles NavLayer, long press with L/R apply actual focus on release (until then the window was merely rendered top-most)
        if (!IsKeyDown(uiKey_NavGamepadMenu)) {
            g.NavWindowingToggleLayer &= (g.NavWindowingHighlightAlpha < 1.0f); // Once button was held long enough we don't consider it a tap-to-toggle-layer press anymore.
            if (g.NavWindowingToggleLayer && g.NavWindow) apply_toggle_layer = true;
            else if (!g.NavWindowingToggleLayer) apply_focus_window = g.NavWindowingTarget;
            g.NavWindowingTarget = NULL;
            g.NavWindowingToggleLayer = false;
        }
    }
    // Keyboard: Focus
    if (g.NavWindowingTarget && g.NavWindowingInputSource == uiInputSource_Keyboard) {
        // Visuals only appears after a brief time after pressing TAB the first time, so that a fast Ctrl+Tab doesn't add visual noise
        uiKeyChord shared_mods = ((g.ConfigNavWindowingKeyNext ? g.ConfigNavWindowingKeyNext : uiMod_Mask_) & (g.ConfigNavWindowingKeyPrev ? g.ConfigNavWindowingKeyPrev : uiMod_Mask_)) & uiMod_Mask_;
        IM_ASSERT(shared_mods != 0); // SameLine/Prev shortcut currently needs a shared modifier to "hold", otherwise Prev actions would keep cycling between two windows.
        g.NavWindowingTimer += io.DeltaTime;
        g.NavWindowingHighlightAlpha = ImMax(g.NavWindowingHighlightAlpha, ImSaturate((g.NavWindowingTimer - NAV_WINDOWING_HIGHLIGHT_DELAY) / 0.05f)); // 1.0f
        if ((keyboard_next_window || keyboard_prev_window) && !just_started_windowing_from_null_focus)
            NavUpdateWindowingTarget(keyboard_next_window ? -1 : +1);
        else if ((io.KeyMods & shared_mods) != shared_mods) apply_focus_window = g.NavWindowingTarget;
    }
    // Keyboard: Press and Release Alt to toggle menu layer
    const uiKey windowing_toggle_keys[] = { uiKey_LeftAlt, uiKey_RightAlt };
    bool windowing_toggle_layer_start = false;
    if (g.NavWindow != NULL && !(g.NavWindow->Flags & uiWindowFlags_NoNavInputs))
        for (uiKey windowing_toggle_key : windowing_toggle_keys)
            if (nav_keyboard_active && IsKeyPressed(windowing_toggle_key, 0, uiKeyOwner_NoOwner)) {
                windowing_toggle_layer_start = true;
                g.NavWindowingToggleLayer = true;
                g.NavWindowingToggleKey = windowing_toggle_key;
                g.NavWindowingInputSource = g.NavInputSource = uiInputSource_Keyboard;
                break;
            }
    if (g.NavWindowingToggleLayer && g.NavWindowingInputSource == uiInputSource_Keyboard) {
        // We cancel toggling nav layer when any text has been typed (generally while holding Alt). (See #370)
        // We cancel toggling nav layer when other modifiers are pressed. (See #4439)
        // - AltGR is Alt+Ctrl on some layout but we can't reliably detect it (not all backends/systems/layout emit it as Alt+Ctrl).
        // We cancel toggling nav layer if an owner has claimed the key.
        if (io.InputQueueCharacters.Size > 0 || io.KeyCtrl || io.KeyShift || io.KeySuper)
            g.NavWindowingToggleLayer = false;
        else if (windowing_toggle_layer_start == false && g.LastKeyboardKeyPressTime == g.Time)
            g.NavWindowingToggleLayer = false;
        else if (TestKeyOwner(g.NavWindowingToggleKey, uiKeyOwner_NoOwner) == false || TestKeyOwner(uiMod_Alt, uiKeyOwner_NoOwner) == false)
            g.NavWindowingToggleLayer = false;
        // Apply layer toggle on Alt release
        // Important: as before version <18314 we lacked an explicit IO event for focus gain/loss, we also compare mouse validity to detect old backends clearing mouse pos on focus loss.
        if (IsKeyReleased(g.NavWindowingToggleKey) && g.NavWindowingToggleLayer)
            if (g.ActiveId == 0 || g.ActiveIdAllowOverlap)
                if (IsMousePosValid(&io.MousePos) == IsMousePosValid(&io.MousePosPrev))
                    apply_toggle_layer = true;
        if (!IsKeyDown(g.NavWindowingToggleKey)) g.NavWindowingToggleLayer = false;
    }
    // Move window
    if (g.NavWindowingTarget && !(g.NavWindowingTarget->Flags & uiWindowFlags_NoMove)) {
        vec2 nav_move_dir;
        if (g.NavInputSource == uiInputSource_Keyboard && !io.KeyShift)
            nav_move_dir = GetKeyMagnitude2d(uiKey_LeftArrow, uiKey_RightArrow, uiKey_UpArrow, uiKey_DownArrow);
        if (g.NavInputSource == uiInputSource_Gamepad)
            nav_move_dir = GetKeyMagnitude2d(uiKey_GamepadLStickLeft, uiKey_GamepadLStickRight, uiKey_GamepadLStickUp, uiKey_GamepadLStickDown);
        if (nav_move_dir.x != 0.0f || nav_move_dir.y != 0.0f) {
            const float NAV_MOVE_SPEED = 800.0f;
            const float move_step = NAV_MOVE_SPEED * io.DeltaTime * GetScale();
            g.NavWindowingAccumDeltaPos += nav_move_dir * move_step;
            g.NavHighlightItemUnderNav = true;
            vec2 accum_floored = ImTrunc(g.NavWindowingAccumDeltaPos);
            if (accum_floored.x != 0.0f || accum_floored.y != 0.0f) {
                uiWindow* moving_window = g.NavWindowingTarget->RootWindowDockTree;
                SetWindowPos(moving_window, moving_window->Pos + accum_floored, uiCond_Always);
                g.NavWindowingAccumDeltaPos -= accum_floored;
            }
        }
    }
    // Apply final focus
    if (apply_focus_window) NavUpdateWindowingApplyFocus(apply_focus_window);
    // Apply menu/layer toggle
    if (apply_toggle_layer && g.NavWindow) {
        ClearActiveID();
        // Move to parent menu if necessary
        uiWindow* new_nav_window = g.NavWindow;
        while (new_nav_window->ParentWindow
            && (new_nav_window->DC.NavLayersActiveMask & (1 << uiNavLayer_Menu)) == 0
            && (new_nav_window->Flags & uiWindowFlags_ChildWindow) != 0
            && (new_nav_window->Flags & (uiWindowFlags_Popup | uiWindowFlags_ChildMenu)) == 0)
            new_nav_window = new_nav_window->ParentWindow;
        if (new_nav_window != g.NavWindow) {
            uiWindow* old_nav_window = g.NavWindow;
            FocusWindow(new_nav_window);
            new_nav_window->NavLastChildNavWindow = old_nav_window;
        }
        // Toggle layer
        const uiNavLayer new_nav_layer = (g.NavWindow->DC.NavLayersActiveMask & (1 << uiNavLayer_Menu)) ? (uiNavLayer)((int)g.NavLayer ^ 1) : uiNavLayer_Main;
        if (new_nav_layer != g.NavLayer) {
            // Reinitialize navigation when entering menu bar with the Alt key (FIXME: could be a properly of the layer?)
            const bool preserve_layer_1_nav_id = (new_nav_window->DockNodeAsHost != NULL);
            if (new_nav_layer == uiNavLayer_Menu && !preserve_layer_1_nav_id)
                g.NavWindow->NavLastIds[new_nav_layer] = 0;
            NavRestoreLayer(new_nav_layer);
            SetNavCursorVisibleAfterMove();
        }
    }
}
// Window has already passed the IsWindowNavFocusable()
static const char* GetFallbackWindowNameForWindowingList(uiWindow* window) {
    if (window->Flags & uiWindowFlags_Popup)
        return UI::LocalizeGetMsg(uiLocKey_WindowingPopup);
    if ((window->Flags & uiWindowFlags_MenuBar) && strcmp(window->Name, "##MainMenuBar") == 0)
        return UI::LocalizeGetMsg(uiLocKey_WindowingMainMenuBar);
    // Not normally shown to user.
    if (window->DockNodeAsHost) return "(Dock node)";
    return UI::LocalizeGetMsg(uiLocKey_WindowingUntitled);
}
// Overlay displayed when using Ctrl+Tab. Called by EndFrame().
void UI::NavUpdateWindowingOverlay() {
    uiContext& g = *GImGui;
    IM_ASSERT(g.NavWindowingTarget != NULL);
    if (g.NavWindowingTimer < NAV_WINDOWING_LIST_APPEAR_DELAY) return;
    const uiViewport* viewport = /*g.NavWindow ? g.NavWindow->Viewport :*/ GetMainViewport();
    SetNextWindowSizeConstraints(vec2(viewport->Size.x * 0.20f, viewport->Size.y * 0.20f), vec2(FLT_MAX, FLT_MAX));
    SetNextWindowPos(viewport->GetCenter(), uiCond_Always, vec2(0.5f, 0.5f));
    PushStyleVar(uiStyleVar_WindowPadding, g.Style.WindowPadding * 2.0f);
    Begin("##NavWindowingOverlay", NULL, uiWindowFlags_NoTitleBar | uiWindowFlags_NoFocusOnAppearing | uiWindowFlags_NoResize | uiWindowFlags_NoMove | uiWindowFlags_NoInputs | uiWindowFlags_AutoResize | uiWindowFlags_NoSavedSettings);
    g.NavWindowingListWindow = g.CurrentWindow;
    if (g.ContextName[0] != 0) BarrierText(g.ContextName);
    for (int n = g.WindowsFocusOrder.Size - 1; n >= 0; n--) {
        uiWindow* window = g.WindowsFocusOrder[n];
        IM_ASSERT(window != NULL); // Fix static analyzers
        if (!IsWindowNavFocusable(window)) continue;
        const char* label = window->Name;
        if (label == FindRenderedTextEnd(label))
            label = GetFallbackWindowNameForWindowingList(window);
        Selectable(label, g.NavWindowingTarget == window);
    }
    End();
    PopStyleVar();
}
//-----------------------------------------------------------------------------
// [SECTION] DRAG AND DROP
//-----------------------------------------------------------------------------
bool UI::IsDragDropActive() { uiContext& g = *GImGui; return g.DragDropActive; }
void UI::ClearDragDrop() {
    uiContext& g = *GImGui;
    if (g.DragDropActive) IMGUI_DEBUG_LOG_ACTIVEID("[dragdrop] ClearDragDrop()\n");
    g.DragDropActive = false;
    g.DragDropPayload.Clear();
    g.DragDropAcceptFlagsCurr = uiDragDropFlags_None;
    g.DragDropAcceptIdCurr = g.DragDropAcceptIdPrev = 0;
    g.DragDropAcceptIdCurrRectSurface = FLT_MAX;
    g.DragDropAcceptFrameCount = -1;
    g.DragDropPayloadBufHeap.clear();
    memset(&g.DragDropPayloadBufLocal, 0, sizeof(g.DragDropPayloadBufLocal));
}
bool UI::BeginTooltipHidden() {
    uiContext& g = *GImGui;
    bool ret = Begin("##Tooltip_Hidden", NULL, uiWindowFlags_Tooltip | uiWindowFlags_NoInputs | uiWindowFlags_NoTitleBar | uiWindowFlags_NoMove | uiWindowFlags_NoResize | uiWindowFlags_NoSavedSettings | uiWindowFlags_AutoResize);
    SetWindowHiddenAndSkipItemsForCurrentFrame(g.CurrentWindow);
    return ret;
}
// When this returns true you need to: a) call SetDragDropPayload() exactly once, b) you may render the payload visual/description, c) call EndDragDropSource()
// If the item has an identifier:
// - This assume/require the item to be activated (typically via ButtonBehavior).
// - Therefore if you want to use this with a mouse button other than left mouse button, it is up to the item itself to activate with another button.
// - We then pull and use the mouse button that was used to activate the item and use it to carry on the drag.
// If the item has no identifier:
// - Currently always assume left mouse button.
bool UI::BeginDragDropSource(uiDragDropFlags flags) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    // FIXME-DRAGDROP: While in the common-most "drag from non-zero active id" case we can tell the mouse button,
    // in both SourceExtern and id==0 cases we may requires something else (explicit flags or some heuristic).
    uiMouseButton mouse_button = uiMouseButton_Left;
    bool source_drag_active = false;
    uiID source_id = 0;
    uiID source_parent_id = 0;
    if ((flags & uiDragDropFlags_SourceExtern) == 0) {
        source_id = g.LastItemData.ID;
        if (source_id != 0) {
            // Common path: items with ID
            if (g.ActiveId != source_id) return false;
            if (g.ActiveIdMouseButton != -1) mouse_button = g.ActiveIdMouseButton;
            if (g.IO.MouseDown[mouse_button] == false || window->SkipItems) return false;
            g.ActiveIdAllowOverlap = false;
        } else {
            // Uncommon path: items without ID
            if (g.IO.MouseDown[mouse_button] == false || window->SkipItems)
                return false;
            if ((g.LastItemData.StatusFlags & uiItemStatusFlags_HoveredRect) == 0 && (g.ActiveId == 0 || g.ActiveIdWindow != window))
                return false;
            // If you want to use BeginDragDropSource() on an item with no unique identifier for interaction, such as Text() or Image(), you need to:
            // A) Read the explanation below, B) Use the uiDragDropFlags_SourceAllowNullID flag.
            if (!(flags & uiDragDropFlags_SourceAllowNullID)) {
                IM_ASSERT(0);
                return false;
            }
            // Magic fallback to handle items with no assigned ID, e.g. Text(), Image()
            // We build a throwaway ID based on current ID stack + relative AABB of items in window.
            // THE IDENTIFIER WON'T SURVIVE ANY REPOSITIONING/RESIZING OF THE WIDGET, so if your widget moves your dragging operation will be canceled.
            // We don't need to maintain/call ClearActiveID() as releasing the button will early out this function and trigger !ActiveIdIsAlive.
            // Rely on keeping other window->LastItemXXX fields intact.
            source_id = g.LastItemData.ID = window->GetIDFromRectangle(g.LastItemData.Rect);
            KeepAliveID(source_id);
            bool is_hovered = ItemHoverable(g.LastItemData.Rect, source_id, g.LastItemData.ItemFlags);
            if (is_hovered && g.IO.MouseClicked[mouse_button]) {
                SetActiveID(source_id, window);
                FocusWindow(window);
            }
            // Allow the underlying widget to display/return hovered during the mouse release frame, else we would get a flicker.
            if (g.ActiveId == source_id) g.ActiveIdAllowOverlap = is_hovered;
        }
        if (g.ActiveId != source_id) return false;
        source_parent_id = window->IDStack.back();
        source_drag_active = IsMouseDragging(mouse_button);
        // Disable navigation and key inputs while dragging + cancel existing request if any
        SetActiveIdUsingAllKeyboardKeys();
    } else {
        // When uiDragDropFlags_SourceExtern is set:
        window = NULL;
        source_id = ImHashStr("#SourceExtern");
        source_drag_active = true;
        mouse_button = g.IO.MouseDown[0] ? 0 : -1;
        KeepAliveID(source_id);
        SetActiveID(source_id, NULL);
    }
    IM_ASSERT(g.DragDropWithinTarget == false); // Can't nest BeginDragDropSource() and BeginDragDropTarget()
    if (!source_drag_active) return false;
    // Activate drag and drop
    if (!g.DragDropActive) {
        IM_ASSERT(source_id != 0);
        ClearDragDrop();
        IMGUI_DEBUG_LOG_ACTIVEID("[dragdrop] BeginDragDropSource() DragDropActive = true, source_id = 0x%08X%s\n",
            source_id, (flags & uiDragDropFlags_SourceExtern) ? " (EXTERN)" : "");
        uiPayload& payload = g.DragDropPayload;
        payload.SourceId = source_id;
        payload.SourceParentId = source_parent_id;
        g.DragDropActive = true;
        g.DragDropSourceFlags = flags;
        g.DragDropMouseButton = mouse_button;
        if (payload.SourceId == g.ActiveId) g.ActiveIdNoClearOnFocusLoss = true;
    }
    g.DragDropSourceFrameCount = g.FrameCount;
    g.DragDropWithinSource = true;
    if (!(flags & uiDragDropFlags_SourceNoPreviewTooltip)) {
        // Target can request the Source to not display its tooltip (we use a dedicated flag to make this request explicit)
        // We unfortunately can't just modify the source flags and skip the call to BeginTooltip, as caller may be emitting contents.
        bool ret;
        if (g.DragDropAcceptIdPrev && (g.DragDropAcceptFlagsPrev & uiDragDropFlags_AcceptNoPreviewTooltip))
            ret = BeginTooltipHidden();
        else
            ret = BeginTooltip();
        IM_ASSERT(ret); // FIXME-NEWBEGIN: If this ever becomes false, we need to Begin("##Hidden", NULL, uiWindowFlags_NoSavedSettings) + SetWindowHiddenAndSkipItemsForCurrentFrame().
        IM_UNUSED(ret);
    }
    if (!(flags & uiDragDropFlags_SourceNoDisableHover) && !(flags & uiDragDropFlags_SourceExtern))
        g.LastItemData.StatusFlags &= ~uiItemStatusFlags_HoveredRect;
    return true;
}
void UI::EndDragDropSource() {
    uiContext& g = *GImGui;
    IM_ASSERT(g.DragDropActive);
    IM_ASSERT(g.DragDropWithinSource && "Not after a BeginDragDropSource()?");
    if (!(g.DragDropSourceFlags & uiDragDropFlags_SourceNoPreviewTooltip)) EndTooltip();
    // Discard the drag if have not called SetDragDropPayload()
    if (g.DragDropPayload.DataFrameCount == -1) ClearDragDrop();
    g.DragDropWithinSource = false;
}
// Use 'cond' to choose to submit payload on drag start or every frame
bool UI::SetDragDropPayload(const char* type, const void* data, size_t data_size, uiCond cond) {
    uiContext& g = *GImGui;
    uiPayload& payload = g.DragDropPayload;
    if (cond == 0) cond = uiCond_Always;
    IM_ASSERT(type != NULL);
    IM_ASSERT(ImStrlen(type) < IM_COUNTOF(payload.DataType) && "Payload type can be at most 32 characters long");
    IM_ASSERT((data != NULL && data_size > 0) || (data == NULL && data_size == 0));
    IM_ASSERT(cond == uiCond_Always || cond == uiCond_Once);
    IM_ASSERT(payload.SourceId != 0); // Not called between BeginDragDropSource() and EndDragDropSource()
    if (cond == uiCond_Always || payload.DataFrameCount == -1) {
        // Copy payload
        ImStrncpy(payload.DataType, type, IM_COUNTOF(payload.DataType));
        g.DragDropPayloadBufHeap.resize(0);
        if (data_size > sizeof(g.DragDropPayloadBufLocal)) {
            // Store in heap
            g.DragDropPayloadBufHeap.resize((int)data_size);
            payload.Data = g.DragDropPayloadBufHeap.Data;
            memcpy(payload.Data, data, (size_t)(int)data_size);
        } else if (data_size > 0) {
            // Store locally
            memset(&g.DragDropPayloadBufLocal, 0, sizeof(g.DragDropPayloadBufLocal));
            payload.Data = g.DragDropPayloadBufLocal;
            memcpy(payload.Data, data, (size_t)(int)data_size);
        } else {
            payload.Data = NULL;
        }
        payload.DataSize = (int)data_size;
    }
    payload.DataFrameCount = g.FrameCount;
    // Return whether the payload has been accepted
    return (g.DragDropAcceptFrameCount == g.FrameCount) || (g.DragDropAcceptFrameCount == g.FrameCount - 1);
}
bool UI::BeginDragDropTargetCustom(const ImRect& bb, uiID id) {
    uiContext& g = *GImGui;
    if (!g.DragDropActive) return false;
    uiWindow* window = g.CurrentWindow;
    uiWindow* hovered_window = g.HoveredWindowUnderMovingWindow;
    if (hovered_window == NULL || window->RootWindowDockTree != hovered_window->RootWindowDockTree)
        return false;
    IM_ASSERT(id != 0);
    if (!IsMouseHoveringRect(bb.Min, bb.Max) || (id == g.DragDropPayload.SourceId)) return false;
    if (window->SkipItems) return false;

    IM_ASSERT(g.DragDropWithinTarget == false && g.DragDropWithinSource == false); // Can't nest BeginDragDropSource() and BeginDragDropTarget()
    g.DragDropTargetRect = bb;
    g.DragDropTargetClipRect = window->ClipRect; // May want to be overridden by user depending on use case?
    g.DragDropTargetId = id;
    g.DragDropTargetFullViewport = 0;
    g.DragDropWithinTarget = true;
    return true;
}
// Typical usage would be:
//   if (!UI::IsWindowHovered(uiHoverFlags_AnyWindow | uiHoverFlags_AllowWhenBlockedByActiveItem))
//       if (UI::BeginDragDropTargetViewport(UI::GetMainViewport(), NULL))
// But we are leaving the hover test to the caller for maximum flexibility.
bool UI::BeginDragDropTargetViewport(uiViewport* viewport, const ImRect* p_bb) {
    uiContext& g = *GImGui;
    if (!g.DragDropActive) return false;

    ImRect bb = p_bb ? *p_bb : ((uiViewportP*)viewport)->GetWorkRect();
    uiID id = viewport->ID;
    if (g.MouseViewport != viewport || !IsMouseHoveringRect(bb.Min, bb.Max, false) || (id == g.DragDropPayload.SourceId))
        return false;

    IM_ASSERT(g.DragDropWithinTarget == false && g.DragDropWithinSource == false); // Can't nest BeginDragDropSource() and BeginDragDropTarget()
    g.DragDropTargetRect = bb;
    g.DragDropTargetClipRect = bb;
    g.DragDropTargetId = id;
    g.DragDropTargetFullViewport = id;
    g.DragDropWithinTarget = true;
    return true;
}
// We don't use BeginDragDropTargetCustom() and duplicate its code because:
// 1) we use LastItemData's uiItemStatusFlags_HoveredRect which handles items that push a temporarily clip rectangle in their code. Calling BeginDragDropTargetCustom(LastItemRect) would not handle them.
// 2) and it's faster. as this code may be very frequently called, we want to early out as fast as we can.
// Also note how the HoveredWindow test is positioned differently in both functions (in both functions we optimize for the cheapest early out case)
bool UI::BeginDragDropTarget() {
    uiContext& g = *GImGui;
    if (!g.DragDropActive) return false;

    uiWindow* window = g.CurrentWindow;
    if (!(g.LastItemData.StatusFlags & uiItemStatusFlags_HoveredRect)) return false;
    uiWindow* hovered_window = g.HoveredWindowUnderMovingWindow;
    if (hovered_window == NULL || window->RootWindowDockTree != hovered_window->RootWindowDockTree || window->SkipItems)
        return false;
    const ImRect& display_rect = (g.LastItemData.StatusFlags & uiItemStatusFlags_HasDisplayRect) ? g.LastItemData.DisplayRect : g.LastItemData.Rect;
    uiID id = g.LastItemData.ID;
    if (id == 0) {
        id = window->GetIDFromRectangle(display_rect);
        KeepAliveID(id);
    }
    if (g.DragDropPayload.SourceId == id) return false;

    IM_ASSERT(g.DragDropWithinTarget == false && g.DragDropWithinSource == false); // Can't nest BeginDragDropSource() and BeginDragDropTarget()
    g.DragDropTargetRect = display_rect;
    g.DragDropTargetClipRect = (g.LastItemData.StatusFlags & uiItemStatusFlags_HasClipRect) ? g.LastItemData.ClipRect : window->ClipRect;
    g.DragDropTargetId = id;
    g.DragDropWithinTarget = true;
    return true;
}
bool UI::IsDragDropPayloadBeingAccepted() {
    uiContext& g = *GImGui;
    return g.DragDropActive && g.DragDropAcceptIdPrev != 0;
}
const uiPayload* UI::AcceptDragDropPayload(const char* type, uiDragDropFlags flags) {
    uiContext& g = *GImGui;
    uiPayload& payload = g.DragDropPayload;
    IM_ASSERT(g.DragDropActive);                        // Not called between BeginDragDropTarget() and EndDragDropTarget() ?
    IM_ASSERT(payload.DataFrameCount != -1);            // Forgot to call EndDragDropTarget() ?
    if (type != NULL && !payload.IsDataType(type)) return NULL;

    // Accept smallest drag target bounding box, this allows us to nest drag targets conveniently without ordering constraints.
    // NB: We currently accept NULL id as target. However, overlapping targets requires a unique ID to function!
    const bool was_accepted_previously = (g.DragDropAcceptIdPrev == g.DragDropTargetId);
    ImRect r = g.DragDropTargetRect;
    float r_surface = r.GetWidth() * r.GetHeight();
    if (r_surface > g.DragDropAcceptIdCurrRectSurface) return NULL;

    g.DragDropAcceptFlagsCurr = flags;
    g.DragDropAcceptIdCurr = g.DragDropTargetId;
    g.DragDropAcceptIdCurrRectSurface = r_surface;
    //IMGUI_DEBUG_LOG("AcceptDragDropPayload(): %08X: accept\n", g.DragDropTargetId);
    // Render default drop visuals
    payload.Preview = was_accepted_previously;
    flags |= (g.DragDropSourceFlags & uiDragDropFlags_AcceptNoDrawDefaultRect); // Source can also inhibit the preview (useful for external sources that live for 1 frame)
    const bool draw_target_rect = payload.Preview && !(flags & uiDragDropFlags_AcceptNoDrawDefaultRect);
    if (draw_target_rect && g.DragDropTargetFullViewport != 0) {
        uiViewport* viewport = FindViewportByID(g.DragDropTargetFullViewport);
        IM_ASSERT(viewport != NULL);
        ImRect bb = g.DragDropTargetRect;
        bb.Expand(-3.5f);
        RenderDragDropTargetRectEx(GetForegroundDrawList(viewport), bb, g.Style.DragDropTargetRounding);
    } else if (draw_target_rect) {
        RenderDragDropTargetRectForItem(r);
    }
    g.DragDropAcceptFrameCount = g.FrameCount;
    if ((g.DragDropSourceFlags & uiDragDropFlags_SourceExtern) && g.DragDropMouseButton == -1)
        payload.Delivery = was_accepted_previously && (g.DragDropSourceFrameCount < g.FrameCount);
    else
        payload.Delivery = was_accepted_previously && !IsMouseDown(g.DragDropMouseButton); // For extern drag sources affecting OS window focus, it's easier to just test !IsMouseDown() instead of IsMouseReleased()
    if (!payload.Delivery && !(flags & uiDragDropFlags_AcceptBeforeDelivery))
        return NULL;
    if (payload.Delivery)
        IMGUI_DEBUG_LOG_ACTIVEID("[dragdrop] AcceptDragDropPayload(): 0x%08X: payload delivery\n", g.DragDropTargetId);
    return &payload;
}
// FIXME-STYLE FIXME-DRAGDROP: Settle on a proper default visuals for drop target.
void UI::RenderDragDropTargetRectForItem(const ImRect& bb) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    ImRect bb_display = bb;
    bb_display.ClipWith(g.DragDropTargetClipRect); // Clip THEN expand so we have a way to visualize that target is not entirely visible.
    bb_display.Expand(g.Style.DragDropTargetPadding);
    bool push_clip_rect = !window->ClipRect.Contains(bb_display);
    if (push_clip_rect) window->DrawList->PushClipRectFullScreen();
    RenderDragDropTargetRectEx(window->DrawList, bb_display, g.Style.DragDropTargetRounding);
    if (push_clip_rect) window->DrawList->PopClipRect();
}
void UI::RenderDragDropTargetRectEx(ImDrawList* draw_list, const ImRect& bb, float rounding) {
    uiContext& g = *GImGui;
    draw_list->AddRectFilled(bb.Min, bb.Max, GetColorU32(uiCol_DragDropTargetBg), rounding, 0);
    draw_list->AddRect(bb.Min, bb.Max, GetColorU32(uiCol_DragDropTarget), rounding, g.Style.DragDropTargetBorderSize);
}
const uiPayload* UI::GetDragDropPayload() {
    uiContext& g = *GImGui;
    return (g.DragDropActive && g.DragDropPayload.DataFrameCount != -1) ? &g.DragDropPayload : NULL;
}
void UI::EndDragDropTarget() {
    uiContext& g = *GImGui;
    IM_ASSERT(g.DragDropActive);
    IM_ASSERT(g.DragDropWithinTarget);
    g.DragDropWithinTarget = false;
    // Clear drag and drop state payload right after delivery
    if (g.DragDropPayload.Delivery) ClearDragDrop();
}
//-----------------------------------------------------------------------------
// [SECTION] LOGGING/CAPTURING
//-----------------------------------------------------------------------------
// All text output from the interface can be captured into tty/file/clipboard.
// By default, tree nodes are automatically opened during logging.
//-----------------------------------------------------------------------------
// Pass text data straight to log (without being displayed)
static inline void LogTextV(uiContext& g, const char* fmt, va_list args) {
    if (g.LogFile) {
        g.LogBuffer.Buf.resize(0);
        g.LogBuffer.appendfv(fmt, args);
        ImFileWrite(g.LogBuffer.c_str(), sizeof(char), (ImU64)g.LogBuffer.size(), g.LogFile);
    } else {
        g.LogBuffer.appendfv(fmt, args);
    }
}
void UI::LogText(const char* fmt, ...) {
    uiContext& g = *GImGui;
    if (!g.LogEnabled) return;
    va_list args;
    va_start(args, fmt);
    LogTextV(g, fmt, args);
    va_end(args);
}
void UI::LogTextV(const char* fmt, va_list args) {
    uiContext& g = *GImGui;
    if (!g.LogEnabled) return;
    LogTextV(g, fmt, args);
}
// Internal version that takes a position to decide on newline placement and pad items according to their depth.
// We split text into individual lines to add current tree level padding
// FIXME: This code is a little complicated perhaps, considering simplifying the whole system.
void UI::LogRenderedText(const vec2* ref_pos, const char* text, const char* text_end) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;

    const char* prefix = g.LogNextPrefix;
    const char* suffix = g.LogNextSuffix;
    g.LogNextPrefix = g.LogNextSuffix = NULL;

    if (!text_end) text_end = FindRenderedTextEnd(text, text_end);

    const bool log_new_line = ref_pos && (ref_pos->y > g.LogLinePosY + ImMax(g.Style.FramePadding.y, g.Style.ItemSpacing.y) + 1);
    if (ref_pos) g.LogLinePosY = ref_pos->y;
    if (log_new_line) {
        LogText(IM_NEWLINE);
        g.LogLineFirstItem = true;
    }
    // Calculate end ourself to ensure "##" are included here.
    if (prefix) LogRenderedText(ref_pos, prefix, prefix + ImStrlen(prefix));
    // Re-adjust padding if we have popped out of our starting depth
    if (g.LogDepthRef > window->DC.TreeDepth) g.LogDepthRef = window->DC.TreeDepth;
    const int tree_depth = (window->DC.TreeDepth - g.LogDepthRef);
    const char* text_remaining = text;
    for (;;) {
        // Split the string. Each new line (after a '\n') is followed by indentation corresponding to the current depth of our log entry.
        // We don't add a trailing \n yet to allow a subsequent item on the same line to be captured.
        const char* line_start = text_remaining;
        const char* line_end = ImStreolRange(line_start, text_end);
        const bool is_last_line = (line_end == text_end);
        if (line_start != line_end || !is_last_line) {
            const int line_length = (int)(line_end - line_start);
            const int indentation = g.LogLineFirstItem ? tree_depth * 4 : 1;
            LogText("%*s%.*s", indentation, "", line_length, line_start);
            g.LogLineFirstItem = false;
            if (*line_end == '\n') {
                LogText(IM_NEWLINE);
                g.LogLineFirstItem = true;
            }
        }
        if (is_last_line) break;
        text_remaining = line_end + 1;
    }
    if (suffix) LogRenderedText(ref_pos, suffix, suffix + ImStrlen(suffix));
}
// Start logging/capturing text output
void UI::LogBegin(uiLogFlags flags, int auto_open_depth) {
    uiContext& g = *GImGui;
    uiWindow* window = g.CurrentWindow;
    IM_ASSERT(g.LogEnabled == false);
    IM_ASSERT(g.LogFile == NULL && g.LogBuffer.empty());
    IM_ASSERT(ImIsPowerOfTwo(flags & uiLogFlags_OutputMask_)); // Check that only 1 type flag is used

    g.LogEnabled = g.ItemUnclipByLog = true;
    g.LogFlags = flags;
    g.LogWindow = window;
    g.LogNextPrefix = g.LogNextSuffix = NULL;
    g.LogDepthRef = window->DC.TreeDepth;
    g.LogDepthToExpand = ((auto_open_depth >= 0) ? auto_open_depth : g.LogDepthToExpandDefault);
    g.LogLinePosY = FLT_MAX;
    g.LogLineFirstItem = true;
}
// Important: doesn't copy underlying data, use carefully (prefix/suffix must be in scope at the time of the next LogRenderedText)
void UI::LogSetNextTextDecoration(const char* prefix, const char* suffix) {
    uiContext& g = *GImGui;
    g.LogNextPrefix = prefix;
    g.LogNextSuffix = suffix;
}
void UI::LogToTTY(int auto_open_depth) {
    uiContext& g = *GImGui;
    if (g.LogEnabled) return;
    IM_UNUSED(auto_open_depth);
#ifndef IMGUI_DISABLE_TTY_FUNCTIONS
    LogBegin(uiLogFlags_OutputTTY, auto_open_depth);
    g.LogFile = stdout;
#endif
}
// Start logging/capturing text output to given file
void UI::LogToFile(int auto_open_depth, const char* filename) {
    uiContext& g = *GImGui;
    if (g.LogEnabled) return;
    // FIXME: We could probably open the file in text mode "at", however note that clipboard/buffer logging will still
    // be subject to outputting OS-incompatible carriage return if within strings the user doesn't use IM_NEWLINE.
    // By opening the file in binary mode "ab" we have consistent output everywhere.
    if (!filename) filename = g.IO.LogFilename;
    if (!filename || !filename[0]) return;
    ImFileHandle f = ImFileOpen(filename, "ab");
    if (!f) {
        IM_ASSERT(0);
        return;
    }
    LogBegin(uiLogFlags_OutputFile, auto_open_depth);
    g.LogFile = f;
}
// Start logging/capturing text output to clipboard
void UI::LogToClipboard(int auto_open_depth) {
    uiContext& g = *GImGui;
    if (g.LogEnabled) return;
    LogBegin(uiLogFlags_OutputClipboard, auto_open_depth);
}
void UI::LogToBuffer(int auto_open_depth) {
    uiContext& g = *GImGui;
    if (g.LogEnabled) return;
    LogBegin(uiLogFlags_OutputBuffer, auto_open_depth);
}
void UI::LogFinish() {
    uiContext& g = *GImGui;
    if (!g.LogEnabled) return;

    LogText(IM_NEWLINE);
    switch (g.LogFlags & uiLogFlags_OutputMask_)
    {
    case uiLogFlags_OutputTTY:
#ifndef IMGUI_DISABLE_TTY_FUNCTIONS
        fflush(g.LogFile);
#endif
        break;
    case uiLogFlags_OutputFile:
        ImFileClose(g.LogFile);
        break;
    case uiLogFlags_OutputBuffer:
        break;
    case uiLogFlags_OutputClipboard:
        if (!g.LogBuffer.empty())
            SetClipboardText(g.LogBuffer.begin());
        break;
    default:
        IM_ASSERT(0);
        break;
    }
    g.LogEnabled = g.ItemUnclipByLog = false;
    g.LogFlags = uiLogFlags_None;
    g.LogFile = NULL;
    g.LogBuffer.clear();
}
// Helper to display logging buttons
// FIXME-OBSOLETE: We should probably obsolete this and let the user have their own helper (this is one of the oldest function alive!)
void UI::LogButtons() {
    uiContext& g = *GImGui;
    PushID("LogButtons");
#ifndef IMGUI_DISABLE_TTY_FUNCTIONS
    const bool log_to_tty = Button("Log To TTY"); SameLine();
#else
    const bool log_to_tty = false;
#endif
    const bool log_to_file = Button("Log To File"); SameLine();
    const bool log_to_clipboard = Button("Log To Clipboard"); SameLine();
    PushItemFlag(uiItemFlags_NoTabStop, true);
    SetNextItemWidth(CalcTextSize("999").x);
    SliderInt("Default Depth", &g.LogDepthToExpandDefault, 0, 9, NULL);
    PopItemFlag();
    PopID();
    // Start logging at the end of the function so that the buttons don't appear in the log
    if (log_to_tty) LogToTTY();
    if (log_to_file) LogToFile();
    if (log_to_clipboard) LogToClipboard();
}
