uiViewport* UI::GetMainViewport() {
    uiContext& g = *GImGui;
    return g.Viewports[0];
}
// FIXME: This leaks access to viewports not listed in PlatformIO.Viewports[]. Problematic? (#4236)
uiViewport* UI::FindViewportByID(uiID viewport_id) {
    uiContext& g = *GImGui;
    for (uiViewportP* viewport : g.Viewports)
        if (viewport->ID == viewport_id)
            return viewport;
    return NULL;
}
uiViewport* UI::FindViewportByPlatformHandle(void* platform_handle) {
    uiContext& g = *GImGui;
    for (uiViewportP* viewport : g.Viewports)
        if (viewport->PlatformHandle == platform_handle)
            return viewport;
    return NULL;
}
void UI::SetCurrentViewport(uiWindow* current_window, uiViewportP* viewport) {
    uiContext& g = *GImGui;
    (void)current_window;
    if (viewport) viewport->LastFrameActive = g.FrameCount;
    if (g.CurrentViewport == viewport) return;
    g.CurrentDpiScale = viewport ? viewport->DpiScale : 1.0f;
    g.CurrentViewport = viewport;
    IM_ASSERT(g.CurrentDpiScale > 0.0f && g.CurrentDpiScale < 99.0f); // Typical correct values would be between 1.0f and 4.0f
    //IMGUI_DEBUG_LOG_VIEWPORT("[viewport] SetCurrentViewport changed '%s' 0x%08X\n", current_window ? current_window->Name : NULL, viewport ? viewport->ID : 0);
    if (g.IO.ConfigDpiScaleFonts) g.Style.FontScaleDpi = g.CurrentDpiScale;
    // Notify platform layer of viewport changes
    // FIXME-DPI: This is only currently used for experimenting with handling of multiple DPI
    if (g.CurrentViewport && g.PlatformIO.Platform_OnChangedViewport)
        g.PlatformIO.Platform_OnChangedViewport(g.CurrentViewport);
}
void UI::SetWindowViewport(uiWindow* window, uiViewportP* viewport) {
    // Abandon viewport
    if (window->ViewportOwned && window->Viewport->Window == window)
        window->Viewport->Size = vec2(0.0f, 0.0f);
    window->Viewport = viewport;
    window->ViewportId = viewport->ID;
    window->ViewportOwned = (viewport->Window == window);
}
static bool UI::GetWindowAlwaysWantOwnViewport(uiWindow* window) {
    // Tooltips and menus are not automatically forced into their own viewport when the NoMerge flag is set, however the multiplication of viewports makes them more likely to protrude and create their own.
    uiContext& g = *GImGui;
    if (g.IO.ConfigViewportsNoAutoMerge || (window->WindowClass.ViewportFlagsOverrideSet & uiViewportFlags_NoAutoMerge))
        if (g.ConfigFlagsCurrFrame & uiConfigFlags_ViewportsEnable)
            if (!window->DockIsActive)
                if ((window->Flags & (uiWindowFlags_ChildWindow | uiWindowFlags_ChildMenu | uiWindowFlags_Tooltip)) == 0)
                    if ((window->Flags & uiWindowFlags_Popup) == 0 || (window->Flags & uiWindowFlags_Modal) != 0)
                        return true;
    return false;
}
// Heuristic, see #8948: depends on how backends handle OS-level parenting.
// Due to how parent viewport stack is layed out, note that IsViewportAbove(a,b) isn't always the same as !IsViewportAbove(b,a).
static bool IsViewportAbove(uiViewportP* potential_above, uiViewportP* potential_below) {
    // If uiBackendFlags_HasParentViewport if set, ->ParentViewport chain should be accurate.
    uiContext& g = *GImGui;
    if (g.IO.BackendFlags & uiBackendFlags_HasParentViewport) {
        for (uiViewport* v = potential_above; v != NULL && v->ParentViewport; v = v->ParentViewport)
            if (v->ParentViewport == potential_below)
                return true;
    } else {
        if (potential_above->ParentViewport == potential_below) return true;
    }
    if (potential_above->LastFocusedStampCount > potential_below->LastFocusedStampCount) return true;
    return false;
}
static bool UI::UpdateTryMergeWindowIntoHostViewport(uiWindow* window, uiViewportP* viewport_dst) {
    uiContext& g = *GImGui;
    IM_ASSERT(window == window->RootWindowDockTree);
    uiViewportP* viewport_src = window->Viewport; // Current viewport
    if (viewport_src == viewport_dst) return false;
    if ((viewport_dst->Flags & uiViewportFlags_CanHostOtherWindows) == 0) return false;
    if ((viewport_dst->Flags & uiViewportFlags_IsMinimized) != 0) return false;
    if (!viewport_dst->GetMainRect().Contains(window->Rect())) return false;
    if (GetWindowAlwaysWantOwnViewport(window)) return false;
    for (uiViewportP* viewport_obstructing : g.Viewports) {
        if (viewport_obstructing == viewport_src || viewport_obstructing == viewport_dst)
            continue;
        if (viewport_obstructing->GetMainRect().Overlaps(window->Rect()))
            if (IsViewportAbove(viewport_obstructing, viewport_dst))
                if (viewport_src == NULL || IsViewportAbove(viewport_src, viewport_obstructing))
                    return false; // viewport_obstructing is between viewport_src and viewport_dst -> Cannot merge.
    }
    // Move to the existing viewport, Move child/hosted windows as well (FIXME-OPT: iterate child)
    IMGUI_DEBUG_LOG_VIEWPORT("[viewport] Window '%s' merge into Viewport 0X%08X\n", window->Name, viewport_dst->ID);
    if (window->ViewportOwned)
        for (int n = 0; n < g.Windows.Size; n++)
            if (g.Windows[n]->Viewport == viewport_src)
                SetWindowViewport(g.Windows[n], viewport_dst);
    SetWindowViewport(window, viewport_dst);
    if ((window->Flags & uiWindowFlags_NoBringToFrontOnFocus) == 0)
        BringWindowToDisplayFront(window);
    return true;
}
// FIXME: handle 0 to N host viewports
static bool UI::UpdateTryMergeWindowIntoHostViewports(uiWindow* window) {
    uiContext& g = *GImGui;
    return UpdateTryMergeWindowIntoHostViewport(window, g.Viewports[0]);
}
// Translate Dear ImGui windows when a Host Viewport has been moved
// (This additionally keeps windows at the same place when uiConfigFlags_ViewportsEnable is toggled!)
void UI::TranslateWindowsInViewport(uiViewportP* viewport, const vec2& old_pos, const vec2& new_pos, const vec2& old_size, const vec2& new_size) {
    uiContext& g = *GImGui;
    //IMGUI_DEBUG_LOG_VIEWPORT("[viewport] TranslateWindowsInViewport 0x%08X\n", viewport->ID);
    IM_ASSERT(viewport->Window == NULL && (viewport->Flags & uiViewportFlags_CanHostOtherWindows));
    // 1) We test if uiConfigFlags_ViewportsEnable was just toggled, which allows us to conveniently
    // translate imgui windows from OS-window-local to absolute coordinates or vice-versa.
    // 2) If it's not going to fit into the new size, keep it at same absolute position.
    // One problem with this is that most Win32 applications doesn't update their render while dragging,
    // and so the window will appear to teleport when releasing the mouse.
    const bool translate_all_windows = (g.ConfigFlagsCurrFrame & uiConfigFlags_ViewportsEnable) != (g.ConfigFlagsLastFrame & uiConfigFlags_ViewportsEnable);
    ImRect test_still_fit_rect(old_pos, old_pos + old_size);
    vec2 delta_pos = new_pos - old_pos;
    for (uiWindow* window : g.Windows) // FIXME-OPT
        if (translate_all_windows || (window->Viewport == viewport && (old_size == new_size || test_still_fit_rect.Contains(window->Rect()))))
            TranslateWindow(window, delta_pos);
}
// Scale all windows (position, size). Use when e.g. changing DPI. (This is a lossy operation!)
void UI::ScaleWindowsInViewport(uiViewportP* viewport, float scale) {
    uiContext& g = *GImGui;
    //IMGUI_DEBUG_LOG_VIEWPORT("[viewport] ScaleWindowsInViewport 0x%08X\n", viewport->ID);
    if (viewport->Window) {
        ScaleWindow(viewport->Window, scale);
    } else {
        for (uiWindow* window : g.Windows)
            if (window->Viewport == viewport)
                ScaleWindow(window, scale);
    }
}
// If the backend doesn't support uiBackendFlags_HasMouseHoveredViewport or doesn't honor uiViewportFlags_NoInputs for it, we do a search ourselves.
// A) It won't take account of the possibility that non-imgui windows may be in-between our dragged window and our target window.
// B) It requires Platform_GetWindowFocus to be implemented by backend.
uiViewportP* UI::FindHoveredViewportFromPlatformWindowStack(const vec2& mouse_platform_pos) {
    uiContext& g = *GImGui;
    uiViewportP* best_candidate = NULL;
    for (uiViewportP* viewport : g.Viewports)
        if (!(viewport->Flags & (uiViewportFlags_NoInputs | uiViewportFlags_IsMinimized)) && viewport->GetMainRect().Contains(mouse_platform_pos))
            if (best_candidate == NULL || best_candidate->LastFocusedStampCount < viewport->LastFocusedStampCount)
                if (viewport->PlatformWindowCreated)
                    best_candidate = viewport;
    return best_candidate;
}
// Update viewports and monitor infos
// Note that this is running even if 'uiConfigFlags_ViewportsEnable' is not set, in order to clear unused viewports (if any) and update monitor info.
static void UI::UpdateViewportsNewFrame() {
    uiContext& g = *GImGui;
    IM_ASSERT(g.PlatformIO.Viewports.Size <= g.Viewports.Size);
    // Update Minimized status (we need it first in order to decide if we'll apply Pos/Size of the main viewport)
    // Update Focused status
    const bool viewports_enabled = (g.ConfigFlagsCurrFrame & uiConfigFlags_ViewportsEnable) != 0;
    if (viewports_enabled) {
        uiViewportP* focused_viewport = NULL;
        for (uiViewportP* viewport : g.Viewports) {
            const bool platform_funcs_available = viewport->PlatformWindowCreated;
            if (g.PlatformIO.Platform_GetWindowMinimized && platform_funcs_available) {
                bool is_minimized = g.PlatformIO.Platform_GetWindowMinimized(viewport);
                if (is_minimized) viewport->Flags |= uiViewportFlags_IsMinimized;
                else viewport->Flags &= ~uiViewportFlags_IsMinimized;
            }
            // Update our implicit z-order knowledge of platform windows, which is used when the backend cannot provide io.MouseHoveredViewport.
            // When setting Platform_GetWindowFocus, it is expected that the platform backend can handle calls without crashing if it doesn't have data stored.
            if (g.PlatformIO.Platform_GetWindowFocus && platform_funcs_available) {
                bool is_focused = g.PlatformIO.Platform_GetWindowFocus(viewport);
                if (is_focused) viewport->Flags |= uiViewportFlags_IsFocused;
                else viewport->Flags &= ~uiViewportFlags_IsFocused;
                if (is_focused) focused_viewport = viewport;
            }
        }
        // Focused viewport has changed?
        if (focused_viewport && g.PlatformLastFocusedViewportId != focused_viewport->ID) {
            IMGUI_DEBUG_LOG_VIEWPORT("[viewport] Focused viewport changed %08X -> %08X '%s', attempting to apply our focus.\n", g.PlatformLastFocusedViewportId, focused_viewport->ID, focused_viewport->Window ? focused_viewport->Window->Name : "n/a");
            const uiViewport* prev_focused_viewport = FindViewportByID(g.PlatformLastFocusedViewportId);
            const bool prev_focused_has_been_destroyed = (prev_focused_viewport == NULL) || (prev_focused_viewport->PlatformWindowCreated == false);
            // Store a tag so we can infer z-order easily from all our windows
            // We compare PlatformLastFocusedViewportId so newly created viewports with _NoFocusOnAppearing flag
            // will keep the front most stamp instead of losing it back to their parent viewport.
            if (focused_viewport->LastFocusedStampCount != g.ViewportFocusedStampCount)
                focused_viewport->LastFocusedStampCount = ++g.ViewportFocusedStampCount;
            g.PlatformLastFocusedViewportId = focused_viewport->ID;
            // Focus associated dear imgui window
            // - if focus didn't happen with a click within imgui boundaries, e.g. Clicking platform title bar. (#6299)
            // - if focus didn't happen because we destroyed another window (#6462)
            // FIXME: perhaps 'FocusTopMostWindowUnderOne()' can handle the 'focused_window->Window != NULL' case as well.
            const bool apply_imgui_focus_on_focused_viewport = !IsAnyMouseDown() && !prev_focused_has_been_destroyed;
            if (apply_imgui_focus_on_focused_viewport && g.IO.ConfigViewportsPlatformFocusSetsuiFocus) {
                focused_viewport->LastFocusedHadNavWindow |= (g.NavWindow != NULL) && (g.NavWindow->Viewport == focused_viewport); // Update so a window changing viewport won't lose focus.
                uiFocusRequestFlags focus_request_flags = uiFocusRequestFlags_UnlessBelowModal | uiFocusRequestFlags_RestoreFocusedChild;
                if (focused_viewport->Window != NULL)
                    FocusWindow(focused_viewport->Window, focus_request_flags);
                else if (focused_viewport->LastFocusedHadNavWindow)
                    FocusTopMostWindowUnderOne(NULL, NULL, focused_viewport, focus_request_flags); // Focus top most in viewport
                else
                    FocusWindow(NULL, focus_request_flags); // No window had focus last time viewport was focused
            }
        }
        if (focused_viewport)
            focused_viewport->LastFocusedHadNavWindow = (g.NavWindow != NULL) && (g.NavWindow->Viewport == focused_viewport);
    }
    // Create/update main viewport with current platform position.
    // FIXME-VIEWPORT: Size is driven by backend/user code for backward-compatibility but we should aim to make this more consistent.
    uiViewportP* main_viewport = g.Viewports[0];
    IM_ASSERT(main_viewport->ID == IMGUI_VIEWPORT_DEFAULT_ID);
    IM_ASSERT(main_viewport->Window == NULL);
    vec2 main_viewport_pos = viewports_enabled ? g.PlatformIO.Platform_GetWindowPos(main_viewport) : vec2(0.0f, 0.0f);
    vec2 main_viewport_size = g.IO.DisplaySize;
    vec2 main_viewport_framebuffer_scale = g.IO.DisplayFramebufferScale;
    if (viewports_enabled && (main_viewport->Flags & uiViewportFlags_IsMinimized)) {
        main_viewport_pos = main_viewport->Pos; // Preserve last pos/size when minimized (FIXME: We don't do the same for Size outside of the viewport path)
        main_viewport_size = main_viewport->Size;
        main_viewport_framebuffer_scale = main_viewport->FramebufferScale;
    }
    AddUpdateViewport(NULL, IMGUI_VIEWPORT_DEFAULT_ID, main_viewport_pos, main_viewport_size, uiViewportFlags_OwnedByApp | uiViewportFlags_CanHostOtherWindows);
    const float memory_compact_start_time = (g.GcCompactAll || g.IO.ConfigMemoryCompactTimer < 0.0f) ? FLT_MAX : (float)g.Time - g.IO.ConfigMemoryCompactTimer;
    g.CurrentDpiScale = 0.0f;
    g.CurrentViewport = NULL;
    g.MouseViewport = NULL;
    for (int n = 0; n < g.Viewports.Size; n++) {
        uiViewportP* viewport = g.Viewports[n];
        viewport->Idx = n;
        // Erase unused viewports
        if (n > 0 && viewport->LastFrameActive < g.FrameCount - 2) {
            DestroyViewport(viewport);
            n--;
            continue;
        }
        const bool platform_funcs_available = viewport->PlatformWindowCreated;
        if (viewports_enabled) {
            // Update Position and Size (from Platform Window to ImGui) if requested.
            // We do it early in the frame instead of waiting for UpdatePlatformWindows() to avoid a frame of lag when moving/resizing using OS facilities.
            if (!(viewport->Flags & uiViewportFlags_IsMinimized) && platform_funcs_available) {
                // Viewport->WorkPos and WorkSize will be updated below
                if (viewport->PlatformRequestMove)
                    viewport->Pos = viewport->LastPlatformPos = g.PlatformIO.Platform_GetWindowPos(viewport);
                if (viewport->PlatformRequestResize)
                    viewport->Size = viewport->LastPlatformSize = g.PlatformIO.Platform_GetWindowSize(viewport);
                if (g.PlatformIO.Platform_GetWindowFramebufferScale != NULL)
                    viewport->FramebufferScale = g.PlatformIO.Platform_GetWindowFramebufferScale(viewport);
            }
        }
        // Update/copy monitor info
        UpdateViewportPlatformMonitor(viewport);
        // Lock down space taken by menu bars and status bars + query initial insets from backend
        // Setup initial value for functions like BeginMainMenuBar(), DockSpaceOverViewport() etc.
        viewport->WorkInsetMin = viewport->BuildWorkInsetMin;
        viewport->WorkInsetMax = viewport->BuildWorkInsetMax;
        viewport->BuildWorkInsetMin = viewport->BuildWorkInsetMax = vec2(0.0f, 0.0f);
        if (g.PlatformIO.Platform_GetWindowWorkAreaInsets != NULL && platform_funcs_available) {
            vec4 insets = g.PlatformIO.Platform_GetWindowWorkAreaInsets(viewport);
            IM_ASSERT(insets.x >= 0.0f && insets.y >= 0.0f && insets.z >= 0.0f && insets.w >= 0.0f);
            viewport->BuildWorkInsetMin = vec2(insets.x, insets.y);
            viewport->BuildWorkInsetMax = vec2(insets.z, insets.w);
        }
        viewport->UpdateWorkRect();
        // Garbage collect transient buffers of recently BG/FG drawlists
        for (int dl_n = 0; dl_n < IM_COUNTOF(viewport->BgFgDrawLists); dl_n++)
            if (viewport->BgFgDrawListsLastTimeActive[dl_n] < memory_compact_start_time && viewport->BgFgDrawLists[dl_n] != NULL) {
                IM_DELETE(viewport->BgFgDrawLists[dl_n]);
                viewport->BgFgDrawLists[dl_n] = NULL;
            }
        // Reset alpha every frame. Users of transparency (docking) needs to request a lower alpha back.
        viewport->Alpha = 1.0f;
        // Translate Dear ImGui windows when a Host Viewport has been moved
        // (This additionally keeps windows at the same place when uiConfigFlags_ViewportsEnable is toggled!)
        const vec2 viewport_delta_pos = viewport->Pos - viewport->LastPos;
        if ((viewport->Flags & uiViewportFlags_CanHostOtherWindows) && (viewport_delta_pos.x != 0.0f || viewport_delta_pos.y != 0.0f))
            TranslateWindowsInViewport(viewport, viewport->LastPos, viewport->Pos, viewport->LastSize, viewport->Size);
        // Update DPI scale
        float new_dpi_scale;
        if (g.PlatformIO.Platform_GetWindowDpiScale && platform_funcs_available)
            new_dpi_scale = g.PlatformIO.Platform_GetWindowDpiScale(viewport);
        else if (viewport->PlatformMonitor != -1)
            new_dpi_scale = g.PlatformIO.Monitors[viewport->PlatformMonitor].DpiScale;
        else
            new_dpi_scale = (viewport->DpiScale != 0.0f) ? viewport->DpiScale : 1.0f;
        IM_ASSERT(new_dpi_scale > 0.0f && new_dpi_scale < 99.0f); // Typical correct values would be between 1.0f and 4.0f
        if (viewport->DpiScale != 0.0f && new_dpi_scale != viewport->DpiScale) {
            float scale_factor = new_dpi_scale / viewport->DpiScale;
            if (g.IO.ConfigDpiScaleViewports)
                ScaleWindowsInViewport(viewport, scale_factor);
            //if (viewport == GetMainViewport())
            //    g.PlatformInterface.SetWindowSize(viewport, viewport->Size * scale_factor);
            // Scale our window moving pivot so that the window will rescale roughly around the mouse position.
            // FIXME-VIEWPORT: This currently creates a resizing feedback loop when a window is straddling a DPI transition border.
            // (Minor: since our sizes do not perfectly linearly scale, deferring the click offset scale until we know the actual window scale ratio may get us slightly more precise mouse positioning.)
            //if (g.MovingWindow != NULL && g.MovingWindow->Viewport == viewport)
            //    g.ActiveIdClickOffset = ImTrunc(g.ActiveIdClickOffset * scale_factor);
        }
        viewport->DpiScale = new_dpi_scale;
    }
    // Update fallback monitor
    g.PlatformMonitorsFullWorkRect = ImRect(+FLT_MAX, +FLT_MAX, -FLT_MAX, -FLT_MAX);
    if (g.PlatformIO.Monitors.Size == 0) {
        uiPlatformMonitor* monitor = &g.FallbackMonitor;
        monitor->MainPos = main_viewport->Pos;
        monitor->MainSize = main_viewport->Size;
        monitor->WorkPos = main_viewport->WorkPos;
        monitor->WorkSize = main_viewport->WorkSize;
        monitor->DpiScale = main_viewport->DpiScale;
        g.PlatformMonitorsFullWorkRect.Add(monitor->WorkPos);
        g.PlatformMonitorsFullWorkRect.Add(monitor->WorkPos + monitor->WorkSize);
    } else {
        g.FallbackMonitor = g.PlatformIO.Monitors[0];
    } for (uiPlatformMonitor& monitor : g.PlatformIO.Monitors) {
        g.PlatformMonitorsFullWorkRect.Add(monitor.WorkPos);
        g.PlatformMonitorsFullWorkRect.Add(monitor.WorkPos + monitor.WorkSize);
    }
    if (!viewports_enabled) {
        g.MouseViewport = main_viewport;
        return;
    }
    // Mouse handling: decide on the actual mouse viewport for this frame between the active/focused viewport and the hovered viewport.
    // Note that 'viewport_hovered' should skip over any viewport that has the uiViewportFlags_NoInputs flags set.
    uiViewportP* viewport_hovered = NULL;
    if (g.IO.BackendFlags & uiBackendFlags_HasMouseHoveredViewport) {
        viewport_hovered = g.IO.MouseHoveredViewport ? (uiViewportP*)FindViewportByID(g.IO.MouseHoveredViewport) : NULL;
        if (viewport_hovered && (viewport_hovered->Flags & uiViewportFlags_NoInputs))
            viewport_hovered = FindHoveredViewportFromPlatformWindowStack(g.IO.MousePos); // Backend failed to handle _NoInputs viewport: revert to our fallback.
    } else {
        // If the backend doesn't know how to honor uiViewportFlags_NoInputs, we do a search ourselves. Note that this search:
        // A) won't take account of the possibility that non-imgui windows may be in-between our dragged window and our target window.
        // B) won't take account of how the backend apply parent<>child relationship to secondary viewports, which affects their Z order.
        // C) uses LastFocusedStampCount as a flawed replacement for the last time a window was focused (we could/should fix that by introducing Focus functions in PlatformIO)
        viewport_hovered = FindHoveredViewportFromPlatformWindowStack(g.IO.MousePos);
    }
    if (viewport_hovered != NULL) g.MouseLastHoveredViewport = viewport_hovered;
    else if (g.MouseLastHoveredViewport == NULL) g.MouseLastHoveredViewport = g.Viewports[0];
    // Update mouse reference viewport
    // (when moving a window we aim at its viewport, but this will be overwritten below if we go in drag and drop mode)
    // (MovingViewport->Viewport will be NULL in the rare situation where the window disappared while moving, set UpdateMouseMovingWindowNewFrame() for details)
    if (g.MovingWindow && g.MovingWindow->Viewport) g.MouseViewport = g.MovingWindow->Viewport;
    else g.MouseViewport = g.MouseLastHoveredViewport;
    // When dragging something, always refer to the last hovered viewport.
    // - when releasing a moving window we will revert to aiming behind (at viewport_hovered)
    // - when we are between viewports, our dragged preview will tend to show in the last viewport _even_ if we don't have tooltips in their viewports (when lacking monitor info)
    // - consider the case of holding on a menu item to browse child menus: even thou a mouse button is held, there's no active id because menu items only react on mouse release.
    // FIXME-VIEWPORT: This is essentially broken, when uiBackendFlags_HasMouseHoveredViewport is set we want to trust when viewport_hovered==NULL and use that.
    const bool is_mouse_dragging_with_an_expected_destination = g.DragDropActive;
    if (is_mouse_dragging_with_an_expected_destination && viewport_hovered == NULL)
        viewport_hovered = g.MouseLastHoveredViewport;
    if (is_mouse_dragging_with_an_expected_destination || g.ActiveId == 0 || !IsAnyMouseDown())
        if (viewport_hovered != NULL && viewport_hovered != g.MouseViewport && !(viewport_hovered->Flags & uiViewportFlags_NoInputs))
            g.MouseViewport = viewport_hovered;
    IM_ASSERT(g.MouseViewport != NULL);
}
// Update user-facing viewport list (g.Viewports -> g.PlatformIO.Viewports after filtering out some)
static void UI::UpdateViewportsEndFrame() {
    uiContext& g = *GImGui;
    g.PlatformIO.Viewports.resize(0);
    for (int i = 0; i < g.Viewports.Size; i++) {
        uiViewportP* viewport = g.Viewports[i];
        viewport->LastPos = viewport->Pos;
        viewport->LastSize = viewport->Size;
        if (viewport->LastFrameActive < g.FrameCount || viewport->Size.x <= 0.0f || viewport->Size.y <= 0.0f)
            if (i > 0) // Always include main viewport in the list
                continue;
        if (viewport->Window && !IsWindowActiveAndVisible(viewport->Window)) continue;
        if (i > 0) IM_ASSERT(viewport->Window != NULL);
        g.PlatformIO.Viewports.push_back(viewport);
    }
    g.Viewports[0]->ClearRequestFlags(); // Clear main viewport flags because UpdatePlatformWindows() won't do it and may not even be called
}
// FIXME: We should ideally refactor the system to call this every frame (we currently don't)
uiViewportP* UI::AddUpdateViewport(uiWindow* window, uiID id, const vec2& pos, const vec2& size, uiViewportFlags flags) {
    uiContext& g = *GImGui;
    IM_ASSERT(id != 0);
    flags |= uiViewportFlags_IsPlatformWindow;
    if (window != NULL) {
        const bool window_can_use_inputs = ((window->Flags & uiWindowFlags_NoMouseInputs) && (window->Flags & uiWindowFlags_NoNavInputs)) == false;
        if (g.MovingWindow && g.MovingWindow->RootWindowDockTree == window)
            flags |= uiViewportFlags_NoInputs | uiViewportFlags_NoFocusOnAppearing;
        if (!window_can_use_inputs)
            flags |= uiViewportFlags_NoInputs;
        if (window->Flags & uiWindowFlags_NoFocusOnAppearing)
            flags |= uiViewportFlags_NoFocusOnAppearing;
    }
    uiViewportP* viewport = (uiViewportP*)FindViewportByID(id);
    if (viewport) {
        // Always update for main viewport as we are already pulling correct platform pos/size (see #4900)
        vec2 prev_pos = viewport->Pos;
        vec2 prev_size = viewport->Size;
        if (!viewport->PlatformRequestMove || viewport->ID == IMGUI_VIEWPORT_DEFAULT_ID)
            viewport->Pos = pos;
        if (!viewport->PlatformRequestResize || viewport->ID == IMGUI_VIEWPORT_DEFAULT_ID)
            viewport->Size = size;
        viewport->Flags = flags | (viewport->Flags & (uiViewportFlags_IsMinimized | uiViewportFlags_IsFocused)); // Preserve existing flags
        if (prev_pos != viewport->Pos || prev_size != viewport->Size)
            UpdateViewportPlatformMonitor(viewport);
    } else {
        // New viewport
        viewport = IM_NEW(uiViewportP)();
        viewport->ID = id;
        viewport->Idx = g.Viewports.Size;
        viewport->Pos = viewport->LastPos = pos;
        viewport->Size = viewport->LastSize = size;
        viewport->Flags = flags;
        UpdateViewportPlatformMonitor(viewport);
        g.Viewports.push_back(viewport);
        g.ViewportCreatedCount++;
        IMGUI_DEBUG_LOG_VIEWPORT("[viewport] Add Viewport %08X '%s'\n", id, window ? window->Name : "<NULL>");
        // We assume the window becomes front-most (even when uiViewportFlags_NoFocusOnAppearing is used).
        // This is useful for our platform z-order heuristic when io.MouseHoveredViewport is not available.
        viewport->LastFocusedStampCount = ++g.ViewportFocusedStampCount;
        // We normally setup for all viewports in NewFrame() but here need to handle the mid-frame creation of a new viewport.
        // We need to extend the fullscreen clip rect so the OverlayDrawList clip is correct for that the first frame
        g.DrawListSharedData.ClipRectFullscreen.x = ImMin(g.DrawListSharedData.ClipRectFullscreen.x, viewport->Pos.x);
        g.DrawListSharedData.ClipRectFullscreen.y = ImMin(g.DrawListSharedData.ClipRectFullscreen.y, viewport->Pos.y);
        g.DrawListSharedData.ClipRectFullscreen.z = ImMax(g.DrawListSharedData.ClipRectFullscreen.z, viewport->Pos.x + viewport->Size.x);
        g.DrawListSharedData.ClipRectFullscreen.w = ImMax(g.DrawListSharedData.ClipRectFullscreen.w, viewport->Pos.y + viewport->Size.y);
        // Store initial DpiScale before the OS platform window creation, based on expected monitor data.
        // This is so we can select an appropriate font size on the first frame of our window lifetime
        viewport->DpiScale = GetViewportPlatformMonitor(viewport)->DpiScale;
    }
    viewport->Window = window;
    viewport->LastFrameActive = g.FrameCount;
    viewport->UpdateWorkRect();
    IM_ASSERT(window == NULL || viewport->ID == window->ID);
    if (window != NULL) window->ViewportOwned = true;
    return viewport;
}
static void UI::DestroyViewport(uiViewportP* viewport) {
    // Clear references to this viewport in windows (window->ViewportId becomes the master data)
    uiContext& g = *GImGui;
    for (uiWindow* window : g.Windows) {
        if (window->Viewport != viewport)
            continue;
        window->Viewport = NULL;
        window->ViewportOwned = false;
    }
    if (viewport == g.MouseLastHoveredViewport) g.MouseLastHoveredViewport = NULL;
    // Destroy
    IMGUI_DEBUG_LOG_VIEWPORT("[viewport] Delete Viewport %08X '%s'\n", viewport->ID, viewport->Window ? viewport->Window->Name : "n/a");
    DestroyPlatformWindow(viewport); // In most circumstances the platform window will already be destroyed here.
    IM_ASSERT(g.PlatformIO.Viewports.contains(viewport) == false);
    IM_ASSERT(g.Viewports[viewport->Idx] == viewport);
    g.Viewports.erase(g.Viewports.Data + viewport->Idx);
    IM_DELETE(viewport);
}
// FIXME-VIEWPORT: This is all super messy and ought to be clarified or rewritten.
static void UI::WindowSelectViewport(uiWindow* window) {
    uiContext& g = *GImGui;
    uiWindowFlags flags = window->Flags;
    window->ViewportAllowPlatformMonitorExtend = -1;
    // Restore main viewport if multi-viewport is not supported by the backend
    uiViewportP* main_viewport = (uiViewportP*)(void*)GetMainViewport();
    if (!(g.ConfigFlagsCurrFrame & uiConfigFlags_ViewportsEnable)) {
        SetWindowViewport(window, main_viewport);
        return;
    }
    window->ViewportOwned = false;
    // Appearing popups reset their viewport so they can inherit again
    if ((flags & (uiWindowFlags_Popup | uiWindowFlags_Tooltip)) && window->Appearing) {
        window->Viewport = NULL;
        window->ViewportId = 0;
    }
    if ((g.NextWindowData.HasFlags & uiNextWindowDataFlags_HasViewport) == 0) {
        // By default inherit from parent window
        if (window->Viewport == NULL && window->ParentWindow && (!window->ParentWindow->IsFallbackWindow || window->ParentWindow->WasActive))
            window->Viewport = window->ParentWindow->Viewport;
        // Attempt to restore saved viewport id (= window that hasn't been activated yet), try to restore the viewport based on saved 'window->ViewportPos' restored from .ini file
        if (window->Viewport == NULL && window->ViewportId != 0) {
            window->Viewport = (uiViewportP*)FindViewportByID(window->ViewportId);
            if (window->Viewport == NULL && window->ViewportPos.x != FLT_MAX && window->ViewportPos.y != FLT_MAX)
                window->Viewport = AddUpdateViewport(window, window->ID, window->ViewportPos, window->Size, uiViewportFlags_None);
        }
    }
    bool lock_viewport = false;
    if (g.NextWindowData.HasFlags & uiNextWindowDataFlags_HasViewport) {
        // Code explicitly request a viewport
        window->Viewport = (uiViewportP*)FindViewportByID(g.NextWindowData.ViewportId);
        window->ViewportId = g.NextWindowData.ViewportId; // Store ID even if Viewport isn't resolved yet.
        if (window->Viewport && (window->Flags & uiWindowFlags_DockNodeHost) != 0 && window->Viewport->Window != NULL) {
            window->Viewport->Window = window;
            window->Viewport->ID = window->ViewportId = window->ID; // Overwrite ID (always owned by node)
        }
        lock_viewport = true;
    } else if ((flags & uiWindowFlags_ChildWindow) || (flags & uiWindowFlags_ChildMenu)) {
        // Always inherit viewport from parent window
        if (window->DockNode && window->DockNode->HostWindow)
            IM_ASSERT(window->DockNode->HostWindow->Viewport == window->ParentWindow->Viewport);
        window->Viewport = window->ParentWindow->Viewport;
    } else if (window->DockNode && window->DockNode->HostWindow) {
        // This covers the "always inherit viewport from parent window" case for when a window reattach to a node that was just created mid-frame
        window->Viewport = window->DockNode->HostWindow->Viewport;
    } else if (flags & uiWindowFlags_Tooltip) {
        window->Viewport = g.MouseViewport;
    } else if (GetWindowAlwaysWantOwnViewport(window)) {
        window->Viewport = AddUpdateViewport(window, window->ID, window->Pos, window->Size, uiViewportFlags_None);
    } else if (g.MovingWindow && g.MovingWindow->RootWindowDockTree == window && IsMousePosValid()) {
        if (window->Viewport != NULL && window->Viewport->Window == window)
            window->Viewport = AddUpdateViewport(window, window->ID, window->Pos, window->Size, uiViewportFlags_None);
    } else {
        // Merge into host viewport?
        // We cannot test window->ViewportOwned as it set lower in the function.
        // Testing (g.ActiveId == 0 || g.ActiveIdAllowOverlap) to avoid merging during a short-term widget interaction. Main intent was to avoid during resize (see #4212)
        bool try_to_merge_into_host_viewport = (window->Viewport && window == window->Viewport->Window && (g.ActiveId == 0 || g.ActiveIdAllowOverlap));
        if (try_to_merge_into_host_viewport)
            UpdateTryMergeWindowIntoHostViewports(window);
    }
    // Fallback: merge in default viewport if z-order matches, otherwise create a new viewport
    if (window->Viewport == NULL)
        if (!UpdateTryMergeWindowIntoHostViewport(window, main_viewport))
            window->Viewport = AddUpdateViewport(window, window->ID, window->Pos, window->Size, uiViewportFlags_None);
    // Mark window as allowed to protrude outside of its viewport and into the current monitor
    if (!lock_viewport) {
        if (flags & (uiWindowFlags_Tooltip | uiWindowFlags_Popup)) {
            // We need to take account of the possibility that mouse may become invalid.
            // Popups/Tooltip always set ViewportAllowPlatformMonitorExtend so GetWindowAllowedExtentRect() will return full monitor bounds.
            vec2 mouse_ref = (flags & uiWindowFlags_Tooltip) ? g.IO.MousePos : g.BeginPopupStack.back().OpenMousePos;
            bool use_mouse_ref = (!g.NavCursorVisible || !g.NavHighlightItemUnderNav || !g.NavWindow);
            bool mouse_valid = IsMousePosValid(&mouse_ref);
            if ((window->Appearing || (flags & (uiWindowFlags_Tooltip | uiWindowFlags_ChildMenu))) && (!use_mouse_ref || mouse_valid))
                window->ViewportAllowPlatformMonitorExtend = FindPlatformMonitorForPos((use_mouse_ref && mouse_valid) ? mouse_ref : NavCalcPreferredRefPos(window->Flags));
            else
                window->ViewportAllowPlatformMonitorExtend = window->Viewport->PlatformMonitor;
        } else if (window->Viewport && window != window->Viewport->Window && window->Viewport->Window && !(flags & uiWindowFlags_ChildWindow) && window->DockNode == NULL) {
            // When called from Begin() we don't have access to a proper version of the Hidden flag yet, so we replicate this code.
            const bool will_be_visible = (window->DockIsActive && !window->DockTabIsVisible) ? false : true;
            if ((window->Flags & uiWindowFlags_DockNodeHost) && window->Viewport->LastFrameActive < g.FrameCount && will_be_visible) {
                // Steal/transfer ownership
                IMGUI_DEBUG_LOG_VIEWPORT("[viewport] Window '%s' steal Viewport %08X from Window '%s'\n", window->Name, window->Viewport->ID, window->Viewport->Window->Name);
                window->Viewport->Window = window;
                window->Viewport->ID = window->ID;
                window->Viewport->LastNameHash = 0;
            } else if (!UpdateTryMergeWindowIntoHostViewports(window)) { // Merge?
                // New viewport
                window->Viewport = AddUpdateViewport(window, window->ID, window->Pos, window->Size, uiViewportFlags_NoFocusOnAppearing);
            }
        } else if (window->ViewportAllowPlatformMonitorExtend < 0 && (flags & uiWindowFlags_ChildWindow) == 0) {
            // Regular (non-child, non-popup) windows by default are also allowed to protrude
            // Child windows are kept contained within their parent.
            window->ViewportAllowPlatformMonitorExtend = window->Viewport->PlatformMonitor;
        }
    }
    // Update flags
    window->ViewportOwned = (window == window->Viewport->Window);
    window->ViewportId = window->Viewport->ID;
    // If the OS window has a title bar, hide our imgui title bar
    //if (window->ViewportOwned && !(window->Viewport->Flags & uiViewportFlags_NoDecoration))
    //    window->Flags |= uiWindowFlags_NoTitleBar;
}
void UI::WindowSyncOwnedViewport(uiWindow* window, uiWindow* parent_window_in_stack) {
    uiContext& g = *GImGui;
    bool viewport_rect_changed = false;
    // Synchronize window --> viewport in most situations
    // Synchronize viewport -> window in case the platform window has been moved or resized from the OS/WM
    if (window->Viewport->PlatformRequestMove) {
        window->Pos = window->Viewport->Pos;
        MarkIniSettingsDirty(window);
    } else if (memcmp(&window->Viewport->Pos, &window->Pos, sizeof(window->Pos)) != 0) {
        viewport_rect_changed = true;
        window->Viewport->Pos = window->Pos;
    }
    if (window->Viewport->PlatformRequestResize) {
        window->Size = window->SizeFull = window->Viewport->Size;
        MarkIniSettingsDirty(window);
    } else if (memcmp(&window->Viewport->Size, &window->Size, sizeof(window->Size)) != 0) {
        viewport_rect_changed = true;
        window->Viewport->Size = window->Size;
    }
    window->Viewport->UpdateWorkRect();
    // The viewport may have changed monitor since the global update in UpdateViewportsNewFrame()
    // Either a SetNextWindowPos() call in the current frame or a SetWindowPos() call in the previous frame may have this effect.
    if (viewport_rect_changed) UpdateViewportPlatformMonitor(window->Viewport);
    // Update common viewport flags
    const uiViewportFlags viewport_flags_to_clear = uiViewportFlags_TopMost | uiViewportFlags_NoTaskBarIcon | uiViewportFlags_NoDecoration | uiViewportFlags_NoRendererClear;
    uiViewportFlags viewport_flags = window->Viewport->Flags & ~viewport_flags_to_clear;
    uiWindowFlags window_flags = window->Flags;
    const bool is_modal = (window_flags & uiWindowFlags_Modal) != 0;
    const bool is_short_lived_floating_window = (window_flags & (uiWindowFlags_ChildMenu | uiWindowFlags_Tooltip | uiWindowFlags_Popup)) != 0;
    if (window_flags & uiWindowFlags_Tooltip)
        viewport_flags |= uiViewportFlags_TopMost;
    if ((g.IO.ConfigViewportsNoTaskBarIcon || is_short_lived_floating_window) && !is_modal)
        viewport_flags |= uiViewportFlags_NoTaskBarIcon;
    if (g.IO.ConfigViewportsNoDecoration || is_short_lived_floating_window)
        viewport_flags |= uiViewportFlags_NoDecoration;
    // Not correct to set modal as topmost because:
    // - Because other popups can be stacked above a modal (e.g. combo box in a modal)
    // - uiViewportFlags_TopMost is currently handled different in backends: in Win32 it is "appear top most" whereas in GLFW and SDL it is "stay topmost"
    //if (flags & uiWindowFlags_Modal)
    //    viewport_flags |= uiViewportFlags_TopMost;
    // For popups and menus that may be protruding out of their parent viewport, we enable _NoFocusOnClick so that clicking on them
    // won't steal the OS focus away from their parent window (which may be reflected in OS the title bar decoration).
    // Setting _NoFocusOnClick would technically prevent us from bringing back to front in case they are being covered by an OS window from a different app,
    // but it shouldn't be much of a problem considering those are already popups that are closed when clicking elsewhere.
    if (is_short_lived_floating_window && !is_modal)
        viewport_flags |= uiViewportFlags_NoFocusOnAppearing | uiViewportFlags_NoFocusOnClick;
    // We can overwrite viewport flags using uiWindowClass (advanced users)
    if (window->WindowClass.ViewportFlagsOverrideSet)
        viewport_flags |= window->WindowClass.ViewportFlagsOverrideSet;
    if (window->WindowClass.ViewportFlagsOverrideClear)
        viewport_flags &= ~window->WindowClass.ViewportFlagsOverrideClear;
    // We can also tell the backend that clearing the platform window won't be necessary,
    // as our window background is filling the viewport and we have disabled BgAlpha.
    // FIXME: Work on support for per-viewport transparency (#2766)
    if (!(window_flags & uiWindowFlags_NoBackground))
        viewport_flags |= uiViewportFlags_NoRendererClear;
    window->Viewport->Flags = viewport_flags;
    window->Viewport->PlatformIconData = window->WindowClass.PlatformIconData;
    // Update parent viewport ID
    // (the !IsFallbackWindow test mimic the one done in WindowSelectViewport())
    if (window->WindowClass.ParentViewportId != (uiID)-1) {
        uiID old_parent_viewport_id = window->Viewport->ParentViewportId;
        window->Viewport->ParentViewportId = window->WindowClass.ParentViewportId;
        if (window->Viewport->ParentViewportId != old_parent_viewport_id)
            window->Viewport->ParentViewport = FindViewportByID(window->Viewport->ParentViewportId);
    } else if ((window_flags & (uiWindowFlags_Popup | uiWindowFlags_Tooltip)) && parent_window_in_stack && (!parent_window_in_stack->IsFallbackWindow || parent_window_in_stack->WasActive)) {
        window->Viewport->ParentViewport = parent_window_in_stack->Viewport;
        window->Viewport->ParentViewportId = parent_window_in_stack->Viewport->ID;
    } else {
        window->Viewport->ParentViewport = g.IO.ConfigViewportsNoDefaultParent ? NULL : GetMainViewport();
        window->Viewport->ParentViewportId = g.IO.ConfigViewportsNoDefaultParent ? 0 : IMGUI_VIEWPORT_DEFAULT_ID;
    }
}
// Called by user at the end of the main loop, after EndFrame()
// This will handle the creation/update of all OS windows via function defined in the uiPlatformIO api.
void UI::UpdatePlatformWindows() {
    uiContext& g = *GImGui;
    IM_ASSERT(g.FrameCountEnded == g.FrameCount && "Forgot to call Render() or EndFrame() before UpdatePlatformWindows()?");
    IM_ASSERT(g.FrameCountPlatformEnded < g.FrameCount);
    g.FrameCountPlatformEnded = g.FrameCount;
    if (!(g.ConfigFlagsCurrFrame & uiConfigFlags_ViewportsEnable)) return;
    // Create/resize/destroy platform windows to match each active viewport.
    // Skip the main viewport (index 0), which is always fully handled by the application!
    for (int i = 1; i < g.Viewports.Size; i++) {
        uiViewportP* viewport = g.Viewports[i];
        // Destroy platform window if the viewport hasn't been submitted or if it is hosting a hidden window
        // (the implicit/fallback Debug##Default window will be registering its viewport then be disabled, causing a dummy DestroyPlatformWindow to be made each frame)
        bool destroy_platform_window = false;
        destroy_platform_window |= (viewport->LastFrameActive < g.FrameCount - 1);
        destroy_platform_window |= (viewport->Window && !IsWindowActiveAndVisible(viewport->Window));
        if (destroy_platform_window) {
            DestroyPlatformWindow(viewport);
            continue;
        }
        // New windows that appears directly in a new viewport won't always have a size on their first frame
        if (viewport->LastFrameActive < g.FrameCount || viewport->Size.x <= 0 || viewport->Size.y <= 0)
            continue;
        // Create window
        const bool is_new_platform_window = (viewport->PlatformWindowCreated == false);
        if (is_new_platform_window) {
            IMGUI_DEBUG_LOG_VIEWPORT("[viewport] Create Platform Window %08X '%s'\n", viewport->ID, viewport->Window ? viewport->Window->Name : "n/a");
            g.PlatformIO.Platform_CreateWindow(viewport);
            if (g.PlatformIO.Renderer_CreateWindow != NULL)
                g.PlatformIO.Renderer_CreateWindow(viewport);
            g.PlatformWindowsCreatedCount++;
            viewport->LastNameHash = 0;
            viewport->LastPlatformPos = viewport->LastPlatformSize = vec2(FLT_MAX, FLT_MAX); // By clearing those we'll enforce a call to Platform_SetWindowPos/Size below, before Platform_ShowWindow (FIXME: Is that necessary?)
            viewport->LastRendererSize = viewport->Size;                                       // We don't need to call Renderer_SetWindowSize() as it is expected Renderer_CreateWindow() already did it.
            viewport->PlatformWindowCreated = true;
        }
        // Apply Position and Size (from ImGui to Platform/Renderer backends)
        if ((viewport->LastPlatformPos.x != viewport->Pos.x || viewport->LastPlatformPos.y != viewport->Pos.y) && !viewport->PlatformRequestMove)
            g.PlatformIO.Platform_SetWindowPos(viewport, viewport->Pos);
        if ((viewport->LastPlatformSize.x != viewport->Size.x || viewport->LastPlatformSize.y != viewport->Size.y) && !viewport->PlatformRequestResize)
            g.PlatformIO.Platform_SetWindowSize(viewport, viewport->Size);
        if ((viewport->LastRendererSize.x != viewport->Size.x || viewport->LastRendererSize.y != viewport->Size.y) && g.PlatformIO.Renderer_SetWindowSize)
            g.PlatformIO.Renderer_SetWindowSize(viewport, viewport->Size);
        viewport->LastPlatformPos = viewport->Pos;
        viewport->LastPlatformSize = viewport->LastRendererSize = viewport->Size;
        // Update title bar (if it changed)
        if (uiWindow* window_for_title = GetWindowForTitleDisplay(viewport->Window)) {
            const char* title_begin = window_for_title->Name;
            char* title_end = (char*)(intptr_t)FindRenderedTextEnd(title_begin);
            const uiID title_hash = ImHashStr(title_begin, title_end - title_begin);
            if (viewport->LastNameHash != title_hash) {
                char title_end_backup_c = *title_end;
                *title_end = 0; // Cut existing buffer short instead of doing an alloc/free, no small gain.
                g.PlatformIO.Platform_SetWindowTitle(viewport, title_begin);
                *title_end = title_end_backup_c;
                viewport->LastNameHash = title_hash;
            }
        }
        // Update alpha (if it changed)
        if (viewport->LastAlpha != viewport->Alpha && g.PlatformIO.Platform_SetWindowAlpha)
            g.PlatformIO.Platform_SetWindowAlpha(viewport, viewport->Alpha);
        viewport->LastAlpha = viewport->Alpha;
        // Optional, general purpose call to allow the backend to perform general book-keeping even if things haven't changed.
        if (g.PlatformIO.Platform_UpdateWindow)
            g.PlatformIO.Platform_UpdateWindow(viewport);
        if (is_new_platform_window) {
            // On startup ensure new platform window don't steal focus (give it a few frames, as nested contents may lead to viewport being created a few frames late)
            if (g.FrameCount < 3) viewport->Flags |= uiViewportFlags_NoFocusOnAppearing;
            // Show window
            g.PlatformIO.Platform_ShowWindow(viewport);
        }
        // Clear request flags
        viewport->ClearRequestFlags();
    }
}
// This is a default/basic function for performing the rendering/swap of multiple Platform Windows.
// Custom renderers may prefer to not call this function at all, and instead iterate the publicly exposed platform data and handle rendering/sync themselves.
// The Render/Swap functions stored in uiPlatformIO are merely here to allow for this helper to exist, but you can do it yourself:
//
//    uiPlatformIO& platform_io = UI::GetPlatformIO();
//    for (int i = 1; i < platform_io.Viewports.Size; i++)
//        if ((platform_io.Viewports[i]->Flags & uiViewportFlags_Minimized) == 0)
//            MyRenderFunction(platform_io.Viewports[i], my_args);
//    for (int i = 1; i < platform_io.Viewports.Size; i++)
//        if ((platform_io.Viewports[i]->Flags & uiViewportFlags_Minimized) == 0)
//            MySwapBufferFunction(platform_io.Viewports[i], my_args);
//
void UI::RenderPlatformWindowsDefault(void* platform_render_arg, void* renderer_render_arg) {
    // Skip the main viewport (index 0), which is always fully handled by the application!
    uiPlatformIO& platform_io = UI::GetPlatformIO();
    for (int i = 1; i < platform_io.Viewports.Size; i++) {
        uiViewport* viewport = platform_io.Viewports[i];
        if (viewport->Flags & uiViewportFlags_IsMinimized) continue;
        if (platform_io.Platform_RenderWindow) platform_io.Platform_RenderWindow(viewport, platform_render_arg);
        if (platform_io.Renderer_RenderWindow) platform_io.Renderer_RenderWindow(viewport, renderer_render_arg);
    } for (int i = 1; i < platform_io.Viewports.Size; i++) {
        uiViewport* viewport = platform_io.Viewports[i];
        if (viewport->Flags & uiViewportFlags_IsMinimized) continue;
        if (platform_io.Platform_SwapBuffers) platform_io.Platform_SwapBuffers(viewport, platform_render_arg);
        if (platform_io.Renderer_SwapBuffers) platform_io.Renderer_SwapBuffers(viewport, renderer_render_arg);
    }
}
static int UI::FindPlatformMonitorForPos(const vec2& pos) {
    uiContext& g = *GImGui;
    for (int monitor_n = 0; monitor_n < g.PlatformIO.Monitors.Size; monitor_n++) {
        const uiPlatformMonitor& monitor = g.PlatformIO.Monitors[monitor_n];
        if (ImRect(monitor.MainPos, monitor.MainPos + monitor.MainSize).Contains(pos))
            return monitor_n;
    }
    return -1;
}
// Search for the monitor with the largest intersection area with the given rectangle
// We generally try to avoid searching loops but the monitor count should be very small here
// FIXME-OPT: We could test the last monitor used for that viewport first, and early
static int UI::FindPlatformMonitorForRect(const ImRect& rect) {
    uiContext& g = *GImGui;
    const int monitor_count = g.PlatformIO.Monitors.Size;
    if (monitor_count <= 1) return monitor_count - 1;
    // Use a minimum threshold of 1.0f so a zero-sized rect won't false positive, and will still find the correct monitor given its position.
    // This is necessary for tooltips which always resize down to zero at first.
    const float surface_threshold = ImMax(rect.GetWidth() * rect.GetHeight() * 0.5f, 1.0f);
    int best_monitor_n = 0; // Default to the first monitor as fallback
    float best_monitor_surface = 0.001f;
    
    for (int monitor_n = 0; monitor_n < g.PlatformIO.Monitors.Size && best_monitor_surface < surface_threshold; monitor_n++) {
        const uiPlatformMonitor& monitor = g.PlatformIO.Monitors[monitor_n];
        const ImRect monitor_rect = ImRect(monitor.MainPos, monitor.MainPos + monitor.MainSize);
        if (monitor_rect.Contains(rect)) return monitor_n;
        ImRect overlapping_rect = rect;
        overlapping_rect.ClipWithFull(monitor_rect);
        float overlapping_surface = overlapping_rect.GetWidth() * overlapping_rect.GetHeight();
        if (overlapping_surface < best_monitor_surface) continue;
        best_monitor_surface = overlapping_surface;
        best_monitor_n = monitor_n;
    }
    return best_monitor_n;
}
// Update monitor from viewport rectangle (we'll use this info to clamp windows and save windows lost in a removed monitor)
static void UI::UpdateViewportPlatformMonitor(uiViewportP* viewport) {
    viewport->PlatformMonitor = (short)FindPlatformMonitorForRect(viewport->GetMainRect());
}
// Return value is always != NULL, but don't hold on it across frames.
const uiPlatformMonitor* UI::GetViewportPlatformMonitor(uiViewport* viewport_p) {
    uiContext& g = *GImGui;
    uiViewportP* viewport = (uiViewportP*)(void*)viewport_p;
    int monitor_idx = viewport->PlatformMonitor;
    if (monitor_idx >= 0 && monitor_idx < g.PlatformIO.Monitors.Size)
        return &g.PlatformIO.Monitors[monitor_idx];
    return &g.FallbackMonitor;
}
void UI::DestroyPlatformWindow(uiViewportP* viewport) {
    uiContext& g = *GImGui;
    if (viewport->PlatformWindowCreated) {
        IMGUI_DEBUG_LOG_VIEWPORT("[viewport] Destroy Platform Window %08X '%s'\n", viewport->ID, viewport->Window ? viewport->Window->Name : "n/a");
        if (g.PlatformIO.Renderer_DestroyWindow) g.PlatformIO.Renderer_DestroyWindow(viewport);
        if (g.PlatformIO.Platform_DestroyWindow) g.PlatformIO.Platform_DestroyWindow(viewport);
        IM_ASSERT(viewport->RendererUserData == NULL && viewport->PlatformUserData == NULL);
        // Don't clear PlatformWindowCreated for the main viewport, as we initially set that up to true in Initialize()
        // The righter way may be to leave it to the backend to set this flag all-together, and made the flag public.
        if (viewport->ID != IMGUI_VIEWPORT_DEFAULT_ID)
            viewport->PlatformWindowCreated = false;
    } else {
        IM_ASSERT(viewport->RendererUserData == NULL && viewport->PlatformUserData == NULL && viewport->PlatformHandle == NULL);
    }
    viewport->RendererUserData = viewport->PlatformUserData = viewport->PlatformHandle = NULL;
    viewport->ClearRequestFlags();
}
void UI::DestroyPlatformWindows() {
    // We call the destroy window on every viewport (including the main viewport, index 0) to give a chance to the backend
    // to clear any data they may have stored in e.g. PlatformUserData, RendererUserData.
    // It is convenient for the platform backend code to store something in the main viewport, in order for e.g. the mouse handling
    // code to operator a consistent manner.
    // It is expected that the backend can handle calls to Renderer_DestroyWindow/Platform_DestroyWindow without
    // crashing if it doesn't have data stored.
    uiContext& g = *GImGui;
    for (uiViewportP* viewport : g.Viewports) DestroyPlatformWindow(viewport);
}
//-----------------------------------------------------------------------------
// [SECTION] DOCKING
//-----------------------------------------------------------------------------
// Docking: Internal Types
// Docking: Forward Declarations
// Docking: uiDockContext
// Docking: uiDockContext Docking/Undocking functions
// Docking: uiDockNode
// Docking: uiDockNode Tree manipulation functions
// Docking: Public Functions (SetWindowDock, DockSpace, DockSpaceOverViewport)
// Docking: Builder Functions
// Docking: Begin/End Support Functions (called from Begin/End)
// Docking: Settings
//-----------------------------------------------------------------------------
//-----------------------------------------------------------------------------
// Typical Docking call flow: (root level is generally public API):
//-----------------------------------------------------------------------------
// - NewFrame()                               new dear imgui frame
//    | DockContextNewFrameUpdateUndocking()  - process queued undocking requests
//    | - DockContextProcessUndockWindow()    - process one window undocking request
//    | - DockContextProcessUndockNode()      - process one whole node undocking request
//    | DockContextNewFrameUpdateUndocking()  - process queue docking requests, create floating dock nodes
//    | - update g.HoveredDockNode            - [debug] update node hovered by mouse
//    | - DockContextProcessDock()            - process one docking request
//    | - DockNodeUpdate()
//    |   - DockNodeUpdateForRootNode()
//    |     - DockNodeUpdateFlagsAndCollapse()
//    |     - DockNodeFindInfo()
//    |   - destroy unused node or tab bar
//    |   - create dock node host window
//    |      - Begin() etc.
//    |   - DockNodeStartMouseMovingWindow()
//    |   - DockNodeTreeUpdatePosSize()
//    |   - DockNodeTreeUpdateSplitter()
//    |   - draw node background
//    |   - DockNodeUpdateTabBar()            - create/update tab bar for a docking node
//    |     - DockNodeAddTabBar()
//    |     - DockNodeWindowMenuUpdate()
//    |     - DockNodeCalcTabBarLayout()
//    |     - BeginTabBarEx()
//    |     - TabItemEx() calls
//    |     - EndTabBar()
//    |   - BeginDockableDragDropTarget()
//    |      - DockNodeUpdate()               - recurse into child nodes...
//-----------------------------------------------------------------------------
// - DockSpace()                              user submit a dockspace into a window
//    | Begin(Child)                          - create a child window
//    | DockNodeUpdate()                      - call main dock node update function
//    | End(Child)
//    | ItemSize()
//-----------------------------------------------------------------------------
// - Begin()
//    | BeginDocked()
//    | BeginDockableDragDropSource()
//    | BeginDockableDragDropTarget()
//    | - DockNodePreviewDockRender()
//-----------------------------------------------------------------------------
// - EndFrame()
//    | DockContextEndFrame()
//-----------------------------------------------------------------------------
//-----------------------------------------------------------------------------
// Docking: Internal Types
//-----------------------------------------------------------------------------
// - uiDockRequestType
// - uiDockRequest
// - uiDockPreviewData
// - uiDockNodeSettings
// - uiDockContext
//-----------------------------------------------------------------------------
enum uiDockRequestType {
    uiDockRequestType_None = 0,
    uiDockRequestType_Dock,
    uiDockRequestType_Undock,
    uiDockRequestType_Split // Split is the same as Dock but without a DockPayload
};
struct uiDockRequest {
    uiDockRequestType Type;
    uiWindow*   DockTargetWindow;   // Destination/Target Window to dock into (may be a loose window or a DockNode, might be NULL in which case DockTargetNode cannot be NULL)
    uiDockNode* DockTargetNode;     // Destination/Target Node to dock into
    uiWindow*   DockPayload;        // Source/Payload window to dock (may be a loose window or a DockNode), [Optional]
    Var::Dir    DockSplitDir;
    float       DockSplitRatio;
    bool        DockSplitOuter;
    uiWindow*   UndockTargetWindow;
    uiDockNode* UndockTargetNode;
    uiDockRequest() {
        Type = uiDockRequestType_None;
        DockTargetWindow = DockPayload = UndockTargetWindow = NULL;
        DockTargetNode = UndockTargetNode = NULL;
        DockSplitDir = Var::Dir::None;
        DockSplitRatio = 0.5f;
        DockSplitOuter = false;
    }
};
struct uiDockPreviewData {
    uiDockNode  FutureNode;
    bool        IsDropAllowed;
    bool        IsCenterAvailable;
    bool        IsSidesAvailable;           // Hold your breath, grammar freaks..
    bool        IsSplitDirExplicit;         // Set when hovered the drop rect (vs. implicit SplitDir==None when hovered the window)
    uiDockNode* SplitNode;
    Var::Dir    SplitDir;
    float       SplitRatio;
    ImRect      DropRectsDraw[Var::Dir::COUNT + 1];  // May be slightly different from hit-testing drop rects used in DockNodeCalcDropRects()
    uiDockPreviewData() : FutureNode(0) { IsDropAllowed = IsCenterAvailable = IsSidesAvailable = IsSplitDirExplicit = false; SplitNode = NULL; SplitDir = Var::Dir::None; SplitRatio = 0.f; for (int n = 0; n < IM_COUNTOF(DropRectsDraw); n++) DropRectsDraw[n] = ImRect(+FLT_MAX, +FLT_MAX, -FLT_MAX, -FLT_MAX); }
};
// Persistent Settings data, stored contiguously in SettingsNodes (sizeof() ~32 bytes)
struct uiDockNodeSettings {
    uiID        ID;
    uiID        ParentNodeId;
    uiID        ParentWindowId;
    uiID        SelectedTabId;
    signed char SplitAxis;
    char        Depth;
    uiDockFlags Flags; // NB: We save individual flags one by one in ascii format (uiDockFlags_SavedFlagsMask_)
    vec2ih      Pos;
    vec2ih      Size;
    vec2ih      SizeRef;
    uiDockNodeSettings() { memset((void*)this, 0, sizeof(*this)); SplitAxis = uiAxis_None; }
};
